-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">2</text><text x="231.5" y="128" text-anchor="middle" fill="#0f172a" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">الابتلاع</text><circle cx="68" cy="200" r="34" fill="#e6efff" stroke="#2563eb" stroke-width="2.5"/><ellipse cx="57.8" cy="194.9" rx="11.9" ry="9.52" fill="#c7dbff" stroke="#2563eb" stroke-width="1.5"/><circle cx="74" cy="204" r="17" fill="#ffffff" stroke="#0f6e56" stroke-width="2"/><ellipse cx="74" cy="204" rx="9" ry="6" fill="#fde2e2" stroke="#ef4444" stroke-width="2"/><line x1="65" y1="204" x2="59" y2="201" stroke="#ef4444" stroke-width="1.5"/><line x1="83" y1="204" x2="89" y2="202" stroke="#ef4444" stroke-width="1.5"/><line x1="82" y1="208" x2="88" y2="211" stroke="#ef4444" stroke-width="1.5"/><line x1="69" y1="200" x2="79" y2="208" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="3 2"/><line x1="78" y1="200" x2="70" y2="208" stroke="#ef4444" stroke-width="1.5" stroke-dasharray="3 2"/><circle cx="54" cy="186" r="2.2" fill="#0f6e56" stroke="none" stroke-width="2"/><circle cx="84" cy="188" r="2.2" fill="#0f6e56" stroke="none" stroke-width="2"/><circle cx="86" cy="212" r="2.2" fill="#0f6e56" stroke="none" stroke-width="2"/><circle cx="56" cy="216" r="2.2" fill="#0f6e56" stroke="none" stroke-width="2"/><circle cx="70" cy="180" r="2.2" fill="#0f6e56" stroke="none" stroke-width="2"/><rect x="6" y="144" width="145" height="128" rx="6" fill="none" stroke="#64748b" stroke-width="1.5"/><circle cx="22" cy="160" r="11" fill="#ffffff" stroke="#2563eb" stroke-width="2"/><text x="22" y="164.5" text-anchor="middle" fill="#2563eb" font-size="14" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">3</text><text x="78.5" y="264" text-anchor="middle" fill="#0f172a" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke