INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('43b4902b-3f94-5a0b-98f9-019bf0a28685', 'sciences-vie-terre', 'البراكين', 'تعريف البركان وبنيته (الخزّان الصهاري والمدخنة والفوّهة)، الصهارة واللابة والفرق بينهما، أنواع الثورات البركانية (الانسيابية الهادئة والانفجارية)، المقذوفات البركانية (لابة وغازات ومواد صلبة)، توزّع البراكين في العالم وعلاقتها بحدود الصفائح التكتونية، إضافةً إلى مخاطر البراكين وفوائدها', '# 🌋 البراكين

> 💡 «البركان نافذة على باطن الأرض الملتهب: من خلاله تخرج موادّ الأعماق إلى السطح.»

## 🏰 ما هو البركان؟

**البركان** هو فُتحة (أو شقّ) في القشرة الأرضية تخرج منها موادّ منصهرة وغازات وموادّ صلبة آتية من باطن الأرض، فتتراكم حول الفُتحة مكوِّنةً غالبًا جبلًا مخروطي الشكل.

## ⚙️ بنية البركان

نميّز في البركان الأجزاء التالية:

- **الخزّان الصهاري (الغرفة الصهارية)**: جوف في العمق تتجمّع فيه **الصهارة** قبل صعودها.
- **المدخنة (المَجرى)**: قناة شاقولية تصعد عبرها الموادّ من الخزّان نحو السطح.
- **الفوّهة**: الفُتحة العلوية للبركان التي تخرج منها المقذوفات.
- **المخروط البركاني**: الجبل المتكوّن من تراكم المقذوفات حول الفوّهة.

> 🗡️ ترتيب الصعود: خزّان صهاري ← مدخنة ← فوّهة ← السطح.

<svg viewBox="0 0 300 236">
<title>مقطع في بركان: الخزّان الصهاري والمدخنة والفوّهة والمخروط واللابة</title>
<rect x="0" y="0" width="300" height="150" fill="#eaf4ff" stroke="none" stroke-width="2"/><rect x="0" y="150" width="300" height="86" fill="#efe2cf" stroke="none" stroke-width="2"/><polygon points="66,150 138,48 149,66 162,48 234,150" fill="#8a6d3b" stroke="#0f172a" stroke-width="2.5"/><line x1="6" y1="150" x2="294" y2="150" stroke="#0f172a" stroke-width="2.5"/><path d="M10 150 L3 157 M25 150 L18 157 M40 150 L33 157 M55 150 L48 157 M70 150 L63 157 M85 150 L78 157 M100 150 L93 157 M115 150 L108 157 M130 150 L123 157 M145 150 L138 157 M160 150 L153 157 M175 150 L168 157 M190 150 L183 157 M205 150 L198 157 M220 150 L213 157 M235 150 L228 157 M250 150 L243 157 M265 150 L258 157 M280 150 L273 157" stroke="#9c8858" stroke-width="1.2"/><ellipse cx="150" cy="202" rx="48" ry="22" fill="#f0873a" stroke="#e8531d" stroke-width="2.5"/><ellipse cx="150" cy="202" rx="30" ry="12" fill="#f6b06a" stroke="none" stroke-width="2"/><polygon points="144,50 160,50 156,182 148,182" fill="#e8531d" stroke="#0f172a" stroke-width="2"/><polygon points="147,34 143,20 150,30 156,16 153,34" fill="#e8531d" stroke="none" stroke-width="2"/><circle cx="135" cy="26" r="3" fill="#f0873a" stroke="none" stroke-width="2"/><circle cx="166" cy="28" r="3" fill="#f0873a" stroke="none" stroke-width="2"/><circle cx="128" cy="40" r="3" fill="#f0873a" stroke="none" stroke-width="2"/><circle cx="172" cy="40" r="3" fill="#f0873a" stroke="none" stroke-width="2"/><polygon points="160,52 163,52 214,150 200,150" fill="#e8531d" stroke="none" stroke-width="2"/><line x1="196" y1="100" x2="240" y2="104" stroke="#64748b" stroke-width="1.4"/><line x1="150" y1="116" x2="120" y2="122" stroke="#64748b" stroke-width="1.4"/><line x1="205" y1="148" x2="232" y2="168" stroke="#64748b" stroke-width="1.4"/><g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="150" y="12" text-anchor="middle" fill="#0f172a" font-size="12">الفوّهة</text><text x="262" y="102" text-anchor="middle" fill="#0f172a" font-size="12">المخروط</text><text x="262" y="116" text-anchor="middle" fill="#0f172a" font-size="12">البركاني</text><text x="98" y="122" text-anchor="middle" fill="#0f172a" font-size="12">المدخنة</text><text x="150" y="206" text-anchor="middle" fill="#0f172a" font-size="11">الخزّان الصهاري</text><text x="252" y="176" text-anchor="middle" fill="#e8531d" font-size="12">اللابة</text><text x="252" y="190" text-anchor="middle" fill="#e8531d" font-size="11">(الحِمم)</text></g>
</svg>

## ⚡ الصهارة واللابة: لا تخلط بينهما

- **الصهارة (Magma)**: صخر منصهر يحتوي على **غازات ذائبة**، يوجد في **باطن الأرض** (داخل الخزّان والمدخنة).
- **اللابة (Lave / حِمم)**: هي الصهارة نفسها **بعد خروجها** إلى **سطح الأرض**، وقد **فقدت معظم غازاتها**.

> ⚠️ القاعدة: الصهارة في الداخل، واللابة في الخارج. الاسم يتغيّر بمجرّد الخروج إلى السطح.

## 🛡️ أنواع الثورات (الانبثاقات) البركانية

تتوقّف طبيعة الثوران على **لزوجة الصهارة** و**كمّية الغازات** فيها:

- **الثوران الانسيابي (الهادئ)**: صهارة **سائلة قليلة اللزوجة** فقيرة نسبيًّا بالغازات؛ تخرج اللابة بسهولة وتسيل بعيدًا في **أنهار من الحِمم**. براكينه ذات **مخروط منبسط** (مثال: براكين هاواي).
- **الثوران الانفجاري (المتفجّر)**: صهارة **لزجة (كثيفة)** غنيّة بالغازات؛ تَسُدّ المدخنة فيتراكم الضغط حتى ينفجر، فيقذف **رمادًا وكُتلًا صخرية وغازات** على شكل سحابة حارقة. براكينه شديدة الخطورة.

> 🔮 كلّما زادت لزوجة الصهارة وكمّية غازاتها، كان الثوران أعنف.

## 🌑 المقذوفات البركانية

يقذف البركان أثناء ثورانه ثلاثة أصناف من الموادّ:

- **موادّ سائلة**: اللابة (الحِمم).
- **موادّ غازية**: بخار الماء وثاني أكسيد الكربون وغازات أخرى.
- **موادّ صلبة**: الرماد البركاني، الحصى، والكُتل الصخرية (القنابل البركانية).

## 🗺️ توزّع البراكين وعلاقتها بالصفائح

البراكين **ليست موزّعة عشوائيًّا**: تتركّز أغلبها على طول **حدود الصفائح التكتونية**، خاصّةً في:

- **حزام النار** المحيط بالمحيط الهادئ.
- مناطق **تباعد** الصفائح (أواسط المحيطات) ومناطق **تقارُبها**.

وهذا يدلّ على ارتباط النشاط البركاني بحركة الصفائح وبالنشاط الباطني للأرض (مثل الزلازل التي ترافقه غالبًا).

## 🏆 المخاطر والفوائد

- **المخاطر**: تدمير المنشآت، حرائق الحِمم، السحب الحارقة والرماد الذي يخنق ويعطّل الحياة والطيران، وتلوّث الهواء.
- **الفوائد**: خصوبة التربة البركانية، الطاقة الحرارية الأرضية (الجيوحرارية)، والثروات المعدنية، إضافةً إلى ينابيع المياه الساخنة.

> 🏆 فهمتَ كيف تثور الأرض؛ تذكّر دائمًا: الصهارة في الداخل، واللابة في الخارج، والثوران إمّا هادئ سائل أو متفجّر لزج.', '# 📜 ملخّص: البراكين

- **البركان**: فُتحة في القشرة الأرضية تخرج منها موادّ منصهرة وغازات وموادّ صلبة من باطن الأرض.
- **بنيته**: خزّان صهاري (في العمق) ← مدخنة (قناة الصعود) ← فوّهة (الفتحة العلوية) ← مخروط بركاني.
- **الصهارة (Magma)**: صخر منصهر **محمّل بالغازات في باطن الأرض**. **اللابة (Lave)**: الصهارة نفسها **بعد خروجها إلى السطح** وقد فقدت معظم غازاتها.
- **الثوران الانسيابي (الهادئ)**: صهارة سائلة قليلة اللزوجة، حِمم تسيل بعيدًا، مخروط منبسط.
- **الثوران الانفجاري**: صهارة لزجة غنيّة بالغازات، انفجار يقذف رمادًا وكُتلًا وسُحبًا حارقة (الأخطر).
- **المقذوفات**: سائلة (لابة) + غازية (بخار ماء وغازات) + صلبة (رماد وحصى وقنابل بركانية).
- **التوزّع**: تتركّز على **حدود الصفائح التكتونية** (حزام النار حول المحيط الهادئ).
- **المخاطر**: تدمير وحرائق وسُحب ورماد. **الفوائد**: تربة خصبة، طاقة جيوحرارية، ثروات معدنية.', 5, NULL)
ON CONFLICT (id) DO UPDATE SET
