  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0f41ff6b-ba79-5c2f-b08d-da6f57a8877a', '8da239ab-2d7d-58b4-810d-be40cba982da', 'ما المشيج الذي تنتجه الخصية؟', '[{"id":"a","text":"البويضة"},{"id":"b","text":"النطفة"},{"id":"c","text":"البيضة المخصّبة"},{"id":"d","text":"الهرمون"}]'::jsonb, 'b', 'الخصية هي الغدّة التناسلية الذكرية التي تنتج النطاف (المشيج الذكري). البويضة ينتجها المبيض، والبيضة المخصّبة تنتج عن اندماج المشيجين، والهرمون ليس مشيجًا بل مادّة كيميائية تنظّم الوظائف.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('511d5dad-156c-553b-9592-81828f63aac6', '8da239ab-2d7d-58b4-810d-be40cba982da', 'أين يحدث الإلقاح عادةً عند المرأة؟', '[{"id":"a","text":"في المبيض"},{"id":"b","text":"في المهبل"},{"id":"c","text":"في الرحم"},{"id":"d","text":"في البوق (قناة فالوب)"}]'::jsonb, 'd', 'تلتقي النطفة بالبويضة فيحدث الإلقاح عادةً في البوق (قناة فالوب). المبيض يطلق البويضة فقط، والرحم مكان تعشيش البيضة المخصّبة ونموّ الجنين لاحقًا، والمهبل قناة الجماع والولادة.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
