  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8df6dff2-703c-5338-9ae5-c789132733b7', '8da239ab-2d7d-58b4-810d-be40cba982da', 'في دورة جنسية متوسّطة طولها 28 يومًا، متى تحدث الإباضة تقريبًا؟', '[{"id":"a","text":"في اليوم الأوّل من الدورة"},{"id":"b","text":"في منتصف الدورة (نحو اليوم 14)"},{"id":"c","text":"في اليوم الأخير من الدورة"},{"id":"d","text":"أثناء الطمث مباشرةً"}]'::jsonb, 'b', 'تحدث الإباضة في منتصف الدورة، أي نحو اليوم 14 في دورة من 28 يومًا. اليوم الأوّل هو بداية الطمث (تساقط البطانة) وليس وقت الإباضة، والإباضة لا تتزامن مع الطمث بل تقع في منتصف المسافة بينه وبين الطمث الموالي.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
