  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('40571775-c88f-503f-bc5e-41dee7862b91', '8da239ab-2d7d-58b4-810d-be40cba982da', 'ما الاسم الذي يطلق على الخليّة الناتجة عن اندماج النطفة والبويضة؟', '[{"id":"a","text":"الجنين"},{"id":"b","text":"البيضة المخصّبة (اللاقحة)"},{"id":"c","text":"المشيمة"},{"id":"d","text":"الجُريب"}]'::jsonb, 'b', 'اندماج المشيجين ينتج البيضة المخصّبة (اللاقحة)، وهي أوّل خليّة للكائن الجديد. الجنين مرحلة لاحقة بعد انقسامات البيضة وتعشيشها، والمشيمة عضو تبادل بين الأمّ والجنين، والجُريب هو ما يحتوي البويضة داخل المبيض قبل الإباضة.', 7, 'mcq', NULL, NULL)
