  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9756bae8-30cd-55e7-a0b2-3b6faeed1690', '8da239ab-2d7d-58b4-810d-be40cba982da', 'أيّ ممّا يلي ليس طريقًا لانتقال فيروس السيدا (VIH)؟', '[{"id":"a","text":"العلاقة الجنسية غير المحمية"},{"id":"b","text":"نقل دم ملوّث أو تبادل الإبر"},{"id":"c","text":"من الأمّ المصابة إلى جنينها"},{"id":"d","text":"مصافحة شخص مصاب أو مشاركته الطعام"}]'::jsonb, 'd', 'ينتقل فيروس السيدا عبر العلاقة الجنسية غير المحمية، والدم الملوّث (نقل الدم أو تبادل الإبر)، ومن الأمّ إلى جنينها. أمّا المصافحة ومشاركة الطعام والأواني والعطاس ولسعة البعوض فلا تنقل الفيروس، وهذا اعتقاد خاطئ شائع يسبّب وصم المصابين دون مبرّر علمي.', 8, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
