INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0a4f69d8-24fa-5b8c-877f-723f6638b509', '22436c51-690e-519a-bacd-4a6c42949e57', 'ما البلوغ؟', '[{"id":"a","text":"مرحلة يصبح فيها الجسم قادرًا على التكاثر"},{"id":"b","text":"مرحلة تتوقّف فيها الغدد التناسلية عن العمل"},{"id":"c","text":"مرض يصيب المراهقين"},{"id":"d","text":"نهاية القدرة على الإنجاب"}]'::jsonb, 'a', 'البلوغ مرحلة انتقال من الطفولة إلى القدرة على التكاثر، تبدأ فيها الغدد التناسلية بإنتاج الأمشاج بتحكّم من الهرمونات الجنسية. فهو ليس مرضًا ولا توقّفًا للغدد، وهو بداية القدرة على الإنجاب لا نهايتها.', 1, 'mcq', NULL, NULL)
