INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c6ea4f3d-b972-5f4f-bfa0-77090bf848e8', '22436c51-690e-519a-bacd-4a6c42949e57', 'ما الغدّة التي تنتج النطاف عند الرجل؟', '[{"id":"a","text":"البروستاتا"},{"id":"b","text":"الخصية"},{"id":"c","text":"المبيض"},{"id":"d","text":"الحُويصلة المنوية"}]'::jsonb, 'b', 'الخصية هي الغدّة التناسلية التي تنتج النطاف. البروستاتا والحُويصلة المنوية غدّتان ملحقتان تفرزان السائل المنوي الذي يغذّي النطاف وينقلها، لا تنتجانها. أمّا المبيض فهو غدّة أنثوية تنتج البويضات.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
