INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('363ccbdf-a9f1-556c-8676-07fa94fa6013', '22436c51-690e-519a-bacd-4a6c42949e57', 'أيّ خاصية تميّز النطفة عن البويضة؟', '[{"id":"a","text":"النطفة كبيرة وغير متحرّكة"},{"id":"b","text":"النطفة صغيرة ومتحرّكة بفضل سوطها"},{"id":"c","text":"النطفة تختزن مدّخرات غذائية كبيرة"},{"id":"d","text":"النطفة لا تحمل أيّ معلومة وراثية"}]'::jsonb, 'b', 'النطفة خليّة صغيرة جدًّا متحرّكة لها سوط (ذنب) يمكّنها من السباحة نحو البويضة. أمّا البويضة فهي الكبيرة غير المتحرّكة التي تختزن المدّخرات الغذائية. وكلا المشيجين يحمل نصف المعلومة الوراثية، فلا يصحّ أنّ النطفة لا تحمل معلومة وراثية.', 6, 'mcq', NULL, NULL)
