INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ac692ccd-95d7-58d2-9f64-2428321331b3', '089e735c-146a-5920-ace4-7460262de9b7', 'ممَّ يُحسب اليوم الأوّل للدورة الجنسية عند المرأة؟', '[{"id":"a","text":"من يوم الإباضة"},{"id":"b","text":"من اليوم الأوّل للطمث"},{"id":"c","text":"من يوم الإلقاح"},{"id":"d","text":"من نهاية الطمث"}]'::jsonb, 'b', 'يُحسب اليوم الأوّل للدورة من اليوم الأوّل لنزول الطمث، وهو علامة واضحة وثابتة. الإباضة تقع في منتصف الدورة لا في بدايتها، والإلقاح حدث غير ثابت قد لا يحدث، ونهاية الطمث ليست المرجع المعتمد.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
