  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c67cb32e-7846-59a3-b2c2-c0e3f3c415a0', '089e735c-146a-5920-ace4-7460262de9b7', 'ماذا يحدث لبطانة الرحم إذا لم يحدث إلقاح؟', '[{"id":"a","text":"تزداد سُمكًا باستمرار"},{"id":"b","text":"تتفكّك وتنزل مع الدم (الطمث)"},{"id":"c","text":"تتحوّل إلى بويضة"},{"id":"d","text":"تبقى ثابتة دون أيّ تغيير"}]'::jsonb, 'b', 'تتكاثف البطانة استعدادًا لاستقبال بيضة مخصّبة؛ فإن لم يحدث إلقاح تتفكّك وتنزل مع الدم وهذا هو الطمث. فهي لا تزداد سُمكًا بلا حدّ، ولا تتحوّل إلى بويضة (البويضة ينتجها المبيض)، ولا تبقى ثابتة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('27d58d3d-e716-5945-ba4b-e2318bb17b86', '089e735c-146a-5920-ace4-7460262de9b7', 'أين تندمج النطفة بالبويضة (مكان الإلقاح)؟', '[{"id":"a","text":"في الرحم"},{"id":"b","text":"في المهبل"},{"id":"c","text":"في البوق (قناة فالوب)"},{"id":"d","text":"في المبيض"}]'::jsonb, 'c', 'يحدث الإلقاح عادةً في البوق، حيث تصعد النطاف وتلتقي بالبويضة بعد الإباضة. الرحم مكان التعشيش والنموّ، والمهبل قناة الجماع، والمبيض يطلق البويضة فقط ولا يحدث فيه الإلقاح.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c75a4895-0130-5339-995b-fed589ccc2e7', '089e735c-146a-5920-ace4-7460262de9b7', 'ما الذي ينتج مباشرةً عن اندماج النطفة والبويضة؟', '[{"id":"a","text":"جنين مكتمل"},{"id":"b","text":"بيضة مخصّبة (لاقحة)"},{"id":"c","text":"نطفة جديدة"},{"id":"d","text":"بويضة جديدة"}]'::jsonb, 'b', 'ينتج عن اندماج المشيجين مباشرةً البيضة المخصّبة (اللاقحة)، وهي أوّل خليّة للكائن الجديد. الجنين مرحلة لاحقة تنشأ بعد انقسامات البيضة وتعشيشها، والاندماج لا ينتج مشيجًا جديدًا (نطفة أو بويضة).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
