  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1858eba0-43b3-541a-a62b-277d01ce38ad', '089e735c-146a-5920-ace4-7460262de9b7', 'لماذا ينقطع الطمث عند المرأة الحامل؟', '[{"id":"a","text":"لأنّ المبيض يتوقّف نهائيًّا عن العمل"},{"id":"b","text":"لأنّ البيضة المخصّبة انغرست فبقيت بطانة الرحم لاحتضان الجنين"},{"id":"c","text":"لأنّ الرحم يفرز دمًا أكثر"},{"id":"d","text":"لأنّ الإباضة تتكرّر كلّ يوم"}]'::jsonb, 'b', 'عند حدوث إلقاح وتعشيش، تبقى بطانة الرحم المتكاثفة لاحتضان الجنين بدل أن تتساقط، فينقطع الطمث؛ ولهذا يكون انقطاعه من أوّل علامات الحمل. وليس السبب توقّف المبيض نهائيًّا، ولا زيادة الدم، ولا تكرار الإباضة يوميًّا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cdac01b9-568d-5517-b581-f8f07a8d378e', '089e735c-146a-5920-ace4-7460262de9b7', 'بِمَ يتمّ تبادل الغذاء والأكسجين بين الأمّ وجنينها أثناء الحمل؟', '[{"id":"a","text":"عن طريق المهبل"},{"id":"b","text":"عن طريق المشيمة والحبل السرّي"},{"id":"c","text":"عن طريق المبيضين"},{"id":"d","text":"عن طريق فم الجنين مباشرةً"}]'::jsonb, 'b', 'يتغذّى الجنين ويتنفّس عبر المشيمة والحبل السرّي اللذين يصلانه بدم الأمّ دون اختلاط الدمين. المهبل قناة الولادة لا التبادل، والمبيضان لا دور لهما في تغذية الجنين، والجنين لا يأكل ولا يتنفّس بفمه داخل الرحم.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

