INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6a18cf58-a729-5b6b-86ae-5cb09623a3a7', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'ما الذي يفسّر ظهور العلامات الجنسية الثانوية عند البلوغ؟', '[{"id":"a","text":"إفراز الغدد التناسلية للهرمونات الجنسية"},{"id":"b","text":"نزول الطمث فقط"},{"id":"c","text":"اتّحاد النطفة بالبويضة"},{"id":"d","text":"نقص التغذية في الطفولة"}]'::jsonb, 'a', 'تظهر العلامات الثانوية (الصوت، الشعر، الثديان…) بفعل الهرمونات الجنسية التي تفرزها الغدد التناسلية عند نضجها (التستوستيرون عند الفتى، الإستروجين عند الفتاة). الطمث نتيجة من نتائج البلوغ عند الفتاة لا سبب لكلّ العلامات، واتّحاد المشيجين هو الإلقاح، والتغذية ليست العامل المتحكّم.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
