  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('69a02aa9-90e4-5e4d-8d70-0f3fd18602d5', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'في دورة منتظمة طولها 28 يومًا، أيّ فترة هي الأكثر احتمالًا لحدوث حمل عند الجماع؟', '[{"id":"a","text":"أثناء أيّام الطمث"},{"id":"b","text":"حول منتصف الدورة قرب الإباضة"},{"id":"c","text":"في اليوم الأخير من الدورة"},{"id":"d","text":"لا يحدث الحمل أبدًا قبل اليوم 25"}]'::jsonb, 'b', 'يحدث الحمل عندما تُلقَّح بويضةٌ متاحة؛ والإباضة تقع حول اليوم 14، فتكون الفترة المحيطة بها الأكثر خصوبة. أثناء الطمث لا توجد بويضة جديدة محرّرة بعد، وفي آخر الدورة تكون البويضة قد زالت إن لم تُلقّح، والقول إنّ الحمل مستحيل قبل اليوم 25 خاطئ.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
