  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4bb113d8-06cc-58d0-8aab-ccff595ec640', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'لماذا يحمل كلّ مشيج (نطفة أو بويضة) نصف المعلومة الوراثية فقط؟', '[{"id":"a","text":"حتّى يكون أصغر حجمًا"},{"id":"b","text":"كي يكتمل العدد عند اندماجهما فيرث الكائن الجديد من الأبوين معًا"},{"id":"c","text":"لأنّ المشيج خليّة ميتة"},{"id":"d","text":"لأنّ نصف المعلومة يضيع أثناء الإلقاح"}]'::jsonb, 'b', 'يحمل كلّ مشيج نصف الصبغيات؛ فعند اندماج النطفة بالبويضة يكتمل العدد في البيضة المخصّبة، فيرث الكائن الجديد المعلومة الوراثية من الأب والأمّ معًا. السبب ليس مجرّد الحجم، والمشيج خليّة حيّة، ولا تضيع المعلومة بل تجتمع.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6052de6d-0e0c-5540-8c69-0b8b7ae3559d', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'بعد الإلقاح في البوق، ما التسلسل الصحيح للأحداث؟', '[{"id":"a","text":"تعشيش في الرحم ← انقسام البيضة ← إباضة"},{"id":"b","text":"انقسام البيضة المخصّبة وتنقّلها ← تعشيش في بطانة الرحم ← بداية الحمل"},{"id":"c","text":"نزول طمث ← إلقاح ثانٍ ← ولادة"},{"id":"d","text":"خروج البيضة عبر المهبل ← تعشيش في المبيض"}]'::jsonb, 'b', 'بعد الإلقاح تبدأ البيضة المخصّبة بالانقسام وهي تتنقّل من البوق نحو الرحم، ثمّ تنغرس (تتعشّش) في بطانة الرحم فيبدأ الحمل. الترتيب في باقي الخيارات خاطئ: الإباضة تسبق الإلقاح، والطمث ينقطع عند الحمل، والتعشيش يحدث في الرحم لا في المبيض.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('31248994-d4f9-5171-bec2-d64dc992c83e', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'ما الدور الأساسي للسائل المنوي الذي تفرزه الغدد الملحقة؟', '[{"id":"a","text":"إنتاج النطاف"},{"id":"b","text":"تغذية النطاف وحملها لتنتقل وتبقى حيّة"},{"id":"c","text":"إنتاج البويضات"},{"id":"d","text":"تكوين بطانة الرحم"}]'::jsonb, 'b', 'السائل المنوي تفرزه الغدد الملحقة (الحُويصلتان المنويتان والبروستاتا) ليغذّي النطاف ويحملها فتبقى حيّة وتتمكّن من الحركة. النطاف نفسها تنتجها الخصية لا الغدد الملحقة، والبويضات ينتجها المبيض، وبطانة الرحم شأن أنثويّ لا علاقة له بالسائل المنوي.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f2ad13f4-0044-50d5-81a3-5c68b357afa6', 'bc5cf83c-7fd3-5e94-9214-5450797c5d44', 'علامَ يدلّ انقطاع الطمث المفاجئ عند امرأة في سنّ الإنجاب كانت دورتها منتظمة؟', '[{"id":"a","text":"على حدوث حمل محتمل (انغراس بيضة مخصّبة)"},{"id":"b","text":"على حدوث إباضة مزدوجة"},{"id":"c","text":"على أنّ المبيضين بدآ بإنتاج النطاف"},{"id":"d","text":"على أنّ بطانة الرحم تساقطت مرّتين"}]'::jsonb, 'a', 'انقطاع الطمث المفاجئ يدلّ على احتمال حمل، لأنّ تعشيش بيضة مخصّبة يُبقي بطانة الرحم فلا تتساقط. الإباضة المزدوجة لا توقف الطمث بحدّ ذاتها، والمبيضان لا ينتجان النطاف أبدًا (هذا دور الخصية)، وتساقط البطانة مرّتين هو عكس انقطاع الطمث.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

