INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2757d84a-6bee-5f43-a43e-c1300c8d0186', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'امرأة دورتها منتظمة طولها 30 يومًا. عُلِم أنّ الإباضة تحدث قبل بداية الدورة الموالية بنحو 14 يومًا. في أيّ يوم من الدورة تحدث الإباضة تقريبًا؟', '[{"id":"a","text":"اليوم 14"},{"id":"b","text":"اليوم 16"},{"id":"c","text":"اليوم 30"},{"id":"d","text":"اليوم 7"}]'::jsonb, 'b', 'الفترة بين الإباضة وبداية الطمث الموالي ثابتة نحو 14 يومًا، فتُحسب الإباضة بطرح 14 من طول الدورة: 30 − 14 = 16. فتقع في اليوم 16 لا اليوم 14 (الذي يصحّ في دورة 28 يومًا فقط). الخياران 30 و7 لا يطابقان هذه القاعدة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2368e5cc-5dc0-5694-b58e-b254eff67d81', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'أُجري تحليل لزوجين لم يُرزقا بأطفال، فتبيّن أنّ منيّ الرجل خالٍ تمامًا من النطاف بينما تبويض المرأة وأجهزتها سليمة. ما التفسير الأرجح لتعذّر حدوث الإلقاح؟', '[{"id":"a","text":"غياب المشيج الذكري يمنع اندماجه مع البويضة"},{"id":"b","text":"بطانة الرحم رقيقة جدًّا"},{"id":"c","text":"البويضة كبيرة الحجم"},{"id":"d","text":"المهبل قصير"}]'::jsonb, 'a', 'الإلقاح يستلزم اندماج مشيجين؛ فإذا خلا المنيّ من النطاف انعدم المشيج الذكري فاستحال الاندماج رغم سلامة جهة المرأة. أمّا سُمك البطانة فيؤثّر في التعشيش لا في غياب الإلقاح هنا، وكِبَر حجم البويضة أمر طبيعيّ، وطول المهبل لا يمنع صعود النطاف لو وُجدت.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('523df43f-964d-58fd-96b5-9a5ce3b65b6b', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'لماذا تُغلَق البويضة أمام بقيّة النطاف فور دخول نطفة واحدة؟', '[{"id":"a","text":"لتسريع نزول الطمث"},{"id":"b","text":"لضمان اندماج نطفة واحدة فقط فيكتمل العدد الصبغي بشكل سليم"},{"id":"c","text":"لأنّ النطاف الأخرى أكبر حجمًا من البويضة"},{"id":"d","text":"لمنع تكوّن المشيمة"}]'::jsonb, 'b', 'الإغلاق يمنع دخول أكثر من نطفة، فيندمج مشيج ذكري واحد مع البويضة ويكتمل العدد الصبغي للكائن الجديد بشكل سليم؛ دخول عدّة نطاف يفسد هذا العدد. لا علاقة للأمر بتسريع الطمث (الذي ينقطع أصلًا عند الحمل)، ولا بأحجام النطاف، ولا بمنع المشيمة التي تتكوّن لاحقًا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a2b2b1e7-24ab-5e93-8e7d-caa36a43e82f', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'ادّعى تلميذ أنّ مصافحة زميل مصاب بالسيدا أو مشاركته مقعد الدراسة قد تنقل العدوى. ما الردّ العلمي الصحيح؟', '[{"id":"a","text":"الادّعاء صحيح، فالفيروس ينتقل بأيّ تلامس"},{"id":"b","text":"خاطئ؛ لا ينتقل الفيروس بالمصافحة أو المشاركة العادية، بل بالجنس غير المحمي والدم الملوّث ومن الأمّ إلى جنينها"},{"id":"c","text":"صحيح، لأنّ الفيروس ينتقل بالهواء"},{"id":"d","text":"صحيح، لأنّ لسعة البعوض تنقله"}]'::jsonb, 'b', 'فيروس السيدا (VIH) ينتقل عبر العلاقة الجنسية غير المحمية والدم الملوّث ومن الأمّ إلى جنينها، ولا ينتقل بالمصافحة أو المشاركة العادية أو الهواء أو البعوض. الادّعاء خاطئ ويؤدّي إلى وصم المصابين ظلمًا، والتوعية العلمية تصحّح هذه المفاهيم الخاطئة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ae3e86ae-32dc-5c51-a4e2-977616c6f8a2', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'لماذا يُعدّ الواقي الذكري وسيلة وقاية مزدوجة في الصحة الإنجابية؟', '[{"id":"a","text":"لأنّه يعالج السيدا بعد الإصابة"},{"id":"b","text":"لأنّه يقي من الأمراض المنقولة جنسيًّا ويمنع الحمل غير المرغوب فيه معًا"},{"id":"c","text":"لأنّه يزيد إنتاج النطاف"},{"id":"d","text":"لأنّه يوقف الدورة الجنسية عند المرأة"}]'::jsonb, 'b', 'الواقي الذكري حاجز يمنع تبادل السوائل، فيقي في آنٍ واحد من العدوى بالأمراض المنقولة جنسيًّا (ومنها السيدا) ومن الحمل غير المرغوب فيه. وهو ليس علاجًا للسيدا، ولا يزيد إنتاج النطاف، ولا يوقف الدورة الجنسية للمرأة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('34e03026-5e9d-54e3-8fcf-62aa589b5472', '52ce77a3-8b9d-57b8-9e21-0add681cbce5', 'يُتابَع طفلٌ لأمّ مصابة بفيروس السيدا. أيّ تدبير يقلّل خطر انتقال الفيروس إليه؟', '[{"id":"a","text":"تجنّب مصافحة الأمّ لطفلها"},{"id":"b","text":"المتابعة الطبّية أثناء الحمل والولادة والحذر في الرضاعة وفق إرشاد الطبيب"},{"id":"c","text":"إبعاد الطفل عن الطعام المشترك"},{"id":"d","text":"منع الطفل من اللعب مع غيره"}]'::jsonb, 'b', 'ينتقل الفيروس من الأمّ إلى طفلها أثناء الحمل أو الولادة أو الرضاعة، لذا تقلّل المتابعة الطبّية في هذه المراحل من الخطر. المصافحة والطعام المشترك واللعب لا تنقل الفيروس أصلًا، فالتدابير المبنية عليها لا قيمة وقائية لها بل تسبّب وصمًا لا مبرّر له.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

