  ('a3806169-7a5a-5797-b569-752b5dd04edb', 'e52ecd64-7704-5ca8-8fc8-78d5dcb4fd53', 'sciences-vie-terre', '🛡️ تدرّب على الفصل: مراجعة التكاثر عند الإنسان', 3, 120, 30, 'boss', 'admin', 5)
