INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4ec0849b-98db-538d-8d52-74d6512bb941', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'أين تُنتَج النطاف وأين تُنتَج البويضات؟', '[{"id":"a","text":"النطاف في الخصيتين والبويضات في المبيضين"},{"id":"b","text":"النطاف في البروستاتا والبويضات في الرحم"},{"id":"c","text":"النطاف في المبيضين والبويضات في الخصيتين"},{"id":"d","text":"كلاهما يُنتَج في الغدد الملحقة"}]'::jsonb, 'a', 'الخصيتان هما الغدّتان التناسليتان عند الرجل وتنتجان النطاف، والمبيضان هما الغدّتان التناسليتان عند المرأة وينتجان البويضات. البروستاتا غدّة ملحقة تفرز جزءًا من السائل المنوي ولا تنتج مشيجًا، والرحم مكان التعشيش والحمل لا إنتاج البويضات، والغدد الملحقة لا تنتج مشيجًا أصلًا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3d76dd20-0515-5e18-b768-f0193ecaf8f1', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'ما الحدث الذي يميّز بداية البلوغ عند الفتاة؟', '[{"id":"a","text":"ظهور أوّل طمث (الحيض)"},{"id":"b","text":"نزول الخصيتين"},{"id":"c","text":"توقّف نموّ العظام نهائيًّا"},{"id":"d","text":"اختفاء العلامات الجنسية الثانوية"}]'::jsonb, 'a', 'أوّل طمث علامة دالّة على بدء نشاط المبيضين ودخول الفتاة مرحلة البلوغ والقدرة على الإنجاب. نزول الخصيتين شأن ذكوري لا أنثوي، والبلوغ يُرافقه ظهور العلامات الجنسية الثانوية لا اختفاؤها، ونموّ العظام يستمرّ خلال هذه المرحلة لا يتوقّف فجأةً.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b8cfb1f9-52b7-5fb5-ab41-dea79ac151c3', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'ماذا نقصد بـ«الإباضة» في الدورة الجنسية عند المرأة؟', '[{"id":"a","text":"تساقط بطانة الرحم خارج الجسم"},{"id":"b","text":"تحرير المبيض لبويضة ناضجة حول منتصف الدورة"},{"id":"c","text":"اندماج النطفة بالبويضة"},{"id":"d","text":"انغراس البيضة المخصّبة في الرحم"}]'::jsonb, 'b', 'الإباضة هي تحرير المبيض لبويضة ناضجة، وتحدث عادةً حول اليوم 14 من دورة طولها 28 يومًا. تساقط بطانة الرحم هو الطمث، واندماج النطفة بالبويضة هو الإلقاح، وانغراس البيضة المخصّبة هو التعشيش؛ وكلّها أحداث مختلفة عن الإباضة.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('71d59e4d-2af1-53c4-a747-8ea29a033b7d', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'ما الفرق الأساسي بين الإلقاح والتعشيش؟', '[{"id":"a","text":"الإلقاح اندماج النطفة بالبويضة، والتعشيش انغراس البيضة المخصّبة في بطانة الرحم"},{"id":"b","text":"هما اسمان لحدث واحد"},{"id":"c","text":"الإلقاح يحدث في الرحم والتعشيش في البوق"},{"id":"d","text":"التعشيش يسبق الإلقاح دائمًا"}]'::jsonb, 'a', 'الإلقاح هو اندماج النطفة بالبويضة (يحدث عادةً في البوق) فتتكوّن البيضة المخصّبة، أمّا التعشيش فهو انغراس هذه البيضة بعد انقسامها وتنقّلها في بطانة الرحم. فهما حدثان مختلفان، والإلقاح يسبق التعشيش لا العكس، والإلقاح يقع في البوق لا في الرحم.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c2a87dd0-6ed6-5a5c-ac71-77c72a3709a4', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'أمّ مرضع لاحظت غياب الطمث طوال أشهر الحمل ثمّ عودته بعده. ما التفسير الصحيح لانقطاعه أثناء الحمل؟', '[{"id":"a","text":"لأنّ المبيضين تعطّلا نهائيًّا"},{"id":"b","text":"لأنّ بطانة الرحم تبقى محفوظةً لاحتضان الجنين فلا تتساقط"},{"id":"c","text":"لأنّ الإلقاح يتكرّر كلّ شهر"},{"id":"d","text":"لأنّ النطاف تواصل تجديد البطانة"}]'::jsonb, 'b', 'أثناء الحمل تُحفظ بطانة الرحم لاحتضان الجنين ولا تتساقط، فينقطع الطمث ثمّ يعود بعد الولادة. المبيضان لم يتعطّلا نهائيًّا بدليل عودة الدورة، ولا يتكرّر الإلقاح خلال الحمل، والنطاف لا دور لها في تجديد بطانة الرحم.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4996b22f-3a8c-5b1f-90c9-c14f0bc94953', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'لماذا يحمل الطفل صفاتٍ من أبيه وأمّه معًا؟', '[{"id":"a","text":"لأنّ المعلومة الوراثية تأتي كلّها من الأمّ"},{"id":"b","text":"لأنّ النطفة والبويضة يحمل كلّ منهما نصف المعلومة الوراثية فتجتمعان في البيضة المخصّبة"},{"id":"c","text":"لأنّ الطفل يكتسب الصفات بعد الولادة من البيئة فقط"},{"id":"d","text":"لأنّ السائل المنوي يحمل صفات الأبوين"}]'::jsonb, 'b', 'يحمل كلّ مشيج (النطفة والبويضة) نصف المعلومة الوراثية، فعند الإلقاح تجتمع المعلومتان في البيضة المخصّبة فيرث الطفل من الأبوين معًا. المعلومة لا تأتي من الأمّ وحدها، والصفات الوراثية تُورَّث عند الإلقاح لا تُكتسب من البيئة وحدها بعد الولادة، والسائل المنوي يغذّي النطاف ويحملها ولا يحمل المعلومة بنفسه.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9620a69a-80ce-5e0d-adf2-287c66f14c4d', 'e52ecd64-7704-5ca8-8fc8-78d5dcb4fd53', 'sciences-vie-terre', '👑 تحدّي المناظرة ⭐⭐⭐⭐: التكاثر والصحّة الإنجابية — تحليل واستدلال', 4, 300, 60, 'challenge', 'admin', 6)
