INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7eb78b18-c3e9-5af1-8f87-6bd3ba822715', '9620a69a-80ce-5e0d-adf2-287c66f14c4d', 'بعد الإباضة، يرتفع إفراز هرمون البروجسترون من الجسم الأصفر. ما الدور الأساسيّ لهذا الهرمون؟', '[{"id":"a","text":"تثخين بطانة الرحم وتهيئتها لتعشيش بويضة مخصّبة محتملة"},{"id":"b","text":"إطلاق البويضة من المبيض"},{"id":"c","text":"بدء نزول الحيض فورًا"},{"id":"d","text":"إنتاج النطاف عند الرجل"}]'::jsonb, 'a', 'بعد الإباضة يتحوّل الجُريب إلى جسم أصفر يُفرز البروجسترون الذي يُثخّن بطانة الرحم ويُغنيها بالأوعية استعدادًا لاستقبال بويضة مخصّبة (التعشيش). ✓ الخطأ الشائع: نسب الإباضة إلى البروجسترون (الإباضة يحرّضها ارتفاع الـ LH)؛ أو ظنّ أنّه يبدأ الحيض (بل تراجُعه هو ما يُطلق الحيض عند غياب الإخصاب).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
