INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9096821e-09c0-513b-8613-b418bae47949', '9620a69a-80ce-5e0d-adf2-287c66f14c4d', 'قال تلميذ: «يحدث الحيض لأنّ البويضة المخصّبة تنغرس في جدار الرحم». ما الخطأ؟', '[{"id":"a","text":"الحيض يحدث عند غياب الإخصاب: تتساقط بطانة الرحم؛ أمّا التعشيش فيوقف الحيض"},{"id":"b","text":"لا خطأ، الحيض ناتج عن التعشيش"},{"id":"c","text":"الحيض يحدث فقط أثناء الحمل"},{"id":"d","text":"الحيض هو خروج البويضة المخصّبة نفسها"}]'::jsonb, 'a', 'الحيض هو تساقط بطانة الرحم عندما لا يحدث إخصاب ولا تعشيش (يتراجع البروجسترون فتنهار البطانة). أمّا تعشيش بويضة مخصّبة فيُبقي البطانة ويوقف الحيض (بداية الحمل). (تمرين «صيد الخطأ».) الخطأ الشائع: عكس العلاقة بين التعشيش والحيض.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7fd0133e-3fd4-5c08-99d9-dedea3f27bc4', '9620a69a-80ce-5e0d-adf2-287c66f14c4d', 'امرأة دورتها منتظمة طولها 32 يومًا، وتحدث الإباضة عندها قبل بداية الحيض التالي بـ 14 يومًا. في أيّ يوم من الدورة تحدث الإباضة تقريبًا؟', '[{"id":"a","text":"اليوم 18"},{"id":"b","text":"اليوم 14"},{"id":"c","text":"اليوم 16"},{"id":"d","text":"اليوم 32"}]'::jsonb, 'a', 'الإباضة تسبق الحيض التالي بـ 14 يومًا بثبات، فنطرح من طول الدورة: 32 − 14 = 18، أي يوم الإباضة هو اليوم 18. ✓ الخطأ الشائع: افتراض أنّ الإباضة دائمًا في اليوم 14 (صحيح فقط لدورة 28 يومًا)؛ أو أخذ منتصف الدورة 32/2 = 16.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('32a3ce47-8e7b-5e13-aac6-9c0c146f9e02', '9620a69a-80ce-5e0d-adf2-287c66f14c4d', 'أُجري تتبّع هرمونيّ لامرأة تعاني تعذّرًا في الإنجاب، فتبيّن غياب الارتفاع المفاجئ لهرمون LH في منتصف الدورة. ما التفسير الأرجح؟', '[{"id":"a","text":"عدم حدوث الإباضة، فلا تُطلَق بويضة للإخصاب"},{"id":"b","text":"غياب النطاف تمامًا عند الرجل"},{"id":"c","text":"انسداد قناتَي فالوب فقط"},{"id":"d","text":"زيادة مفرطة في البروجسترون"}]'::jsonb, 'a', 'الارتفاع المفاجئ لهرمون LH هو المُحرّض المباشر للإباضة؛ فغيابه يعني عدم إطلاق البويضة (غياب الإباضة)، ومن ثمّ تعذّر الإخصاب. (تمرين تحليل وثيقة.) ✓ الخطأ الشائع: نسب المشكلة إلى الرجل أو إلى القناتين مع أنّ المعطى الهرمونيّ يخصّ الإباضة عند المرأة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c68896c4-207b-54f4-8795-30927415f895', '9620a69a-80ce-5e0d-adf2-287c66f14c4d', 'كيف تمنع الحبوب المانعة للحمل (الهرمونية) حدوث الحمل بصفة أساسية؟', '[{"id":"a","text":"بمنع الإباضة (تثبيط إطلاق البويضة)"},{"id":"b","text":"بقتل النطاف بعد القذف"},{"id":"c","text":"بإجهاض بويضة مخصّبة بعد تعشيشها"},{"id":"d","text":"بمنع التقاء النطفة بالبويضة ميكانيكيًّا كالواقي"}]'::jsonb, 'a', 'الحبوب الهرمونية تُبقي مستوى الهرمونات ثابتًا فتمنع الارتفاع المحرّض للإباضة، فلا تُطلَق بويضة أصلًا ولا يحدث إخصاب. ✓ الخطأ الشائع: ظنّ أنّها تُجهض حملًا قائمًا (بل تمنع نشوءه)؛ أو خلطها بالواقي الذكريّ (حاجز ميكانيكيّ).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1598fb1e-a2fc-576d-ab5a-a44f822e4f3c', '9620a69a-80ce-5e0d-adf2-287c66f14c4d', 'في المسار الطبيعيّ للتكاثر، أين يحدث الإخصاب عادةً، وأين تُعشّش البويضة المخصّبة؟', '[{"id":"a","text":"الإخصاب في قناة فالوب ; التعشيش في الرحم"},{"id":"b","text":"الإخصاب في الرحم ; التعشيش في المبيض"},{"id":"c","text":"الإخصاب في المبيض ; التعشيش في قناة فالوب"},{"id":"d","text":"الإخصاب والتعشيش كلاهما في المهبل"}]'::jsonb, 'a', 'يلتقي النطف بالبويضة ويحدث الإخصاب في قناة فالوب (البوق)، ثمّ تنتقل البويضة المخصّبة وهي تنقسم لتُعشّش في بطانة الرحم. ✓ الخطأ الشائع: توطين الإخصاب في الرحم أو في المبيض؛ الرحم مكان التعشيش والنموّ لا الإخصاب.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

