INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ed3b59f8-da5a-5bc4-a945-b8e1ef4a53b2', 'a274e462-368e-5cd0-8155-351efa152309', 'ما هو «المستضدّ» (الأنتيجان)؟', '[{"id":"a","text":"كرية بيضاء تبتلع الميكروبات"},{"id":"b","text":"جزيء غريب عن الجسم يستثير ردّ فعل دفاعيًّا"},{"id":"c","text":"جسم مضادّ ينتجه الجسم لمقاومة المرض"},{"id":"d","text":"دواء يقتل البكتيريا"}]'::jsonb, 'b', 'المستضدّ هو كلّ جزيء غريب (غير ذاتي) يدخل الجسم فيتعرّف عليه جهاز المناعة كأجنبيّ ويستثير الدفاع. الكرية البيضاء والجسم المضادّ أدوات دفاع لا مستضدّات، والدواء ليس جزءًا من جهاز المناعة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7f9d4a7b-d61f-55a8-993f-2b53a5bacc9b', 'a274e462-368e-5cd0-8155-351efa152309', 'أيّ ممّا يلي حاجز طبيعي يمثّل خطّ الدفاع الأوّل؟', '[{"id":"a","text":"الأجسام المضادّة"},{"id":"b","text":"اللمفاويات T"},{"id":"c","text":"الجلد السليم"},{"id":"d","text":"البلعمة"}]'::jsonb, 'c', 'خطّ الدفاع الأوّل هو الحواجز الطبيعية مثل الجلد السليم والمخاطيّات والإفرازات. أمّا البلعمة فهي خطّ ثانٍ (مناعة غير نوعية)، والأجسام المضادّة واللمفاويات T من المناعة النوعية (خطّ ثالث).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
