  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c4e554d8-cc06-5b4d-a4d4-e852123e2c7a', 'a274e462-368e-5cd0-8155-351efa152309', 'ما الترتيب الصحيح لمراحل البلعمة؟', '[{"id":"a","text":"هضم ← ابتلاع ← التصاق ← إطراح"},{"id":"b","text":"التصاق ← ابتلاع ← هضم ← إطراح"},{"id":"c","text":"ابتلاع ← التصاق ← إطراح ← هضم"},{"id":"d","text":"إطراح ← هضم ← ابتلاع ← التصاق"}]'::jsonb, 'b', 'تبدأ البلعمة بالتصاق الكرية البيضاء بالميكروب، ثمّ ابتلاعه (الإحاطة به وإدخاله)، ثمّ هضمه بالإنزيمات، وأخيرًا إطراح البقايا. الترتيب المنطقي يبدأ بالاقتراب لا بالهضم.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('225f6708-eb96-5ee3-89e9-35d42975fc0d', 'a274e462-368e-5cd0-8155-351efa152309', 'لماذا توصف البلعمة بأنّها مناعة «غير نوعية»؟', '[{"id":"a","text":"لأنّها تهاجم ميكروبًا واحدًا محدّدًا فقط"},{"id":"b","text":"لأنّها تتدخّل ضدّ أيّ غازٍ مهما كان نوعه"},{"id":"c","text":"لأنّها تنتج أجسامًا مضادّة نوعية"},{"id":"d","text":"لأنّها تحتفظ بذاكرة عن كلّ ميكروب"}]'::jsonb, 'b', 'البلعمة غير نوعية لأنّها تتدخّل بالطريقة نفسها ضدّ أيّ ميكروب دون تمييز نوعه ودون ذاكرة. التعرّف على ميكروب محدّد وإنتاج أجسام مضادّة نوعية وامتلاك الذاكرة كلّها خصائص المناعة النوعية.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f7bdf433-23d1-597d-9230-aa4c7eb71a0c', 'a274e462-368e-5cd0-8155-351efa152309', 'ما الذي يميّز الجسم المضادّ بأنّه «نوعي»؟', '[{"id":"a","text":"أنّه يهاجم جميع الميكروبات في الجسم دفعةً واحدة"},{"id":"b","text":"أنّه يرتبط بمستضدّ واحد موافق له فقط كالمفتاح وقفله"},{"id":"c","text":"أنّه يبتلع الميكروب ويهضمه"},{"id":"d","text":"أنّه يدمّر اللمفاويات المصابة"}]'::jsonb, 'b', 'نوعية الجسم المضادّ تعني أنّه يتعرّف على مستضدّ واحد فقط يوافق شكله (كالمفتاح وقفله) ويرتبط به. لا يهاجم كلّ الميكروبات، والابتلاع والهضم وظيفة الكريات البلعمية، وتدمير الخلايا المصابة وظيفة اللمفاويات T.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c80316fd-ccd8-5796-8ce4-01ab290692ed', 'a274e462-368e-5cd0-8155-351efa152309', 'ما سبب خطورة السيدا (SIDA) على جهاز المناعة؟', '[{"id":"a","text":"أنّ فيروس VIH يقوّي اللمفاويات فيصبح الجسم مفرط المناعة"},{"id":"b","text":"أنّ فيروس VIH يدمّر اللمفاويات T فينهار جهاز المناعة وتظهر أمراض انتهازية"},{"id":"c","text":"أنّه بكتيريا تُعالَج بسهولة بالمضادّات الحيوية"},{"id":"d","text":"أنّه يزيد إنتاج الأجسام المضادّة بشكل مفرط"}]'::jsonb, 'b', 'فيروس VIH يهاجم ويدمّر اللمفاويات T الأساسية في المناعة النوعية، فينهار جهاز المناعة تدريجيًّا ويعجز الجسم عن مقاومة العدوى فتظهر أمراض انتهازية. السيدا فيروس لا بكتيريا، ولا تنفع معه المضادّات الحيوية، وهو يُضعف المناعة لا يقوّيها.', 7, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
