  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('96d100ae-a565-548c-a68a-12d239d5149a', 'a274e462-368e-5cd0-8155-351efa152309', 'ما الفرق الأساسي بين التلقيح والمصل؟', '[{"id":"a","text":"التلقيح يحقن أجسامًا مضادّة جاهزة، والمصل يحقن ميكروبًا مُضعَّفًا"},{"id":"b","text":"التلقيح يحقن ميكروبًا مُضعَّفًا فيصنع الجسمُ مناعته (وقاية)، والمصل يحقن أجسامًا مضادّة جاهزة (علاج سريع)"},{"id":"c","text":"كلاهما يحقن أجسامًا مضادّة جاهزة وتأثيرهما طويل الأمد"},{"id":"d","text":"التلقيح علاج فوري، والمصل وقاية طويلة الأمد"}]'::jsonb, 'b', 'التلقيح يُدخل ميكروبًا مُضعَّفًا أو ميّتًا فيستثير الجسم ليصنع أجسامه المضادّة وذاكرته المناعية: وقاية مسبقة طويلة الأمد. المصل يُدخل أجسامًا مضادّة جاهزة من غيره: علاج سريع لكن قصير الأمد ودون ذاكرة. الخياران (أ) و(د) يعكسان الدورين.', 8, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
