INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0d8bf231-f6cd-5321-b685-2e2237923776', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'أيّ ممّا يلي متعضّية مجهرية لا تتكاثر إلّا داخل خلية مضيفة؟', '[{"id":"a","text":"البكتيريا"},{"id":"b","text":"الفيروس"},{"id":"c","text":"الكرية البيضاء"},{"id":"d","text":"الجسم المضادّ"}]'::jsonb, 'b', 'الفيروس ليس خلية ولا يملك جهازًا للتكاثر بنفسه، فلا يتكاثر إلّا بدخول خلية حيّة (مضيفة) واستغلالها لصنع نسخ منه. أمّا البكتيريا فهي خلية تتكاثر بالانقسام بمفردها. الكرية البيضاء والجسم المضادّ من أدوات الدفاع لا من الميكروبات.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dfa1b322-f81a-506d-9a27-1e1469a2522c', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'بِمَ تُعالَج العدوى البكتيرية؟', '[{"id":"a","text":"بالمضادّات الحيوية"},{"id":"b","text":"باللقاحات فقط"},{"id":"c","text":"بمضادّات لا تؤثّر إلّا في الفيروسات"},{"id":"d","text":"لا علاج لها إطلاقًا"}]'::jsonb, 'a', 'المضادّات الحيوية (Antibiotiques) فعّالة ضدّ البكتيريا فتقتلها أو توقف تكاثرها. وهي لا تؤثّر في الفيروسات إطلاقًا. اللقاح وسيلة وقاية مسبقة لا علاج لعدوى قائمة، والعدوى البكتيرية قابلة للعلاج.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('95219141-5521-5154-bb14-e1878ea1967d', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'ما المقصود بـ«العدوى»؟', '[{"id":"a","text":"إنتاج الجسم لأجسام مضادّة"},{"id":"b","text":"دخول متعضّية ممرضة إلى الجسم وتكاثرها فيه"},{"id":"c","text":"ابتلاع الكرية البيضاء للميكروب"},{"id":"d","text":"حقن مصل مضادّ للمرض"}]'::jsonb, 'b', 'العدوى هي دخول متعضّية مجهرية ممرضة إلى الجسم وتكاثرها فيه، عبر الهواء أو الماء أو الغذاء أو الجروح أو الاتّصال. إنتاج الأجسام المضادّة والبلعمة هما ردّا فعل دفاعيّان ضدّ العدوى لا العدوى ذاتها، وحقن المصل إجراء طبّي.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4ceffa55-c541-5898-a4c1-b4db8702b762', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'أيّ ممّا يلي ليس حاجزًا طبيعيًّا للدفاع عن الجسم؟', '[{"id":"a","text":"الجلد"},{"id":"b","text":"المخاط"},{"id":"c","text":"اللعاب والدموع"},{"id":"d","text":"الأجسام المضادّة"}]'::jsonb, 'd', 'الجلد والمخاط واللعاب والدموع حواجز طبيعية تمثّل خطّ الدفاع الأوّل الذي يمنع دخول الجراثيم. أمّا الأجسام المضادّة فتنتمي إلى المناعة النوعية (دفاع داخلي متأخّر) ولا تُعدّ حاجزًا طبيعيًّا.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('905ca97e-bdc1-540b-94db-34981c0e26c4', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'لماذا لا تنفع المضادّات الحيوية في علاج الأنفلونزا؟', '[{"id":"a","text":"لأنّ الأنفلونزا تسبّبها بكتيريا قويّة جدًّا"},{"id":"b","text":"لأنّ الأنفلونزا يسبّبها فيروس، والمضادّ الحيوي فعّال ضدّ البكتيريا فقط"},{"id":"c","text":"لأنّ المضادّ الحيوي يقوّي الفيروس"},{"id":"d","text":"لأنّ الأنفلونزا ليست عدوى"}]'::jsonb, 'b', 'الأنفلونزا مرض فيروسي، والمضادّات الحيوية لا تؤثّر إلّا في البكتيريا لأنّها تستهدف بنى خلوية لا توجد في الفيروسات. فهي إذن عديمة الفائدة ضدّ الفيروسات ولا تقوّيها، والأنفلونزا عدوى فيروسية فعلًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3dd4d1bd-fb69-501c-845d-e29cb6378bb8', 'f4c8c701-88bc-5536-bafa-ac6a6f8f4e83', 'ما الذي يحدث عادةً عند جرح الجلد بأداة ملوّثة؟', '[{"id":"a","text":"يصبح الجسم محصّنًا نهائيًّا ضدّ كلّ الأمراض"},{"id":"b","text":"يُخترَق خطّ الدفاع الأوّل فتتمكّن الجراثيم من الدخول وقد تسبّب عدوى"},{"id":"c","text":"تتوقّف كلّ دفاعات الجسم"},{"id":"d","text":"تتحوّل الجراثيم تلقائيًّا إلى أجسام مضادّة"}]'::jsonb, 'b', 'الجلد السليم حاجز يمنع دخول الجراثيم؛ فإذا جُرح اختُرق خطّ الدفاع الأوّل وأمكن للجراثيم الدخول وإحداث عدوى، فتتدخّل عندها الكريات البيضاء (خطّ ثانٍ). الجرح لا يمنح مناعة دائمة ولا يوقف الدفاعات، والجراثيم لا تتحوّل إلى أجسام مضادّة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

