INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fc1b9db7-ba16-5a86-a122-88533ff7851f', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'ما الخلايا المسؤولة عن البلعمة؟', '[{"id":"a","text":"الكريات الحمراء"},{"id":"b","text":"الكريات البيضاء البلعمية"},{"id":"c","text":"الصفيحات الدموية"},{"id":"d","text":"خلايا الجلد"}]'::jsonb, 'b', 'البلعمة تقوم بها الكريات البيضاء البلعمية التي تبتلع الميكروب وتهضمه. الكريات الحمراء تنقل الأكسجين، والصفيحات تتدخّل في تخثّر الدم، وخلايا الجلد حاجز طبيعي لا خلايا بلعمية.', 1, 'mcq', NULL, NULL)
