INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('eec7086d-db3e-5470-9329-1f506b013b6a', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'ما هي المرحلة الأخيرة في عملية البلعمة؟', '[{"id":"a","text":"الالتصاق"},{"id":"b","text":"الابتلاع"},{"id":"c","text":"إطراح بقايا الميكروب المهضوم"},{"id":"d","text":"الهضم"}]'::jsonb, 'c', 'تنتهي البلعمة بإطراح بقايا الميكروب بعد هضمه. الترتيب: التصاق ثمّ ابتلاع ثمّ هضم ثمّ إطراح، فالإطراح هو الخطوة الأخيرة.', 2, 'mcq', NULL, NULL)
