  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dc91df15-6b43-5536-891e-95745aadbbde', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'علامات الاحمرار والتورّم والألم والحرارة موضعيًّا تدلّ على:', '[{"id":"a","text":"شفاء تامّ ونهائي"},{"id":"b","text":"الالتهاب الذي يرافق نشاط الكريات البيضاء"},{"id":"c","text":"توقّف جهاز المناعة"},{"id":"d","text":"إنتاج مصل داخل الجسم"}]'::jsonb, 'b', 'هذه العلامات الأربع تميّز الالتهاب، وهو ردّ فعل دفاعي يرافق توافد الكريات البيضاء إلى مكان العدوى ونشاطها. وهو دليل على عمل المناعة لا على توقّفها، وليس شفاءً تامًّا، والجسم لا ينتج «مصلًا».', 3, 'mcq', NULL, NULL)
