  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('491b4317-0ecd-5415-a65d-7748002fc11d', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'أيّ نوع من اللمفاويات يهاجم مباشرةً الخلايا المصابة ويدمّرها؟', '[{"id":"a","text":"اللمفاويات B"},{"id":"b","text":"اللمفاويات T"},{"id":"c","text":"الكريات الحمراء"},{"id":"d","text":"الصفيحات الدموية"}]'::jsonb, 'b', 'اللمفاويات T مسؤولة عن المناعة الخلوية: تتعرّف على الخلايا المصابة (المعدِية) وتدمّرها مباشرةً. أمّا اللمفاويات B فتنتج أجسامًا مضادّة (مناعة خلطية)، والكريات الحمراء والصفيحات ليست لمفاويات.', 4, 'mcq', NULL, NULL)
