  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b92226a3-6d6f-56b2-bc2f-4e4d93714d2b', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'لماذا لا يمرض الشخص غالبًا عند لقائه ميكروبًا سبق له أن واجهه؟', '[{"id":"a","text":"لأنّ الميكروب يضعف من تلقاء نفسه مع الزمن"},{"id":"b","text":"بفضل الذاكرة المناعية التي تجعل الردّ الثاني أسرع وأقوى"},{"id":"c","text":"لأنّ الجلد يصبح أكثر سُمكًا"},{"id":"d","text":"لأنّ المضادّات الحيوية تبقى دائمًا في الدم"}]'::jsonb, 'b', 'بعد أوّل لقاء يحتفظ الجسم بخلايا ذاكرة، فعند لقاء ثانٍ بالميكروب نفسه يكون الردّ المناعي أسرع وأقوى فيُقضى عليه قبل ظهور المرض. الميكروب لا يضعف ذاتيًّا، والجلد لا يتغيّر سُمكه لذلك، والمضادّات الحيوية أدوية لا تبقى في الدم.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
