  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ba12d467-f325-53d7-b435-6e2016012912', '796f9185-d6da-58cb-a816-baa7f2ac578d', 'تُسمّى مناعة اللمفاويات B التي تعتمد على أجسام مضادّة ذائبة في سوائل الجسم:', '[{"id":"a","text":"مناعة خلوية"},{"id":"b","text":"مناعة خلطية"},{"id":"c","text":"مناعة غير نوعية"},{"id":"d","text":"مناعة وراثية"}]'::jsonb, 'b', 'تُسمّى مناعة خلطية لأنّها محمولة في أخلاط الجسم (سوائله كالدم) عبر الأجسام المضادّة التي تنتجها اللمفاويات B. أمّا المناعة الخلوية فتقوم بها اللمفاويات T مباشرةً، والبلعمة غير نوعية، ولا توجد «مناعة وراثية» بهذا المعنى هنا.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
