INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('14e823cf-30fc-548c-8963-37b1b24a36a7', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'في التلقيح، من الذي ينتج الأجسام المضادّة؟', '[{"id":"a","text":"تُحقن جاهزة من جسم آخر"},{"id":"b","text":"ينتجها جسم الملقَّح نفسه استجابةً للميكروب المُضعَّف"},{"id":"c","text":"تنتجها البكتيريا داخل اللقاح"},{"id":"d","text":"لا تُنتج أجسام مضادّة في التلقيح"}]'::jsonb, 'b', 'اللقاح يحتوي ميكروبًا مُضعَّفًا أو ميّتًا (أو مستضدّه) يستثير جسم الملقَّح ليصنع أجسامه المضادّة وخلايا ذاكرته. حقن أجسام مضادّة جاهزة من جسم آخر هو المصل لا التلقيح، والبكتيريا لا تنتج أجسامًا مضادّة، والتلقيح يستهدف أصلًا إنتاجها.', 1, 'mcq', NULL, NULL)
