  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fa75f8a4-9f9d-5f88-b206-083dc4bad1fc', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'ماذا تعني عبارة «السيدا متلازمة العوز المناعي المكتسب»؟', '[{"id":"a","text":"أنّه مرض وراثي ينتقل من الأبوين فقط"},{"id":"b","text":"أنّه حالة نقص في مناعة الجسم مكتسبة بسبب فيروس VIH"},{"id":"c","text":"أنّه فرط في نشاط المناعة"},{"id":"d","text":"أنّه عدوى بكتيرية بسيطة"}]'::jsonb, 'b', '«العوز المناعي» = نقص المناعة، و«المكتسب» = ناتج عن عدوى (فيروس VIH) لا عن وراثة. فهو إذن ضعف في المناعة لا فرط فيها، وليس وراثيًّا ولا عدوى بكتيرية بسيطة، بل عدوى فيروسية خطيرة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('547b29ab-ebe8-58f9-a489-6a9762f2bb63', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'أيّ من هذه الطرق لا ينتقل بها فيروس السيدا (VIH)؟', '[{"id":"a","text":"الدم الملوّث ومشاركة أدوات الحقن"},{"id":"b","text":"من الأمّ المصابة إلى جنينها"},{"id":"c","text":"المصافحة ومشاركة الطعام والعطس"},{"id":"d","text":"العلاقة الجنسية غير المحميّة"}]'::jsonb, 'c', 'ينتقل VIH عبر الدم الملوّث وأدوات الحقن المشتركة، والعلاقة الجنسية غير المحميّة، ومن الأمّ إلى جنينها. أمّا المصافحة ومشاركة الطعام والعطس فلا تنقله، ولذلك لا مبرّر لإقصاء المصابين اجتماعيًّا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d6079308-2039-5fd4-8588-4b70638d9877', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'مريض أُصيب بجرح ملوّث ويُخشى عليه من الكزاز، فما الإجراء العلاجي العاجل المناسب؟', '[{"id":"a","text":"حقن لقاح فقط والانتظار أسابيع"},{"id":"b","text":"حقن مصل مضادّ للكزاز لأنّه يوفّر أجسامًا مضادّة جاهزة فوريّة"},{"id":"c","text":"إعطاؤه مضادًّا حيويًّا فقط دون أيّ إجراء مناعي"},{"id":"d","text":"عدم التدخّل لأنّ الجسم سيتكفّل وحده فورًا"}]'::jsonb, 'b', 'الحالة طارئة تتطلّب حماية فورية، والمصل يمنح أجسامًا مضادّة جاهزة تعمل حالًا فيناسب العلاج العاجل. اللقاح بطيء (يحتاج أيّامًا لبناء المناعة) فلا يكفي وحده في الطوارئ، والاكتفاء بالامتناع أو بالمضادّ الحيوي لا يبطل سُمّ الكزاز بسرعة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bf81a271-35e2-51bd-a56f-7a22097ffc11', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'أيّ العبارات التالية صحيحة بخصوص مدّة الحماية؟', '[{"id":"a","text":"التلقيح يمنح حماية قصيرة، والمصل حماية طويلة الأمد"},{"id":"b","text":"التلقيح يمنح حماية طويلة الأمد (بذاكرة مناعية)، والمصل حماية قصيرة (بلا ذاكرة)"},{"id":"c","text":"كلاهما يمنح حماية دائمة مدى الحياة"},{"id":"d","text":"كلاهما حماية قصيرة لا تتجاوز اليوم"}]'::jsonb, 'b', 'التلقيح يُكسب الجسم ذاكرة مناعية فتكون حمايته طويلة الأمد، بينما المصل يقدّم أجسامًا مضادّة جاهزة تُستهلك ولا تترك ذاكرة فحمايته قصيرة. لذلك لا يصحّ القول إنّهما متساويان في المدّة ولا أنّ المصل أطول من التلقيح.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('85975a29-3b73-5283-b45c-50082f7bbdef', '6a48c608-35ba-5265-90c3-2e9bf50fbdc2', 'لماذا يصبح مريض السيدا عرضةً لأمراض كثيرة قد تكون قاتلة؟', '[{"id":"a","text":"لأنّ الفيروس يقوّي اللمفاويات فيهاجم الجسمُ نفسَه"},{"id":"b","text":"لأنّ تدمير اللمفاويات T يُضعف المناعة النوعية فيعجز الجسم عن مقاومة العدوى"},{"id":"c","text":"لأنّ الجلد يفقد كلّ حواجزه الطبيعية فجأةً"},{"id":"d","text":"لأنّ الجسم ينتج فائضًا من الأجسام المضادّة"}]'::jsonb, 'b', 'VIH يدمّر اللمفاويات T الأساسية في المناعة النوعية، فينهار الدفاع تدريجيًّا ويعجز الجسم عن مقاومة الميكروبات فتظهر أمراض انتهازية قد تكون قاتلة. الفيروس يُضعف المناعة لا يقوّيها، والمشكلة في اللمفاويات لا في الجلد، ولا علاقة لها بفائض الأجسام المضادّة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'd99e2d63-4a69-52a9-96c9-39d1b17da995', 'sciences-vie-terre', '👑 تحدّي النخبة: المناعة — تحليل وتركيب', 4, 300, 60, 'challenge', 'admin', 4)
