INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8aacf3aa-1540-535d-aeeb-1f5a6d3b1fad', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'بعد حقن لقاح، قِيس تركيز الأجسام المضادّة في الدم: ارتفع ارتفاعًا ضعيفًا وبطيئًا بعد الحقنة الأولى، ثمّ ارتفع ارتفاعًا قويًّا وسريعًا بعد الحقنة الثانية بالمستضدّ نفسه. ما التفسير الصحيح؟', '[{"id":"a","text":"الحقنة الثانية أدخلت أجسامًا مضادّة جاهزة"},{"id":"b","text":"الردّ الثاني أقوى وأسرع بفضل الذاكرة المناعية المتكوّنة بعد الحقنة الأولى"},{"id":"c","text":"الجسم نسي المستضدّ تمامًا بين الحقنتين"},{"id":"d","text":"المستضدّ تكاثر داخل الدم فأنتج الأجسام المضادّة بنفسه"}]'::jsonb, 'b', 'الحقنة الأولى تُكوّن خلايا ذاكرة، فعند اللقاء الثاني بالمستضدّ نفسه يكون الردّ أسرع وأقوى (إنتاج وفير وسريع للأجسام المضادّة). اللقاح لا يحقن أجسامًا مضادّة جاهزة (ذلك دور المصل)، والذاكرة تنفي النسيان، والمستضدّ لا ينتج الأجسام المضادّة بل يستثير الجسم لإنتاجها.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e59e6651-39d8-51cc-b0ab-77d608c80ba9', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'قورن بين تجربتين: فأر (أ) حُقن بميكروب مُضعَّف ثمّ بعد أسابيع بالميكروب الممرض فلم يمرض؛ فأر (ب) حُقن مباشرةً بالميكروب الممرض فمرض. ما الاستنتاج؟', '[{"id":"a","text":"الميكروب المُضعَّف هو الذي قتل الميكروب الممرض في دم الفأر (أ)"},{"id":"b","text":"الحقن الأوّل بالميكروب المُضعَّف أكسب الفأر (أ) مناعة (تلقيح) فقاوم الميكروب الممرض"},{"id":"c","text":"الفأر (ب) كان أضعف بنية فقط دون علاقة بالمناعة"},{"id":"d","text":"الميكروب الممرض غير ممرض أصلًا"}]'::jsonb, 'b', 'الفرق الوحيد بين الفأرين هو الحقن المسبق بالميكروب المُضعَّف؛ فبما أنّ الفأر (أ) لم يمرض، فإنّ هذا الحقن أكسبه مناعة (مبدأ التلقيح: ذاكرة وأجسام مضادّة). لا يبقى الميكروب المُضعَّف ليقتل الممرض، والفأر (ب) مرض لأنّه غير ملقَّح، والميكروب ممرض فعلًا بدليل مرض (ب).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('90feb615-2b2b-56ba-943e-5d42595f4154', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'طفلٌ تعرّض لعضّة كلب يُشتبه بإصابته بالكَلَب (داء السُّعار). لِمَ يُعطى عادةً المصل واللقاح معًا؟', '[{"id":"a","text":"المصل يمنح حماية فورية بأجسام مضادّة جاهزة، واللقاح يبني حماية طويلة الأمد لاحقًا"},{"id":"b","text":"لأنّ المصل واللقاح شيء واحد لا فرق بينهما"},{"id":"c","text":"لأنّ كليهما يحقن ميكروبًا مُضعَّفًا"},{"id":"d","text":"لأنّ اللقاح يعمل فورًا والمصل بعد أسابيع"}]'::jsonb, 'a', 'الكَلَب خطير ويحتاج حمايةً فورية يوفّرها المصل (أجسام مضادّة جاهزة تعمل حالًا)، يرافقه اللقاح ليبني مناعة طويلة الأمد عبر الذاكرة. هما مختلفان (المصل أجسام جاهزة، اللقاح ميكروب مُضعَّف)، والفوري هو المصل لا اللقاح، فالخياران الباقيان يقلبان الأدوار.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e7f9403b-2a71-5bf8-8bc8-8bcda864c2ce', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'لوحظ في دم مريض بالسيدا انخفاضٌ متواصل في عدد اللمفاويات T مع تزايد العدوى الانتهازية. ما العلاقة السببية الصحيحة؟', '[{"id":"a","text":"العدوى الانتهازية هي التي تخلق فيروس VIH"},{"id":"b","text":"تدمير VIH للمفاويات T يُضعف المناعة، فتنتهز الميكروبات هذا الضعف وتسبّب العدوى"},{"id":"c","text":"انخفاض اللمفاويات T يقوّي المناعة فتقلّ العدوى"},{"id":"d","text":"لا علاقة بين اللمفاويات T والعدوى الانتهازية"}]'::jsonb, 'b', 'VIH يدمّر اللمفاويات T فينخفض عددها وتضعف المناعة النوعية، فتنتهز الميكروبات هذا الضعف وتسبّب أمراضًا (عدوى انتهازية). العلاقة طردية بين هبوط اللمفاويات وتزايد العدوى. العدوى لا تخلق الفيروس، وهبوط اللمفاويات يُضعف المناعة لا يقوّيها، والعلاقة قائمة لا منعدمة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f9be8486-4590-5088-9040-3192630fe12a', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'مريضٌ يعاني عدوى فيروسية، فطلب من الطبيب مضادًّا حيويًّا «ليشفى أسرع». ما الردّ العلمي الصحيح؟', '[{"id":"a","text":"المضادّ الحيوي سيقضي على الفيروس فورًا"},{"id":"b","text":"المضادّ الحيوي لا يؤثّر في الفيروسات، وسوء استعماله قد يسبّب مقاومة البكتيريا للمضادّات"},{"id":"c","text":"المضادّ الحيوي يقوّي الفيروس فيشتدّ المرض دائمًا"},{"id":"d","text":"المضادّ الحيوي يتحوّل داخل الجسم إلى لقاح ضدّ الفيروس"}]'::jsonb, 'b', 'المضادّات الحيوية تستهدف البكتيريا فقط ولا أثر لها في الفيروسات، فطلبها لعدوى فيروسية لا فائدة منه، بل استعمالها العشوائي يسهم في نشوء بكتيريا مقاومة للمضادّات. وهو لا يقتل الفيروس ولا «يقوّيه» ولا يتحوّل إلى لقاح.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2e9d7a5c-3647-547e-adee-13a69d9dbf1c', '4e8e7777-2b8c-5481-8ce0-cb008e2141cc', 'صُنّف التالي ترتيبًا منطقيًّا لخطوط الدفاع عند دخول ميكروب اخترق الجلد: (1) الأجسام المضادّة النوعية، (2) الحواجز الطبيعية، (3) البلعمة. ما الترتيب الزمني الصحيح لتدخّلها؟', '[{"id":"a","text":"1 ثمّ 2 ثمّ 3"},{"id":"b","text":"2 ثمّ 3 ثمّ 1"},{"id":"c","text":"3 ثمّ 1 ثمّ 2"},{"id":"d","text":"1 ثمّ 3 ثمّ 2"}]'::jsonb, 'b', 'الدفاع يبدأ بالحواجز الطبيعية (خطّ أوّل يمنع الدخول)، فإذا اخترقها الميكروب تدخّلت البلعمة (مناعة غير نوعية سريعة)، وإن لم تكفِ تدخّلت المناعة النوعية بالأجسام المضادّة واللمفاويات (أبطأ وأدقّ). إذن: 2 ثمّ 3 ثمّ 1، وبقيّة الترتيبات تخالف هذا التسلسل.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

