INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7bec2444-166c-5816-b3d9-ecd9e08def33', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'ما المقصود بالمستضدّ (l''antigène)؟', '[{"id":"a","text":"جسم غريب يدخل الجسم فيستثير ردّ فعل مناعيًّا"},{"id":"b","text":"جسم مضادّ ينتجه الجسم للدفاع"},{"id":"c","text":"دواء يقتل البكتيريا مباشرةً"},{"id":"d","text":"خليّة دم حمراء"}]'::jsonb, 'a', 'المستضدّ جسم غريب (ميكروب أو سُمّ…) يدخل الجسم فيستثير المناعة لإنتاج أجسام مضادّة ضدّه. الجسم المضادّ هو ردّ الجسم على المستضدّ لا المستضدّ نفسه، والدواء القاتل للبكتيريا هو المضادّ الحيوي، وكريّة الدم الحمراء تنقل الأكسجين ولا علاقة لها بتعريف المستضدّ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('69a3daf3-d1a8-5d46-83ac-f0db66d268c8', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'أيّ خطّ دفاعي يمثّل الحاجز الأوّل الذي يمنع دخول الميكروبات إلى الجسم؟', '[{"id":"a","text":"الجلد والأغشية المخاطية السليمة"},{"id":"b","text":"اللمفاويات T فقط"},{"id":"c","text":"الأجسام المضادّة في الدم"},{"id":"d","text":"خلايا الذاكرة المناعية"}]'::jsonb, 'a', 'الجلد والأغشية المخاطية السليمة حواجز طبيعية أولى تمنع دخول الميكروبات. أمّا اللمفاويات والأجسام المضادّة وخلايا الذاكرة فتنتمي إلى الدفاع النوعي الداخلي الذي يتدخّل بعد اختراق الميكروب للحواجز الأولى، فلا تكون هي الحاجز الأوّل.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3522af16-158b-527b-af8c-6c7874578b9c', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'ما الذي يميّز المناعة النوعية عن المناعة الطبيعية (غير النوعية)؟', '[{"id":"a","text":"النوعية موجّهة ضدّ ميكروب محدّد وتترك ذاكرة، أمّا غير النوعية فعامّة وسريعة"},{"id":"b","text":"النوعية عامّة ضدّ كلّ الميكروبات بلا تمييز"},{"id":"c","text":"غير النوعية تترك ذاكرة مناعية طويلة الأمد"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'a', 'المناعة النوعية موجّهة ضدّ مستضدّ محدّد (بأجسام مضادّة ولمفاويات مختصّة) وتترك ذاكرة مناعية، بينما المناعة الطبيعية ردّ سريع عامّ ضدّ أيّ دخيل بلا تمييز ولا ذاكرة. لذلك العبارتان (ب) و(ج) معكوستان، والقول بعدم وجود فرق خاطئ.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('24f7201a-0436-5b0f-94f5-d41e71342f6c', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'صديق يخاف من زميل مصاب بفيروس السيدا (VIH) ويتجنّب مصافحته. ما التصحيح العلمي السليم؟', '[{"id":"a","text":"الخوف مبرَّر لأنّ المصافحة تنقل الفيروس"},{"id":"b","text":"المصافحة والاحتكاك اليومي العادي لا ينقلان الفيروس فلا مبرّر للإقصاء"},{"id":"c","text":"العطس ومشاركة الطعام ينقلان الفيروس بسرعة"},{"id":"d","text":"الفيروس ينتقل عبر الهواء فقط"}]'::jsonb, 'b', 'ينتقل VIH عبر الدم الملوّث وأدوات الحقن المشتركة والعلاقة الجنسية غير المحميّة ومن الأمّ إلى جنينها، أمّا المصافحة والاحتكاك العادي ومشاركة الطعام والعطس فلا تنقله، فلا مبرّر للخوف أو الإقصاء الاجتماعي. القول إنّه ينتقل بالمصافحة أو العطس أو عبر الهواء خاطئ علميًّا.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a8f1275f-176b-51d2-b051-c3e72afd3988', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'طبيب أراد منح طفل سليم حمايةً وقائيةً طويلة الأمد ضدّ مرض مُعدٍ. أيّ إجراء يختار؟', '[{"id":"a","text":"التلقيح لأنّه يكسب الجسم ذاكرة مناعية تدوم طويلًا"},{"id":"b","text":"المصل لأنّه يعطي حماية دائمة"},{"id":"c","text":"المضادّ الحيوي للوقاية المستمرّة"},{"id":"d","text":"لا حاجة لأيّ إجراء وقائي"}]'::jsonb, 'a', 'الوقاية طويلة الأمد للسليم تتحقّق بالتلقيح، لأنّه يستثير الجسم ليصنع أجسامه المضادّة وخلايا ذاكرته فتدوم الحماية. المصل حماية علاجية فورية لكنّها قصيرة بلا ذاكرة، والمضادّ الحيوي علاج للعدوى البكتيرية لا وسيلة وقاية مناعية، والامتناع يترك الطفل دون حماية.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f546e528-792b-5710-a28d-a7d752f30871', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'لماذا تكون الاستجابة المناعية أسرع وأقوى عند التعرّض الثاني لنفس الميكروب؟', '[{"id":"a","text":"لأنّ الميكروب يصبح أضعف من تلقاء نفسه"},{"id":"b","text":"بفضل خلايا الذاكرة المتكوّنة من التعرّض الأوّل"},{"id":"c","text":"لأنّ الجلد يصبح أكثر سمكًا"},{"id":"d","text":"لأنّ الجسم يفقد كلّ مناعته بين المرّتين"}]'::jsonb, 'b', 'خلايا الذاكرة المتكوّنة بعد التعرّض الأوّل تتعرّف على الميكروب بسرعة عند عودته فتكون الاستجابة الثانية أسرع وأقوى، وهذا أساس فعل التلقيح. الميكروب لا يضعف من تلقاء نفسه، وسُمك الجلد لا علاقة له بالأمر، والجسم لا يفقد مناعته بل يحتفظ بذاكرتها.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

