  ('71740120-5eaa-55d5-ab17-52c93342fb2c', 'd99e2d63-4a69-52a9-96c9-39d1b17da995', 'sciences-vie-terre', '👑 تحدّي المناظرة ⭐⭐⭐⭐: المناعة — نوعية وذاكرة وتحليل تجربة', 4, 300, 60, 'challenge', 'admin', 6)
