INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('82788385-f05d-5d5d-9a4c-5bd045bf251c', '71740120-5eaa-55d5-ab17-52c93342fb2c', 'الجسم المضادّ الذي يُنتجه الجسم يتّحد نوعيًّا (كالمفتاح والقفل) بـ...؟', '[{"id":"a","text":"المستضدّ (الأنتيجان) الذي حرّض إنتاجه فقط"},{"id":"b","text":"أيّ ميكروب يدخل الجسم"},{"id":"c","text":"اللمفاويات نفسها"},{"id":"d","text":"المضادّات الحيوية"}]'::jsonb, 'a', 'الأجسام المضادّة نوعية: لكلّ مستضدّ جسمٌ مضادّ يتّحد به تحديدًا (تكامل شكليّ كالمفتاح والقفل)، فلا يعمل ضدّ مستضدّ آخر. ✓ الخطأ الشائع: ظنّها عامّة تهاجم أيّ ميكروب (هذا وصف المناعة غير النوعية كالبلعمة)؛ أو خلط الجسم المضادّ بالمضادّ الحيويّ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('57b57c9b-e408-511f-8727-99083f906edf', '71740120-5eaa-55d5-ab17-52c93342fb2c', 'قال تلميذ: «الأجسام المضادّة هي نفسها المستضدّات (الأنتيجانات) التي تدخل الجسم». ما الخطأ؟', '[{"id":"a","text":"المستضدّ جسمٌ غريب يدخل الجسم، والأجسام المضادّة يُنتجها الجسم ردًّا عليه لتُبطله"},{"id":"b","text":"لا خطأ، هما الشيء نفسه"},{"id":"c","text":"المستضدّ يُنتجه الجسم والأجسام المضادّة غريبة عنه"},{"id":"d","text":"كلاهما تُنتجه البالعات الكبيرة"}]'::jsonb, 'a', 'المستضدّ (الأنتيجان) هو العنصر الغريب (ميكروب أو جزء منه) الذي يدخل الجسم، بينما الأجسام المضادّة بروتينات يُنتجها الجسم (اللمفاويات B) ردًّا على المستضدّ لتتّحد به وتُبطله. فهما نقيضان لا شيء واحد. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين المُحرِّض (المستضدّ) والاستجابة (الجسم المضادّ).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0b56ce6e-8b2b-5052-9b2a-4106caecca20', '71740120-5eaa-55d5-ab17-52c93342fb2c', 'عند أوّل تماسّ مع مستضدّ ارتفعت الأجسام المضادّة ببطء وبمقدار ضعيف. وعند تماسٍّ ثانٍ بالمستضدّ نفسه ارتفعت بسرعة وبمقدار كبير. ما تفسير الاستجابة الثانية؟', '[{"id":"a","text":"الذاكرة المناعية: خلايا ذاكرة تكوّنت في التماسّ الأوّل"},{"id":"b","text":"ضعف الميكروب في المرّة الثانية"},{"id":"c","text":"تناول المريض مضادًّا حيويًّا"},{"id":"d","text":"الصدفة، لا تفسير علميّ"}]'::jsonb, 'a', 'بعد التماسّ الأوّل تبقى خلايا ذاكرة، فعند تماسٍّ ثانٍ بالمستضدّ نفسه تتعرّف عليه بسرعة وتُنتج أجسامًا مضادّة أسرع وأكثر (الاستجابة الثانوية). وعلى هذا المبدأ يقوم التلقيح. (تمرين تحليل منحنى.) ✓ الخطأ الشائع: نسب السرعة إلى ضعف الميكروب لا إلى الذاكرة المناعية.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('28cc938d-d6ff-5eda-9385-0c4e85342e0a', '71740120-5eaa-55d5-ab17-52c93342fb2c', 'أيّ خلايا لمفاوية تُنتج الأجسام المضادّة، وأيّها تهاجم مباشرةً الخلايا المصابة بالفيروس؟', '[{"id":"a","text":"اللمفاويات B تنتج الأجسام المضادّة ; اللمفاويات T تهاجم الخلايا المصابة"},{"id":"b","text":"اللمفاويات T تنتج الأجسام المضادّة ; اللمفاويات B تهاجم الخلايا المصابة"},{"id":"c","text":"كلاهما ينتج الأجسام المضادّة فقط"},{"id":"d","text":"البالعات الكبيرة تقوم بالمهمّتين"}]'::jsonb, 'a', 'اللمفاويات B مسؤولة عن المناعة الخلطية (إنتاج أجسام مضادّة تنتشر في الدم)، واللمفاويات T (القاتلة) مسؤولة عن المناعة الخلوية فتقضي مباشرةً على الخلايا المصابة. ✓ الخطأ الشائع: عكس دورَي B و T؛ أو نسب إنتاج الأجسام المضادّة إلى البالعات.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a9d1a169-203e-50dc-950e-9255a1968258', '71740120-5eaa-55d5-ab17-52c93342fb2c', 'ما الفرق الأساسيّ بين التلقيح (اللقاح) والمصل العلاجيّ؟', '[{"id":"a","text":"اللقاح مستضدّ مُضعَّف يمنح مناعة ذاتية بطيئة ودائمة (وقائيّ) ; المصل أجسام مضادّة جاهزة تمنح مناعة منقولة فورية وقصيرة (علاجيّ)"},{"id":"b","text":"اللقاح أجسام مضادّة جاهزة ; المصل مستضدّ مُضعَّف"},{"id":"c","text":"كلاهما يمنح مناعة دائمة بالطريقة نفسها"},{"id":"d","text":"المصل يمنع العدوى قبل حدوثها واللقاح يعالجها بعد وقوعها"}]'::jsonb, 'a', 'اللقاح يُدخل مستضدًّا مُضعَّفًا فيُحرّض الجسم على تكوين مناعته وذاكرته ببطء لكن لمدّة طويلة (وقاية). أمّا المصل فيُدخل أجسامًا مضادّة جاهزة تعمل فورًا لكن تزول بسرعة (علاج إسعافيّ، مثل مصل الكَلَب). ✓ الخطأ الشائع: عكس مكوّنَي اللقاح والمصل، أو عكس صفتَي «وقائيّ/علاجيّ».', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c35afb13-719f-561c-8e9c-97a0f28414fa', '71740120-5eaa-55d5-ab17-52c93342fb2c', 'تجربة: فأر (أ) حُقن بمستضدّ فأنتج أجسامًا مضادّة، ثمّ أُخذ مصله (الحاوي للأجسام المضادّة) وحُقن في فأر (ب) سليم لم يلتقِ المستضدّ قطّ. ثمّ عُرِّض الفأران للميكروب الممرض. ماذا نتوقّع؟', '[{"id":"a","text":"كلاهما محميّ: (أ) بمناعة ذاتية و(ب) بمناعة منقولة عبر المصل"},{"id":"b","text":"(أ) فقط محميّ، و(ب) يمرض حتمًا"},{"id":"c","text":"(ب) فقط محميّ، و(أ) يمرض"},{"id":"d","text":"كلاهما يمرض لعدم وجود لقاح"}]'::jsonb, 'a', 'الفأر (أ) كوّن أجسامه المضادّة بنفسه (مناعة ذاتية نشطة)، والفأر (ب) تلقّى أجسامًا مضادّة جاهزة عبر المصل (مناعة منقولة سلبية)، فكلاهما محميّ لحظة التعرّض — وهذا مبدأ الاستمصال (العلاج بالمصل). (تمرين تحليل تجربة.) ✓ الخطأ الشائع: ظنّ أنّ الحماية تتطلّب دائمًا إنتاجًا ذاتيًّا، وإهمال إمكان نقل الأجسام المضادّة جاهزة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

