INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('35a00c12-9909-5c2a-8a00-be13c99fc7b7', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'أين توجد الصبغيّات (الكروموزومات) داخل الخليّة؟', '[{"id":"a","text":"في الغشاء الخلوي"},{"id":"b","text":"في النواة"},{"id":"c","text":"في السيتوبلازم خارج النواة"},{"id":"d","text":"في جدار الخليّة"}]'::jsonb, 'b', 'الصبغيّات هي الحوامل المادّية للبرنامج الوراثي وتوجد داخل **نواة** الخليّة. أمّا الغشاء والسيتوبلازم والجدار فلا تحمل الصبغيّات.', 1, 'mcq', NULL, NULL)
