  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e7aec043-f953-5f1a-9ec0-7af39cb26cc9', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'كم صبغيًّا تحتوي خلايا جسم الإنسان؟', '[{"id":"a","text":"23 صبغيًّا"},{"id":"b","text":"24 صبغيًّا"},{"id":"c","text":"46 صبغيًّا"},{"id":"d","text":"92 صبغيًّا"}]'::jsonb, 'c', 'خلايا الجسم تحتوي على **46 صبغيًّا أي 23 زوجًا**. والعدد 23 هو عدد صبغيّات المشيج (نصف العدد) وليس عدد صبغيّات خلايا الجسم.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8b1bcb5a-a641-5b43-8dbc-3d3c02c5b70a', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ما الزوج الصبغيّ الجنسي عند الذكر وعند الأنثى عند الإنسان؟', '[{"id":"a","text":"الذكر XX والأنثى XY"},{"id":"b","text":"الذكر XY والأنثى XX"},{"id":"c","text":"الذكر YY والأنثى XX"},{"id":"d","text":"الذكر والأنثى كلاهما XY"}]'::jsonb, 'b', 'الأنثى تحمل **XX** والذكر يحمل **XY**. لا يوجد فرد بزوج YY لأنّ كلّ فرد يرث صبغيّ X واحدًا على الأقلّ من أمّه.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b4bae8e5-dfff-5896-8a67-3de4e2a159db', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ما الفرق بين الصبغيّ والمورّثة (الجين)؟', '[{"id":"a","text":"المورّثة أكبر من الصبغيّ وتحتوي عليه"},{"id":"b","text":"الصبغيّ والمورّثة شيء واحد بأسماء مختلفة"},{"id":"c","text":"الصبغيّ مقطع صغير داخل المورّثة"},{"id":"d","text":"المورّثة مقطع من الـ ADN محمول على الصبغيّ ومسؤول عن صفة"}]'::jsonb, 'd', 'المورّثة (الجين) هي **مقطع من الـ ADN** محمول على الصبغيّ ومسؤول عن صفة وراثية واحدة. الصبغيّ أكبر بكثير ويحمل آلاف المورّثات، فهما ليسا الشيء نفسه، والصبغيّ لا يقع داخل المورّثة بل العكس.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('27d2d9fb-50f4-5a3b-832a-a9ff231e850c', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ممّ يتكوّن الصبغيّ أساسًا؟', '[{"id":"a","text":"من جزيء الـ ADN الحامل للمورّثات"},{"id":"b","text":"من الماء فقط"},{"id":"c","text":"من الأمشاج"},{"id":"d","text":"من خلايا صغيرة متراصّة"}]'::jsonb, 'a', 'يتكوّن كلّ صبغيّ من جزيء **الـ ADN** الذي يحمل على طوله المورّثات. الأمشاج خلايا تناسلية وليست مكوّنًا للصبغيّ، والصبغيّ ليس مجموعة خلايا بل جزء من خليّة واحدة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('86618ab4-ad97-58d2-8e24-7ac78edb4f33', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'من الذي يحدّد جنس المولود ولماذا؟', '[{"id":"a","text":"الأمّ، لأنّ البويضة تحمل أحيانًا X وأحيانًا Y"},{"id":"b","text":"الأب، لأنّ النطفة تحمل إمّا X وإمّا Y بينما البويضة تحمل X دائمًا"},{"id":"c","text":"الأمّ، لأنّها تحمل XX"},{"id":"d","text":"يتحدّد الجنس صدفةً بعد الولادة"}]'::jsonb, 'b', 'البويضة تحمل **X دائمًا**، أمّا النطفة فتحمل إمّا X (فينتج XX = أنثى) وإمّا Y (فينتج XY = ذكر). إذن **الأب** هو الذي يحدّد الجنس وليس الأمّ، ويتحدّد لحظة الإلقاح لا بعد الولادة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1d6632dd-7eec-56fd-acc3-0209ae0a41bb', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'إذا كان الحليل A سائدًا و a متنحّيًا، أيّ تركيب تظهر فيه الصفة المتنحّية؟', '[{"id":"a","text":"A//A"},{"id":"b","text":"A//a"},{"id":"c","text":"a//a"},{"id":"d","text":"كلّ التركيبات السابقة"}]'::jsonb, 'c', 'لا تظهر الصفة المتنحّية إلّا حين يجتمع حليلان متنحّيان **a//a**. أمّا A//A و A//a فتظهر فيهما الصفة السائدة لأنّ A يطغى على a؛ والمهجّن A//a يبدو سائدًا لكنّه يحمل a وينقله.', 7, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f80763c6-ffd4-5598-b20c-406692d2ce77', 'd832856d-91f0-58a4-80d5-4f60a4473575', 'ما سبب متلازمة داون (التثلّث الصبغي 21)؟', '[{"id":"a","text":"نقص صبغيّ فيصبح العدد 45"},{"id":"b","text":"وجود ثلاث نسخ من الصبغيّ رقم 21 فيصبح العدد 47"},{"id":"c","text":"غياب الصبغيّات الجنسية"},{"id":"d","text":"صفة مكتسبة من المحيط"}]'::jsonb, 'b', 'في متلازمة داون توجد **ثلاث نسخ من الصبغيّ 21** بدل نسختين، فيصبح المجموع **47 صبغيًّا** بدل 46. فهي ناتجة عن خلل في **عدد الصبغيّات**، وليست نقصًا ولا صفة مكتسبة من المحيط.', 8, 'mcq', NULL, NULL)
