INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('137d9695-303a-550a-92f8-4100be9b598d', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'ماذا نسمّي الصورة المرتّبة لصبغيّات خليّة حسب حجمها وشكلها في أزواج؟', '[{"id":"a","text":"المورّثة"},{"id":"b","text":"النمط النووي (caryotype)"},{"id":"c","text":"المشيج"},{"id":"d","text":"البيضة المخصّبة"}]'::jsonb, 'b', '**النمط النووي (caryotype)** هو ترتيب صبغيّات الخليّة في أزواج حسب الحجم والشكل، ويُستعمل لكشف أيّ خلل في عدد الصبغيّات. أمّا المورّثة فجزء من الـ ADN، والمشيج والبيضة المخصّبة خلايا لا صور.', 3, 'mcq', NULL, NULL)
