  ('85f28f4b-b0ae-5abc-bd27-14fc560e394f', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'في كلّ زوج من الصبغيّات المتماثلة عند الإنسان:', '[{"id":"a","text":"الصبغيّان كلاهما من الأمّ"},{"id":"b","text":"الصبغيّان كلاهما من الأب"},{"id":"c","text":"صبغيّ من الأب وصبغيّ من الأمّ"},{"id":"d","text":"صبغيّ واحد فقط دون أصل محدّد"}]'::jsonb, 'c', 'في كلّ زوج صبغيّ متماثل **صبغيّ موروث من الأب وآخر من الأمّ**، ولذلك يرث الابن صفاته من الأبوين معًا. فلا يأتي الزوجان من والد واحد.', 4, 'mcq', NULL, NULL)
