  ('360e1e1c-e34d-522e-b88d-60a6544c87dd', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'أيّ ترتيب صحيح من الأكبر إلى الأصغر؟', '[{"id":"a","text":"المورّثة ← الصبغيّ ← النواة"},{"id":"b","text":"النواة ← الصبغيّ ← المورّثة"},{"id":"c","text":"الصبغيّ ← النواة ← المورّثة"},{"id":"d","text":"الـ ADN ← النواة ← الصبغيّ"}]'::jsonb, 'b', 'ترتيب الاحتواء الصحيح: **النواة ← الصبغيّ ← الـ ADN ← المورّثة**. فالنواة تحوي الصبغيّات، وكلّ صبغيّ يتكوّن من ADN يحمل المورّثات. إذن النواة أكبر، والمورّثة أصغر.', 5, 'mcq', NULL, NULL)
