INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2d2d3287-9e19-5a41-bd76-9d109ae06236', '87a68336-6ce3-5711-a664-f4b1b9a9bd05', 'خليّة جسمية فيها 47 صبغيًّا بسبب ثلاث نسخ من الصبغيّ 21؛ هذا يدلّ على:', '[{"id":"a","text":"نمط نووي عادي لإنسان سليم"},{"id":"b","text":"متلازمة داون (التثلّث الصبغي 21)"},{"id":"c","text":"أنّها خليّة مشيج"},{"id":"d","text":"صفة مكتسبة من المحيط"}]'::jsonb, 'b', 'وجود **47 صبغيًّا** بسبب ثلاث نسخ من الصبغيّ 21 هو سمة **متلازمة داون**. النمط العادي 46 صبغيًّا، والمشيج فيه 23 فقط، والخلل في عدد الصبغيّات سبب وراثي لا صفة مكتسبة.', 6, 'mcq', NULL, NULL)
