INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('71f7f295-09e6-5967-b8bc-a4fbe6e6d491', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'ماذا نسمّي الجزيء الطويل الذي يتكوّن منه الصبغيّ ويحمل المورّثات؟', '[{"id":"a","text":"المشيج"},{"id":"b","text":"الـ ADN"},{"id":"c","text":"النواة"},{"id":"d","text":"الحليل"}]'::jsonb, 'b', 'يتكوّن الصبغيّ من جزيء **الـ ADN** الذي يحمل على طوله المورّثات. النواة بنية تحوي الصبغيّات لا جزيء، والمشيج خليّة تناسلية، والحليل شكل من أشكال المورّثة.', 1, 'mcq', NULL, NULL)
