INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cdbbd4f3-efdc-5f8d-b062-5920e2748b11', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'ما المورّثة (الجين)؟', '[{"id":"a","text":"نواة الخليّة كاملة"},{"id":"b","text":"مقطع من الـ ADN مسؤول عن صفة وراثية"},{"id":"c","text":"زوج كامل من الصبغيّات"},{"id":"d","text":"خليّة تناسلية"}]'::jsonb, 'b', 'المورّثة **مقطع من الـ ADN** يحدّد صفة وراثية واحدة. فهي ليست النواة ولا زوجًا كاملًا من الصبغيّات (الصبغيّ يحمل آلاف المورّثات)، وليست خليّة.', 2, 'mcq', NULL, NULL)
