INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('86c1b473-6c80-5ae9-b67c-587df9e21a29', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'كم صبغيًّا يحمل المشيج (النطفة أو البويضة) عند الإنسان؟', '[{"id":"a","text":"46 صبغيًّا"},{"id":"b","text":"23 صبغيًّا"},{"id":"c","text":"47 صبغيًّا"},{"id":"d","text":"92 صبغيًّا"}]'::jsonb, 'b', 'يحمل المشيج **23 صبغيًّا** أي نصف عدد صبغيّات خلايا الجسم، حتّى إذا اتّحد مشيجان عند الإلقاح تكوّنت بيضة مخصّبة فيها 46 صبغيًّا من جديد. العدد 46 خاصّ بخلايا الجسم.', 3, 'mcq', NULL, NULL)
