INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4ad0af0b-064e-5c4f-a536-c12c4b51b674', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'أيّ نوع من الصبغيّات تحمله البويضة دائمًا؟', '[{"id":"a","text":"X دائمًا"},{"id":"b","text":"Y دائمًا"},{"id":"c","text":"X أو Y بالتساوي"},{"id":"d","text":"لا تحمل صبغيًّا جنسيًّا"}]'::jsonb, 'a', 'بما أنّ الأمّ XX، فكلّ بويضة تحمل صبغيّ **X**. النطفة هي التي تحمل X أو Y بالتساوي، أمّا البويضة فلا يمكن أن تحمل Y لأنّ الأمّ لا تملكه أصلًا.', 4, 'mcq', NULL, NULL)
