  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a780469f-de41-55c6-921c-4ace85279c6d', '4fa23279-6976-5b3e-9a66-2b31fc791adc', 'في كلّ حمل، ما احتمال أن يكون المولود ذكرًا؟', '[{"id":"a","text":"25 ٪"},{"id":"b","text":"50 ٪"},{"id":"c","text":"75 ٪"},{"id":"d","text":"100 ٪"}]'::jsonb, 'b', 'تحمل النطف نوعين بالتساوي (X و Y)، فاحتمال XY (ذكر) = احتمال XX (أنثى) = **50 ٪** في كلّ حمل. والاحتمال مستقلّ عن جنس المواليد السابقين.', 6, 'mcq', NULL, NULL)
