INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8f4880f3-8cdb-5b90-a220-963449cf81cc', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'إذا كان A (لون أسود) سائدًا و a (لون بنّي) متنحّيًا، أيّ تركيب يُظهر اللون البنّي؟', '[{"id":"a","text":"A//A"},{"id":"b","text":"A//a"},{"id":"c","text":"a//a"},{"id":"d","text":"A//A و A//a معًا"}]'::jsonb, 'c', 'اللون البنّي صفة متنحّية لا تظهر إلّا بـ **a//a**. التركيبان A//A و A//a يُظهران اللون الأسود السائد لأنّ A يطغى على a.', 1, 'mcq', NULL, NULL)
