INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d3c255f0-011f-5efe-9041-ee2a43d71b28', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'فرد مظهره يطابق الصفة السائدة لكنّه ينقل الصفة المتنحّية لأبنائه؛ ما تركيبه الوراثي؟', '[{"id":"a","text":"A//A نقيّ سائد"},{"id":"b","text":"A//a مهجّن"},{"id":"c","text":"a//a نقيّ متنحٍّ"},{"id":"d","text":"لا يمكن أن يحدث ذلك"}]'::jsonb, 'b', 'الفرد **المهجّن A//a** يُظهر الصفة السائدة (بفضل A) لكنّه يحمل الحليل المتنحّي a وينقله إلى أبنائه. النقيّ A//A لا يحمل a إطلاقًا، والنقيّ a//a تظهر عليه الصفة المتنحّية لا السائدة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
