INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('75e75676-0c66-5d10-af00-98f6ad0aeb25', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'لماذا يُعدّ الـ ADN «حاملًا للبرنامج الوراثي»؟', '[{"id":"a","text":"لأنّه يحمل المورّثات التي تحدّد الصفات وتُنسخ عند تكوين الخلايا"},{"id":"b","text":"لأنّه يوجد خارج النواة"},{"id":"c","text":"لأنّه صفة مكتسبة"},{"id":"d","text":"لأنّه يتغيّر تبعًا للمحيط فقط"}]'::jsonb, 'a', 'يحمل الـ ADN على طوله **المورّثات** التي تحدّد الصفات الوراثية، وتنتقل نسخة منه عند تكوين الأمشاج فينقل البرنامج إلى الجيل التالي. وهو يوجد داخل النواة لا خارجها، وليس صفة مكتسبة من المحيط.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
