  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bacef7f6-427b-5d36-bb58-893321bddf0e', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'تزاوج بين فردين نقيّين: A//A (سائد) × a//a (متنحٍّ). ما تركيب كلّ الأبناء في الجيل الأوّل ومظهرهم؟', '[{"id":"a","text":"كلّهم a//a وتظهر عليهم الصفة المتنحّية"},{"id":"b","text":"كلّهم A//a وتظهر عليهم الصفة السائدة"},{"id":"c","text":"نصفهم A//A ونصفهم a//a"},{"id":"d","text":"كلّهم A//A وتظهر عليهم الصفة السائدة"}]'::jsonb, 'b', 'كلّ والد نقيّ ينتج مشيجًا من نوع واحد: الأوّل A والثاني a. فيتّحدان فيكون كلّ الأبناء **A//a مهجّنين**، وتظهر عليهم **الصفة السائدة** لأنّ A يطغى على a.', 4, 'mcq', NULL, NULL)
