  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a773a17b-68c4-52e0-8679-ae7eb08b021c', 'a5d10140-e10e-53fe-844c-e63b967a6636', 'أبوان سليمان أنجبا طفلًا مصابًا بمرض وراثي متنحٍّ؛ ماذا نستنتج عن الأبوين؟', '[{"id":"a","text":"كلاهما مصاب بالمرض"},{"id":"b","text":"كلّ منهما حامل للحليل المتنحّي (مهجّن) دون أن يكون مريضًا"},{"id":"c","text":"أحدهما فقط يحمل المرض"},{"id":"d","text":"المرض مكتسب من المحيط"}]'::jsonb, 'b', 'بما أنّ المرض **متنحٍّ**، فإصابة الطفل تعني أنّه ورث الحليل المعطوب من **كلا الأبوين**. ولأنّ الأبوين سليمان فكلّ منهما **مهجّن حامل** (يحمل حليلًا متنحّيًا واحدًا) دون أن يمرض. لو حمل أحدهما فقط لما اجتمع الحليلان المتنحّيان عند الطفل.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
