INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('90aeeea5-4c06-58ae-a3df-79e08c57a989', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'نملك حليلين: B (بنّي) سائد و b (أزرق) متنحٍّ للون العينين. أب أزرق العينين (b//b) وأمّ مهجّنة (B//b). ما النسبة المنتظرة للأبناء زرق العينين؟', '[{"id":"a","text":"0 ٪"},{"id":"b","text":"25 ٪"},{"id":"c","text":"50 ٪"},{"id":"d","text":"100 ٪"}]'::jsonb, 'c', 'الأب b//b ينتج أمشاج b فقط. الأمّ B//b تنتج نصف أمشاجها B ونصفها b. التركيبات الممكنة: B//b (بنّي) بنسبة 50 ٪، و b//b (أزرق) بنسبة 50 ٪. إذن **50 ٪** من الأبناء زرق العينين (b//b).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8b127b66-0b2d-5231-9c9c-e7c75dd13eda', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'أبوان بنّيا العينين أنجبا طفلًا أزرق العينين (الأزرق متنحٍّ b//b). ما تركيب كلٍّ من الأبوين؟', '[{"id":"a","text":"كلاهما B//B"},{"id":"b","text":"كلاهما B//b (مهجّنان)"},{"id":"c","text":"أحدهما B//B والآخر b//b"},{"id":"d","text":"كلاهما b//b"}]'::jsonb, 'b', 'الطفل أزرق العينين b//b ورث b من كلّ والد. وبما أنّ الأبوين بنّيا العينين (يحملان B الظاهر) فكلّ منهما **B//b مهجّن**: يحمل B فيبدو بنّيًّا، ويحمل b فينقله. لو كان أحدهما B//B لما أمكن أن يرث الطفل b منه.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6cc80dc1-af6b-571f-8fac-8bea7f168b76', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'في مرض وراثي متنحٍّ، أب مصاب (a//a) وأمّ سليمة حاملة (A//a). ما احتمال أن يكون الطفل مصابًا؟', '[{"id":"a","text":"0 ٪"},{"id":"b","text":"25 ٪"},{"id":"c","text":"50 ٪"},{"id":"d","text":"75 ٪"}]'::jsonb, 'c', 'الأب a//a ينتج أمشاج a فقط. الأمّ A//a تنتج نصفها A ونصفها a. التركيبات: A//a (سليم حامل) 50 ٪، و a//a (مصاب) 50 ٪. إذن احتمال أن يكون الطفل **مصابًا = 50 ٪**.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9f62f0da-43e1-59f6-8b58-cc16fd625e2a', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'خليّة جسمية لأنثى مصابة بمتلازمة داون؛ كم صبغيًّا جسميًّا (autosome) تحمل، وما زوجها الجنسي؟', '[{"id":"a","text":"44 صبغيًّا جسميًّا + XX، المجموع 46"},{"id":"b","text":"45 صبغيًّا جسميًّا + XX، المجموع 47"},{"id":"c","text":"44 صبغيًّا جسميًّا + XY، المجموع 46"},{"id":"d","text":"46 صبغيًّا جسميًّا + XX، المجموع 48"}]'::jsonb, 'b', 'التثلّث الصبغي 21 يضيف نسخة ثالثة إلى الصبغيّات **الجسمية** فيصبح عددها 45 بدل 44، أمّا الزوج الجنسي فيبقى **XX** (أنثى). المجموع = 45 + 2 = **47 صبغيًّا**. الخلل في الصبغيّات الجسمية لا الجنسية.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d20073c4-39c9-54e5-85c5-0d0ca6394aff', '1733d648-9849-51c2-8a74-f26b0ad28cea', 'تزاوج بين فردين مهجّنين A//a × A//a (A سائد، a متنحٍّ). ما النسبة المنتظرة للأبناء الذين تظهر عليهم الصفة المتنحّية؟', '[{"id":"a","text":"0 ٪"},{"id":"b","text":"25 ٪"},{"id":"c","text":"50 ٪"},{"id":"d","text":"75 ٪"}]'::jsonb, 'b', 'كلّ والد مهجّن ينتج نصف أمشاجه A ونصفها a. التركيبات الممكنة: A//A، A//a، a//A، a//a بنسب متساوية (1:2:1). تظهر الصفة المتنحّية فقط في **a//a** أي ربع الحالات = **25 ٪**، بينما 75 ٪ تظهر عليهم الصفة السائدة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

