  ('a990f679-0980-511b-b5ed-402261f682ee', '9fdf29ea-2d99-548e-a7b2-1bf306ef6e7e', 'sciences-vie-terre', '🛡️ تدرّب على الفصل: مراجعة الوراثة وانتقال الصفات', 3, 120, 30, 'boss', 'admin', 5)
