INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dd8bdce6-a544-5205-aac1-ae6960b51d97', 'a990f679-0980-511b-b5ed-402261f682ee', 'أين توجد الصبغيّات (الكروموزومات) داخل الخليّة؟', '[{"id":"a","text":"في النواة"},{"id":"b","text":"في الغشاء الخلوي"},{"id":"c","text":"في السيتوبلازم خارج النواة"},{"id":"d","text":"لا توجد إلّا في خلايا الدم"}]'::jsonb, 'a', 'تحمل النواة الصبغيّات المكوّنة من الـADN الذي يحمل البرنامج الوراثي. الغشاء الخلوي يحيط بالخليّة ولا يخزّن الصبغيّات، والسيتوبلازم محيط النواة لا مقرّ الصبغيّات، والصبغيّات موجودة في كلّ الخلايا الجسمية لا في خلايا الدم وحدها.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9d55b2c5-05d2-5179-a78e-b1375e9cfc25', 'a990f679-0980-511b-b5ed-402261f682ee', 'كم عدد الصبغيّات في الخليّة الجسمية الطبيعية عند الإنسان؟', '[{"id":"a","text":"23 صبغيًّا"},{"id":"b","text":"46 صبغيًّا (23 زوجًا)"},{"id":"c","text":"92 صبغيًّا"},{"id":"d","text":"عدد متغيّر من خليّة لأخرى"}]'::jsonb, 'b', 'تحتوي الخليّة الجسمية على 46 صبغيًّا مرتّبة في 23 زوجًا. أمّا 23 صبغيًّا فهو عدد المشيج (النطفة أو البويضة) أي نصف العدد، و92 ضعف العدد الطبيعي وهو غير صحيح، والعدد ثابت في الخلايا الجسمية لا متغيّر.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('baefc9a9-a115-5310-ae35-8b71a02b0ab9', 'a990f679-0980-511b-b5ed-402261f682ee', 'ما الذي يحدّد جنس المولود (ذكر أم أنثى)؟', '[{"id":"a","text":"نوع الصبغي الجنسي الذي تحمله النطفة (X أو Y)"},{"id":"b","text":"البويضة التي تحمل دائمًا الصبغي Y"},{"id":"c","text":"تغذية الأمّ أثناء الحمل"},{"id":"d","text":"عدد البويضات في المبيض"}]'::jsonb, 'a', 'البويضة تحمل دائمًا الصبغي X، بينما النطفة قد تحمل X (فيكون المولود أنثى XX) أو Y (فيكون ذكرًا XY)، فالنطفة هي التي تحدّد الجنس. البويضة لا تحمل Y، وتغذية الأمّ وعدد البويضات لا علاقة لهما بتحديد الجنس.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('38fd9564-327c-5f1b-8405-288fda1cb27f', 'a990f679-0980-511b-b5ed-402261f682ee', 'إذا كان أليل العيون البنّية (B) سائدًا وأليل العيون الزرقاء (b) متنحّيًا، فأيّ تركيب وراثي يُعطي عيونًا زرقاء؟', '[{"id":"a","text":"B//B"},{"id":"b","text":"B//b"},{"id":"c","text":"b//b"},{"id":"d","text":"أيّ تركيب يحتوي B"}]'::jsonb, 'c', 'لا تظهر الصفة المتنحّية (العيون الزرقاء) إلّا عندما يكون التركيب نقيًّا متنحّيًا b//b، لأنّ وجود أليل سائد واحد B يُظهر الصفة السائدة. لذلك B//B وB//b يعطيان عيونًا بنّية، وأيّ تركيب فيه B لا يُظهر اللون الأزرق.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c9750b6b-d923-54c1-9c68-dcf226412d75', 'a990f679-0980-511b-b5ed-402261f682ee', 'أبوان عيونهما بنّية أنجبا طفلًا أزرق العينين (صفة متنحّية). ماذا نستنتج عن تركيب الأبوين؟', '[{"id":"a","text":"أنّهما نقيّان B//B"},{"id":"b","text":"أنّ كلًّا منهما هجين B//b يحمل الأليل المتنحّي"},{"id":"c","text":"أنّ أحدهما فقط يحمل الأليل المتنحّي"},{"id":"d","text":"أنّ الطفل لا ينتمي إليهما"}]'::jsonb, 'b', 'بما أنّ الطفل أزرق العينين فتركيبه b//b، فقد ورث أليلًا متنحّيًا b من كلّ من أبويه؛ ولأنّ الأبوين بنّيا العينين فلا بدّ أنّ كلًّا منهما هجين B//b يحمل الأليل المتنحّي خفيًّا. لو كانا نقيّين B//B لما ظهر الطفل أزرق، ولا يكفي أن يحمله أحدهما فقط، والاستنتاج لا يطعن في نسب الطفل.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('447a71f3-39ea-50cb-90e8-87208e9b2496', 'a990f679-0980-511b-b5ed-402261f682ee', 'لماذا يُعدّ الـADN «حاملًا للبرنامج الوراثي»؟', '[{"id":"a","text":"لأنّه يخزّن المعلومات التي تحدّد الصفات وتنتقل عبر المورّثات إلى الأبناء"},{"id":"b","text":"لأنّه يمدّ الخليّة بالطاقة"},{"id":"c","text":"لأنّه يكتسب الصفات من البيئة بعد الولادة"},{"id":"d","text":"لأنّه موجود في خلايا الدم فقط"}]'::jsonb, 'a', 'الـADN يحمل في تتابعه المورّثات (الجينات) التي تشفّر صفات الكائن وتنتقل من الأبوين إلى الأبناء عبر المشيجين، فهو حامل البرنامج الوراثي. تزويد الخليّة بالطاقة دور آخر لا يخصّ الـADN، والصفات الوراثية تُورَّث لا تُكتسب من البيئة وحدها، والـADN موجود في نوى كلّ الخلايا لا في خلايا الدم فقط.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

