  ('01d40a59-b76b-52b5-bf01-ad2a22b6ed6a', '9fdf29ea-2d99-548e-a7b2-1bf306ef6e7e', 'sciences-vie-terre', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الوراثة — تراكيب واحتمالات واستدلال عكسيّ', 4, 300, 60, 'challenge', 'admin', 6)
