INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('72260d0f-b6a8-591f-a4ba-7d597e39f5a7', '01d40a59-b76b-52b5-bf01-ad2a22b6ed6a', 'فرد تركيبه الوراثيّ A//a، حيث A حليل سائد (بنّي) و a حليل متنحٍّ (أزرق) للون العينين. ما نمطه الظاهريّ (لون عينيه)؟', '[{"id":"a","text":"بنّي، لأنّ A سائد يُخفي a"},{"id":"b","text":"أزرق"},{"id":"c","text":"لون وسط بين البنّي والأزرق"},{"id":"d","text":"يتعذّر تحديده"}]'::jsonb, 'a', 'في هيمنة تامّة، يُعبَّر عن الحليل السائد فقط عند وجوده: التركيب A//a يُظهر الصفة السائدة (بنّي)، ويبقى الحليل a محمولًا دون ظهور. ✓ الخطأ الشائع: توقّع لون وسط (لا يوجد امتزاج في الهيمنة التامّة)؛ أو إظهار الصفة المتنحّية مع وجود الحليل السائد.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a16a9028-8c43-5484-a060-7c5606bf85d1', '01d40a59-b76b-52b5-bf01-ad2a22b6ed6a', 'قال تلميذ: «بما أنّ الأبوين سليمان، فمن المستحيل أن يُنجبا طفلًا مصابًا بمرض وراثيّ». ما الخطأ؟', '[{"id":"a","text":"في المرض المتنحّي قد يكون الأبوان حاملَين سليمَين (A//a) فيُنجبان طفلًا مصابًا (a//a) باحتمال 1/4"},{"id":"b","text":"لا خطأ، أبوان سليمان لا يُنجبان مصابًا أبدًا"},{"id":"c","text":"المرض الوراثيّ لا ينتقل من الأبوين إطلاقًا"},{"id":"d","text":"يظهر المرض فقط إن كان الأبوان مصابَين معًا"}]'::jsonb, 'a', 'في التوريث المتنحّي، الأبوان الحاملان السليمان (A//a) يحمل كلٌّ منهما الحليل المتنحّي دون أن يظهر عليه المرض، وقد يلتقي الحليلان a عند الطفل (a//a) باحتمال 1/4 فيُصاب. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين النمط الظاهريّ (سليم) والتركيب الوراثيّ (حامل).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
