INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7cf43550-601e-5604-8479-fa068324b13b', '01d40a59-b76b-52b5-bf01-ad2a22b6ed6a', 'هُجِّن نبات بذوره ملساء (الحليل S سائد) مجهول التركيب مع نبات بذوره مجعّدة (s//s). كانت الذرّية نصفها ملساء ونصفها مجعّدة. ما تركيب النبات المجهول؟', '[{"id":"a","text":"S//s (مهجّن)"},{"id":"b","text":"S//S (نقيّ سائد)"},{"id":"c","text":"s//s (نقيّ متنحٍّ)"},{"id":"d","text":"لا يمكن معرفته من هذا التزاوج"}]'::jsonb, 'a', 'التزاوج الاختباريّ مع متنحٍّ نقيّ (s//s) يكشف التركيب: ظهور نصف مجعّد (s//s) في الذرّية يعني أنّ المجهول أعطى حليل s، فهو مهجّن S//s (لو كان S//S لكانت الذرّية كلّها ملساء). ✓ الخطأ الشائع: استنتاج S//S رغم ظهور أفراد مجعّدة؛ نسبة 1/2–1/2 دليلٌ قاطع على أنّه مهجّن.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b931fedc-1090-5c6d-802b-ea23e28e1f98', '01d40a59-b76b-52b5-bf01-ad2a22b6ed6a', 'ما احتمال أن يكون المولود القادم لزوجين ذكرًا، ومن الذي يحدّد جنس المولود؟', '[{"id":"a","text":"1/2 ; يحدّده الأب (نطفة تحمل X أو نطفة تحمل Y)"},{"id":"b","text":"1/2 ; تحدّده الأمّ (البويضة تحمل X أو Y)"},{"id":"c","text":"يتغيّر حسب عدد الأبناء الذكور السابقين"},{"id":"d","text":"3/4 للذكر"}]'::jsonb, 'a', 'البويضة تحمل دائمًا X، بينما نطفة الأب تحمل إمّا X (فتُعطي أنثى XX) وإمّا Y (فتُعطي ذكرًا XY) باحتمال متساوٍ، فاحتمال الذكر 1/2 ويحدّده الأب. ✓ الخطأ الشائع: نسب تحديد الجنس إلى الأمّ؛ أو ظنّ أنّ الأبناء السابقين يغيّرون الاحتمال (كلّ حمل حدث مستقلّ).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d4f3c804-d325-5125-879b-bfec8c571934', '01d40a59-b76b-52b5-bf01-ad2a22b6ed6a', 'زوجان كلاهما حاملٌ سليم لمرض وراثيّ متنحٍّ (تركيب كلٍّ منهما A//a). ما احتمال أن يكون طفلاهما القادمان (اثنان) مصابَين معًا (a//a)؟', '[{"id":"a","text":"1/16"},{"id":"b","text":"1/4"},{"id":"c","text":"1/2"},{"id":"d","text":"1/8"}]'::jsonb, 'a', 'من التزاوج A//a × A//a، احتمال أن يكون طفلٌ واحد مصابًا (a//a) هو 1/4. وبما أنّ ولادتَي الطفلَين حدثان مستقلّان، نضرب الاحتمالَين: 1/4 × 1/4 = 1/16. ✓ الخطأ الشائع: إعطاء 1/4 (احتمال طفل واحد فقط)؛ أو جمع الاحتمالَين بدل ضربهما.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b6c0c8e8-6a84-5f25-b26e-ea8da6d35da8', '01d40a59-b76b-52b5-bf01-ad2a22b6ed6a', 'في مرضٍ وراثيّ، لُوحظ أنّ كلّ طفل مصاب له أحد أبوين مصاب على الأقلّ، ولا يظهر المرض إطلاقًا في طفل أبواه سليمان. ما نمط توريث هذا المرض غالبًا؟', '[{"id":"a","text":"سائد (يظهر بوجود حليل واحد، فيلزم أن يكون أحد الأبوين مصابًا)"},{"id":"b","text":"متنحٍّ (قد يظهر من أبوين سليمَين حاملَين)"},{"id":"c","text":"لا علاقة له بالوراثة"},{"id":"d","text":"محمول على الصبغيّ Y حصرًا"}]'::jsonb, 'a', 'ظهور المرض في كلّ جيل مع لزوم إصابة أحد الأبوين لكلّ طفل مصاب يدلّ على توريث سائد: يكفي حليل واحد لظهور المرض، فلا يظهر من أبوين سليمَين. ✓ الخطأ الشائع: عدّه متنحّيًا — في المتنحّي يمكن أن يظهر المرض فجأةً من أبوين سليمَين حاملَين، وهو ما نُفي هنا.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

