INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2a20a238-a2b1-57fc-b649-829296191a8e', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما هو الزلزال؟', '[{"id":"a","text":"هزّة أرضية مفاجئة ناتجة عن تحرّر مفاجئ لطاقة في أعماق الأرض"},{"id":"b","text":"ارتفاع تدريجي بطيء لسطح الأرض على مدى سنوات"},{"id":"c","text":"تدفّق الحمم البركانية فوق سطح الأرض"},{"id":"d","text":"تيّار هوائي قويّ يحرّك الغبار قرب السطح"}]'::jsonb, 'a', 'الزلزال هزّة أرضية مفاجئة وعابرة سببها تحرّر مفاجئ لطاقة مخزّنة في صخور الأعماق، تنتقل على شكل موجات زلزالية. وهو غير ظواهر بطيئة كرفع السطح، وغير البراكين التي تخصّ تدفّق الحمم.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6f6bf23f-9526-5ada-ae7e-0dae2870a1fc', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما الفرق بين البؤرة والمركز السطحي؟', '[{"id":"a","text":"البؤرة على السطح، والمركز السطحي في العمق فوقها"},{"id":"b","text":"البؤرة نقطة المنشأ في العمق، والمركز السطحي النقطة على السطح فوقها مباشرة"},{"id":"c","text":"هما اسمان لنفس النقطة على سطح الأرض"},{"id":"d","text":"البؤرة أبعد منطقة عن الزلزال، والمركز السطحي أقربها"}]'::jsonb, 'b', 'البؤرة هي نقطة منشأ الزلزال داخل الأرض (في العمق) وتنطلق منها الموجات، أمّا المركز السطحي فهو النقطة الواقعة على سطح الأرض عموديًّا فوق البؤرة مباشرة، وهي الأكثر تضرّرًا. والخلط بينهما خطأ شائع.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('da45a278-22b0-5c97-8252-a4583ddafef4', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما اسم الجهاز الذي يكشف اهتزازات الأرض ويسجّلها؟', '[{"id":"a","text":"المرصاد الزلزالي (sismographe)"},{"id":"b","text":"مقياس الحرارة (thermomètre)"},{"id":"c","text":"مقياس الضغط الجوّي (baromètre)"},{"id":"d","text":"البوصلة"}]'::jsonb, 'a', 'المرصاد الزلزالي (sismographe) جهاز يكشف اهتزازات الأرض ويسجّلها في رسم يُسمّى المخطّط الزلزالي (sismogramme). أمّا مقياس الحرارة والضغط والبوصلة فتقيس ظواهر أخرى لا علاقة لها بالزلازل.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('65f1a1e6-58d6-59a4-8184-84ad6c26c3c1', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'أيّ من التدابير التالية يُعدّ وقاية صحيحة من أضرار الزلازل؟', '[{"id":"a","text":"بناء مقاوم للزلازل واحترام معايير البناء"},{"id":"b","text":"بناء المباني العالية فقط عند الفوالق النشطة"},{"id":"c","text":"إيقاف المرصاد الزلزالي لتوفير الطاقة"},{"id":"d","text":"الوقوف قرب النوافذ الزجاجية أثناء الهزّة"}]'::jsonb, 'a', 'لا يمكن منع الزلازل لكن يمكن التقليل من أضرارها بالبناء المقاوم للزلازل واحترام معايير البناء، وخرائط المخاطر، والتربية على السلامة، والإنذار المبكّر. أمّا البناء عند الفوالق النشطة أو الوقوف قرب النوافذ فيزيدان الخطر، وإيقاف المرصاد يحرمنا من المراقبة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('98a8b766-e594-564b-8a39-f32f8d51c296', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'أيّ نوع من الموجات الزلزالية يصل أوّلًا إلى المرصاد الزلزالي؟', '[{"id":"a","text":"الموجات السطحية"},{"id":"b","text":"الموجات الثانوية (S)"},{"id":"c","text":"الموجات الأوّلية (P)"},{"id":"d","text":"تصل كلّ الموجات في الوقت نفسه"}]'::jsonb, 'c', 'الموجات الأوّلية (P) هي الأسرع فتصل أوّلًا إلى المرصاد، تليها الموجات الثانوية (S) الأبطأ، ثمّ الموجات السطحية. ومن فرق زمن وصول P و S يُحدَّد موقع المركز السطحي.', 5, 'mcq', NULL, NULL)
