  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4d3f0d1b-37f9-5375-8817-cefb99e387ca', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'أيّ سلّم يُستعمل لقياس مقدار الزلزال (الطاقة المحرَّرة)؟', '[{"id":"a","text":"سلّم ميركالّي"},{"id":"b","text":"سلّم سلسيوس"},{"id":"c","text":"سلّم ريشتر"},{"id":"d","text":"سلّم بوفور"}]'::jsonb, 'c', 'يُقاس مقدار الزلزال (الطاقة المحرَّرة عند البؤرة) بسلّم ريشتر انطلاقًا من تسجيلات المرصاد. أمّا سلّم ميركالّي فيقيس الشدّة (آثار الزلزال على السطح)، وسلسيوس للحرارة، وبوفور لقوّة الريح.', 6, 'mcq', NULL, NULL)
