  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7b20b4cf-270a-5ce0-a311-d9517b887488', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما الفرق بين شدّة الزلزال ومقداره؟', '[{"id":"a","text":"الشدّة قيمة واحدة للزلزال، والمقدار يختلف من مكان لآخر"},{"id":"b","text":"الشدّة تقيس آثار الزلزال على السطح وتختلف من مكان لآخر، والمقدار يقيس الطاقة المحرَّرة وقيمته واحدة"},{"id":"c","text":"هما يقيسان الشيء نفسه بسلّمين مختلفين"},{"id":"d","text":"الشدّة تقاس بسلّم ريشتر والمقدار بسلّم ميركالّي"}]'::jsonb, 'b', 'الشدّة تقيس آثار الزلزال المُلاحَظة على السطح (أضرار، إحساس الناس) وتختلف من موضع لآخر (سلّم ميركالّي). أمّا المقدار فيقيس الطاقة المحرَّرة عند البؤرة وله قيمة واحدة مهما تعدّدت أماكن القياس (سلّم ريشتر). والخلط بينهما خطأ شائع.', 7, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
