  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d859e196-71a8-50e6-ba77-f28d2884ea23', '5d2c1e1f-e40c-5946-9ef5-aa4132ce8cfc', 'ما السبب الرئيسي لمعظم الزلازل؟', '[{"id":"a","text":"هطول الأمطار الغزيرة على سطح الأرض"},{"id":"b","text":"دوران الأرض حول الشمس"},{"id":"c","text":"حركة الصفائح التكتونية وانكسار الصخور على الفوالق عند حدودها"},{"id":"d","text":"ارتفاع درجة حرارة الجوّ في فصل الصيف"}]'::jsonb, 'c', 'تنشأ معظم الزلازل عن حركة الصفائح التكتونية: تتراكم الضغوط عند حدود الصفائح حتى تتجاوز مقاومة الصخور فتنكسر فجأة على مستوى فالق، فتتحرّر الطاقة دفعةً واحدة. لذلك تتركّز الزلازل عند حدود الصفائح. والأمطار والحرارة ودوران الأرض ليست أسبابًا للزلازل.', 8, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
