INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('725ed275-3afa-5fbf-bf81-caf4b6fdbbcc', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'الزلزال ناتج أساسًا عن:', '[{"id":"a","text":"تحرّر مفاجئ لطاقة مخزّنة في صخور الأعماق"},{"id":"b","text":"تبخّر مياه البحار بسرعة كبيرة"},{"id":"c","text":"سقوط النيازك على سطح الأرض دائمًا"},{"id":"d","text":"ذوبان الجليد في القطبين"}]'::jsonb, 'a', 'الزلزال هزّة مفاجئة سببها تحرّر مفاجئ لطاقة مخزّنة في صخور الأعماق، تنتقل على شكل موجات زلزالية. أمّا تبخّر المياه وذوبان الجليد فظواهر سطحية لا تحرّر هذه الطاقة، وسقوط النيازك سبب نادر جدًّا وليس السبب الأساسي.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d1a72a3c-bf11-5d5f-bf0d-54e2d869f279', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'البؤرة (le foyer) هي:', '[{"id":"a","text":"النقطة على سطح الأرض التي يحسّ فيها الناس بالهزّة"},{"id":"b","text":"النقطة داخل الأرض التي تنطلق منها الموجات الزلزالية"},{"id":"c","text":"الجهاز الذي يسجّل الزلزال"},{"id":"d","text":"سلّم لقياس قوّة الزلزال"}]'::jsonb, 'b', 'البؤرة هي نقطة منشأ الزلزال داخل الأرض (في العمق) وتنطلق منها الموجات الزلزالية. أمّا النقطة على السطح فهي المركز السطحي، والجهاز هو المرصاد الزلزالي، والسلّم يخصّ قياس المقدار أو الشدّة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e9f283ed-6a7c-5c8b-8d54-b3c204480640', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'المركز السطحي (l''épicentre) هو:', '[{"id":"a","text":"النقطة الأعمق في باطن الأرض"},{"id":"b","text":"أبعد منطقة عن الزلزال"},{"id":"c","text":"النقطة على سطح الأرض الواقعة عموديًّا فوق البؤرة مباشرة"},{"id":"d","text":"مركز الكرة الأرضية"}]'::jsonb, 'c', 'المركز السطحي هو النقطة على سطح الأرض الواقعة عموديًّا فوق البؤرة مباشرة، وهي عادةً الأكثر تضرّرًا لأنّها الأقرب إلى البؤرة. وهو ليس نقطة في العمق ولا مركز الأرض ولا أبعد منطقة عن الزلزال.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3834eb4e-5a63-54c8-88f2-d78b3998b401', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'ما العلاقة الصحيحة بين الزلزال والموجات الزلزالية؟', '[{"id":"a","text":"الموجات الزلزالية هي سبب الزلزال"},{"id":"b","text":"الزلزال يحرّر طاقة تنتقل على شكل موجات زلزالية تُحدث الاهتزاز"},{"id":"c","text":"لا علاقة بين الزلزال والموجات الزلزالية"},{"id":"d","text":"الموجات الزلزالية تنتشر فقط في الغلاف الجوّي"}]'::jsonb, 'b', 'عند الزلزال تتحرّر طاقة عند البؤرة تنتقل على شكل موجات زلزالية تنتشر في الصخور وتُحدث اهتزاز السطح. فالموجات نتيجة لتحرّر الطاقة وليست سببًا للزلزال، وهي تنتشر في الأرض لا في الهواء.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('40428907-308f-5afa-9838-2d8b1b4781f1', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'أين تقع البؤرة بالنسبة للمركز السطحي؟', '[{"id":"a","text":"في العمق تحت المركز السطحي مباشرة"},{"id":"b","text":"على السطح بجانب المركز السطحي"},{"id":"c","text":"في الغلاف الجوّي فوق المركز السطحي"},{"id":"d","text":"البؤرة والمركز السطحي في نفس المكان تمامًا"}]'::jsonb, 'a', 'البؤرة تقع في العمق داخل الأرض، والمركز السطحي يقع على السطح عموديًّا فوقها مباشرة. فالبؤرة إذن تحت المركز السطحي مباشرة. وليست على السطح ولا في الجوّ، وليست في نفس مكان المركز السطحي لأنّ هذا في العمق وذاك على السطح.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b714b909-99c3-50bd-8d4d-1c3c63c3e53b', 'd88a2774-8652-59a1-bc01-b2d51cd56be3', 'لماذا تكون المنطقة قرب المركز السطحي عادةً الأكثر تضرّرًا؟', '[{"id":"a","text":"لأنّها أبعد المناطق عن البؤرة"},{"id":"b","text":"لأنّها الأقرب إلى البؤرة فتصلها الموجات أقوى"},{"id":"c","text":"لأنّ المرصاد الزلزالي موجود فيها دائمًا"},{"id":"d","text":"لأنّ الموجات تتوقّف عندها فجأة"}]'::jsonb, 'b', 'المركز السطحي هو الأقرب إلى البؤرة، فتصله الموجات الزلزالية وهي أقوى، لذلك يكون عادةً الأكثر تضرّرًا. وكلّما ابتعدنا عنه ضعفت آثار الزلزال تدريجيًّا. ووجود المرصاد لا علاقة له بالأضرار.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

