  ('2f705317-1f56-54d3-a7e5-61d7945a6a56', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', 'تمرين: الموجات وتسجيلها والشدّة والمقدار', 2, 50, 10, 'practice', 'admin', 2)
