INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('77baee2e-263c-5970-8b40-c6bf998173a3', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'الموجات الأوّلية (P) تتميّز بأنّها:', '[{"id":"a","text":"الأبطأ وتصل أخيرًا"},{"id":"b","text":"الأسرع وتصل أوّلًا إلى المرصاد"},{"id":"c","text":"لا تنتشر إلّا في الهواء"},{"id":"d","text":"لا تُسجَّل في المرصاد الزلزالي"}]'::jsonb, 'b', 'الموجات الأوّلية (P) هي الأسرع، فتصل أوّلًا إلى المرصاد الزلزالي، تليها الموجات الثانوية (S) الأبطأ. وتنتشر الموجات في الصخور لا في الهواء، وتُسجَّل جميعها في المرصاد.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
