  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7d9445fb-6119-55b3-b6ad-ca0c619576f1', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'الرسم الذي يسجّله المرصاد الزلزالي للاهتزازات يُسمّى:', '[{"id":"a","text":"المخطّط الزلزالي (sismogramme)"},{"id":"b","text":"الخريطة الطبوغرافية"},{"id":"c","text":"سلّم ريشتر"},{"id":"d","text":"المخطّط الحراري"}]'::jsonb, 'a', 'المخطّط الزلزالي (sismogramme) هو الرسم الذي يسجّله المرصاد الزلزالي ويبيّن سعة الاهتزازات وزمن وصول الموجات. أمّا سلّم ريشتر فهو مقياس للمقدار، والخريطة الطبوغرافية والمخطّط الحراري ظواهر أخرى.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d59298e9-7418-5d6b-81f9-b2892d20f5d5', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'كيف يحدّد العلماء موقع المركز السطحي للزلزال؟', '[{"id":"a","text":"من لون الصخور المحيطة بالبؤرة"},{"id":"b","text":"من فرق زمن وصول الموجات P و S المسجَّل في المراصد"},{"id":"c","text":"من درجة حرارة الجوّ وقت الزلزال"},{"id":"d","text":"من سرعة الرياح في المنطقة"}]'::jsonb, 'b', 'بما أنّ الموجات P أسرع من S، يكبر فرق زمن وصولهما كلّما ابتعد المرصاد عن المركز السطحي. وبجمع معطيات عدّة مراصد يمكن تحديد موقع المركز السطحي. ولا علاقة لذلك بلون الصخور أو حرارة الجوّ أو الرياح.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ccf3dff4-c04d-501a-a013-05a7d2962b44', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'شدّة الزلزال (l''intensité):', '[{"id":"a","text":"تقيس الطاقة المحرَّرة عند البؤرة ولها قيمة واحدة"},{"id":"b","text":"تقيس آثار الزلزال على السطح وتختلف من مكان إلى آخر"},{"id":"c","text":"تُقاس بسلّم ريشتر فقط"},{"id":"d","text":"ثابتة في كلّ نقاط الأرض"}]'::jsonb, 'b', 'الشدّة تقيس آثار الزلزال المُلاحَظة على السطح (الأضرار، إحساس الناس) وتختلف من مكان إلى آخر للزلزال نفسه، وتُقاس بسلّم ميركالّي. أمّا قياس الطاقة المحرَّرة بقيمة واحدة فهو المقدار (بسلّم ريشتر).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
