  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d8e1d932-6b1e-5677-a7fb-3f2585c44174', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'مقدار الزلزال (la magnitude):', '[{"id":"a","text":"يقيس الطاقة المحرَّرة عند البؤرة وله قيمة واحدة للزلزال الواحد"},{"id":"b","text":"يقيس آثار الزلزال ويتغيّر من مدينة إلى أخرى"},{"id":"c","text":"يُقاس بسلّم ميركالّي الوصفي"},{"id":"d","text":"يدلّ على عدد المباني المنهارة فقط"}]'::jsonb, 'a', 'المقدار يقيس الطاقة المحرَّرة عند البؤرة، وله قيمة واحدة للزلزال الواحد مهما تعدّدت أماكن القياس، ويُقاس بسلّم ريشتر. أمّا قياس الآثار المتغيّرة من مكان لآخر بسلّم ميركالّي فهو الشدّة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
