INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c65975ff-f3fb-5c32-a5ee-efdc8c6f4518', '2f705317-1f56-54d3-a7e5-61d7945a6a56', 'زلزال واحد سُجّل في عدّة مدن. أيّ القياسين يبقى ثابتًا؟', '[{"id":"a","text":"الشدّة، لأنّها تقيس الآثار على السطح"},{"id":"b","text":"المقدار، لأنّه يقيس الطاقة المحرَّرة عند البؤرة"},{"id":"c","text":"كلاهما يتغيّر من مدينة إلى أخرى"},{"id":"d","text":"كلاهما ثابت لا يتغيّر أبدًا"}]'::jsonb, 'b', 'المقدار يقيس الطاقة المحرَّرة عند البؤرة فيبقى ثابتًا (قيمة واحدة) مهما تعدّدت المدن. أمّا الشدّة فتقيس الآثار على السطح فتختلف من مدينة إلى أخرى حسب القرب من المركز السطحي ونوع التربة والبناء.', 6, 'mcq', NULL, NULL)
