INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4b5453e8-a3cf-5de8-a7c1-226aafb06278', '7b43517f-f4b4-5927-9c82-970e9805f797', 'ما الذي يحدث في الصخور لحظة وقوع الزلزال التكتوني؟', '[{"id":"a","text":"تتمدّد الصخور ببطء دون انكسار"},{"id":"b","text":"تنكسر الصخور فجأة على مستوى فالق فتتحرّر الطاقة المخزّنة دفعةً واحدة"},{"id":"c","text":"تذوب الصخور وتتحوّل إلى حمم سطحية"},{"id":"d","text":"تتبخّر الصخور تمامًا"}]'::jsonb, 'b', 'تتراكم الضغوط في الصخور حتى تتجاوز مقاومتها، فتنكسر فجأة على مستوى فالق وتتحرّر الطاقة المخزّنة دفعةً واحدة على شكل موجات زلزالية. وهذا غير الذوبان (الذي يخصّ البراكين) وغير التمدّد البطيء أو التبخّر.', 1, 'mcq', NULL, NULL)
