INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('35271850-977a-5554-bbe3-72d8437bfceb', '7b43517f-f4b4-5927-9c82-970e9805f797', 'أين تتركّز معظم الزلازل في العالم؟', '[{"id":"a","text":"في وسط الصفائح بعيدًا عن حدودها"},{"id":"b","text":"عند حدود الصفائح التكتونية"},{"id":"c","text":"في الصحارى الرملية فقط"},{"id":"d","text":"في المناطق القطبية المتجمّدة فقط"}]'::jsonb, 'b', 'تتركّز معظم الزلازل عند حدود الصفائح التكتونية حيث تحتكّ الصفائح وتتراكم الضغوط، ومنها حوض البحر الأبيض المتوسّط الذي تقع فيه تونس. أمّا وسط الصفائح والصحارى والقطبين فليست مناطق زلزالية مميّزة بحدّ ذاتها.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3671e022-537d-558c-bc83-c5b6c887f596', '7b43517f-f4b4-5927-9c82-970e9805f797', 'ما الفالق (la faille)؟', '[{"id":"a","text":"جهاز لقياس الزلازل"},{"id":"b","text":"كسر في الصخور يحدث على طوله انزلاق مفاجئ يحرّر الطاقة"},{"id":"c","text":"موجة زلزالية سطحية"},{"id":"d","text":"سلّم لقياس مقدار الزلزال"}]'::jsonb, 'b', 'الفالق كسر في الصخور يحدث على طوله انزلاق مفاجئ حين تتجاوز الضغوط مقاومة الصخور، فتتحرّر الطاقة وينشأ الزلزال. وليس جهازًا (المرصاد) ولا موجة ولا سلّمًا (ريشتر/ميركالّي).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2c86b888-acae-5405-803e-337f9656b635', '7b43517f-f4b4-5927-9c82-970e9805f797', 'لماذا تُعتبر تونس منطقة معرّضة للنشاط الزلزالي؟', '[{"id":"a","text":"لأنّها تقع وسط صفيحة بعيدة عن أيّ حدود"},{"id":"b","text":"لأنّها قريبة من منطقة التقاء الصفائح في حوض البحر الأبيض المتوسّط"},{"id":"c","text":"لأنّ مناخها حارّ وجافّ"},{"id":"d","text":"لأنّها تكثر فيها الأمطار"}]'::jsonb, 'b', 'تقع تونس قرب منطقة التقاء الصفائح في حوض البحر الأبيض المتوسّط حيث تتراكم الضغوط، لذلك تتعرّض لنشاط زلزالي. والمناخ والأمطار لا علاقة لهما بأسباب الزلازل التكتونية.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7d2c52cf-0c3c-5f30-8a94-70f58b61e9d9', '7b43517f-f4b4-5927-9c82-970e9805f797', 'أيّ تسلسل يصف نشأة الزلزال التكتوني بشكل صحيح؟', '[{"id":"a","text":"تساقط أمطار ← تشبّع التربة ← اهتزاز"},{"id":"b","text":"حركة الصفائح ← تراكم الضغوط ← انكسار الصخور على فالق ← تحرّر الطاقة وموجات زلزالية"},{"id":"c","text":"ارتفاع الحرارة ← تبخّر المياه ← هزّة"},{"id":"d","text":"هبوب رياح قويّة ← انزلاق الرمال ← زلزال"}]'::jsonb, 'b', 'التسلسل الصحيح: حركة الصفائح التكتونية تراكم الضغوط عند الحدود تجاوز مقاومة الصخور وانكسارها على فالق تحرّر مفاجئ للطاقة على شكل موجات زلزالية. أمّا الأمطار والحرارة والرياح فليست أسبابًا لهذا التسلسل التكتوني.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('161a8d73-1f98-5032-b759-c9f3020c4cd4', '7b43517f-f4b4-5927-9c82-970e9805f797', 'زلزالان لهما المقدار نفسه، لكن أحدهما سبّب أضرارًا أكبر بكثير. ما التفسير الأرجح؟', '[{"id":"a","text":"هذا مستحيل: المقدار نفسه يعني الأضرار نفسها دائمًا"},{"id":"b","text":"اختلاف الشدّة بسبب عمق البؤرة وقرب العمران ونوع التربة وجودة البناء"},{"id":"c","text":"اختلاف لون الصخور بين المنطقتين"},{"id":"d","text":"اختلاف فصل السنة فقط"}]'::jsonb, 'b', 'المقدار يقيس الطاقة عند البؤرة، لكن الأضرار (الشدّة) تتأثّر بعمق البؤرة، وقرب المركز السطحي من العمران، ونوع التربة، وجودة البناء. لذلك قد يسبّب زلزالان بنفس المقدار أضرارًا مختلفة. واللون والفصل لا يفسّران ذلك.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

