INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('509e52da-1efa-54f9-9da1-4eeaa51f355c', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'ما السلوك الصحيح أثناء حدوث زلزال داخل مبنى؟', '[{"id":"a","text":"الوقوف قرب النوافذ الزجاجية لمشاهدة الخارج"},{"id":"b","text":"الاحتماء تحت طاولة متينة والابتعاد عن النوافذ"},{"id":"c","text":"استعمال المصعد فورًا للنزول بسرعة"},{"id":"d","text":"الركض بين الطوابق بأقصى سرعة"}]'::jsonb, 'b', 'السلوك الآمن هو الاحتماء تحت طاولة متينة وحماية الرأس والابتعاد عن النوافذ. أمّا الوقوف قرب الزجاج فيعرّض للجروح، واستعمال المصعد خطر لأنّه قد يتوقّف، والركض بين الطوابق يزيد خطر السقوط.', 1, 'mcq', NULL, NULL)
