INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5196e4a6-7147-5b9c-b857-57526d7a7ea5', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'ما الموجة الزلزالية الأكثر تدميرًا للمباني عادةً؟', '[{"id":"a","text":"الموجات الأوّلية (P)"},{"id":"b","text":"الموجات السطحية"},{"id":"c","text":"لا توجد موجة أكثر تدميرًا من غيرها"},{"id":"d","text":"الموجات الصوتية في الهواء"}]'::jsonb, 'b', 'الموجات السطحية تنتشر قرب السطح وتُحدث اهتزازات قويّة فهي الأكثر تدميرًا للمباني، رغم أنّ الموجات P تصل أوّلًا. والموجات الصوتية في الهواء ليست موجات زلزالية.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
