  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f9c0751c-3098-59c2-9b2b-5866a95f73e8', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'أيّ ظاهرة قد تنتج عن زلزال قويّ يقع في قاع البحر؟', '[{"id":"a","text":"تسونامي (موجات بحرية عملاقة)"},{"id":"b","text":"كسوف للشمس"},{"id":"c","text":"هطول ثلوج كثيفة"},{"id":"d","text":"تكوّن قوس قزح"}]'::jsonb, 'a', 'الزلزال القويّ في قاع البحر قد يزيح كتلة ضخمة من الماء فجأة فينشأ التسونامي: موجات بحرية عملاقة قد تجتاح السواحل. أمّا الكسوف والثلوج وقوس قزح فظواهر لا علاقة لها بالزلازل.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
