  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('13fb75ad-e954-5336-97b3-69221d649f56', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'أيّ إجراء بناء يقلّل فعليًّا من أضرار الزلازل؟', '[{"id":"a","text":"تشييد مبانٍ مقاومة للزلازل وفق معايير مضادّة للهزّات"},{"id":"b","text":"البناء مباشرةً فوق الفوالق النشطة"},{"id":"c","text":"استعمال مواد هشّة لتخفيف وزن المبنى"},{"id":"d","text":"إلغاء أيّ معايير في البناء لتسريع الإنجاز"}]'::jsonb, 'a', 'البناء المقاوم للزلازل وفق معايير مضادّة للهزّات يقلّل الأضرار فعليًّا. أمّا البناء فوق الفوالق النشطة أو استعمال مواد هشّة أو إلغاء المعايير فكلّها تزيد الخطر.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
