  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('46aedd13-e330-51e4-852a-e36919f88ee8', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'زلزال سُجّل مقداره 6 على سلّم ريشتر، وقيست له شدّات مختلفة في عدّة مدن. ما التفسير الصحيح؟', '[{"id":"a","text":"خطأ في القياس لأنّ كلّ القيم يجب أن تتطابق"},{"id":"b","text":"المقدار قيمة واحدة (الطاقة عند البؤرة)، بينما تختلف الشدّة من مدينة لأخرى حسب الآثار"},{"id":"c","text":"المقدار يجب أن يختلف هو الآخر من مدينة لأخرى"},{"id":"d","text":"الشدّة والمقدار يقيسان نفس الشيء فلا يمكن اختلافهما"}]'::jsonb, 'b', 'المقدار يقيس الطاقة المحرَّرة عند البؤرة وله قيمة واحدة (6 هنا) في كلّ المدن، بينما تقيس الشدّة آثار الزلزال على السطح فتختلف من مدينة لأخرى حسب القرب من المركز السطحي ونوع التربة وجودة البناء. فلا تناقض في ذلك.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1d98981a-72a1-59f9-8c58-6216ca3fb14d', '0e6d4948-f756-5b0e-a27a-05de124a5644', 'ربط منطقي: لماذا يساعد امتلاك شبكة مراصد زلزالية متعدّدة على الوقاية؟', '[{"id":"a","text":"لأنّها تمنع وقوع الزلازل نهائيًّا"},{"id":"b","text":"لأنّها تحدّد مواقع الزلازل وتراقب النشاط الزلزالي فتدعم الإنذار المبكّر وخرائط المخاطر"},{"id":"c","text":"لأنّها ترفع مقدار الزلزال فتقلّل أضراره"},{"id":"d","text":"لأنّها تغيّر اتّجاه الموجات الزلزالية بعيدًا عن المدن"}]'::jsonb, 'b', 'شبكة المراصد تحدّد مواقع الزلازل (المركز السطحي) عبر فرق وصول الموجات وتراقب النشاط الزلزالي، فتدعم الإنذار المبكّر ورسم خرائط المخاطر والتخطيط العمراني. لكنّها لا تمنع الزلازل ولا تغيّر مقدارها ولا تحرف الموجات؛ دورها الرصد والوقاية لا التحكّم في الظاهرة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

