  ('6a153e25-c76a-52ac-8403-bfee61662c58', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', '🛡️ تدرّب على الفصل: مراجعة الزلازل', 3, 120, 30, 'boss', 'admin', 5)
