INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0054721d-54a6-5958-a1f5-ea942da944ed', '6a153e25-c76a-52ac-8403-bfee61662c58', 'ما البؤرة الزلزالية (le foyer / l''hypocentre)؟', '[{"id":"a","text":"النقطة في باطن الأرض التي ينطلق منها الزلزال"},{"id":"b","text":"النقطة على سطح الأرض فوق منشأ الزلزال مباشرةً"},{"id":"c","text":"الجهاز الذي يسجّل الموجات الزلزالية"},{"id":"d","text":"رقم على سلّم ريشتر"}]'::jsonb, 'a', 'البؤرة هي النقطة في عمق الأرض التي ينطلق منها الزلزال وتتحرّر فيها الطاقة. النقطة السطحية فوقها مباشرةً هي المركز السطحي (l''épicentre)، والجهاز المسجّل هو المرصاد الزلزالي، ورقم ريشتر يعبّر عن المقدار لا عن مكان المنشأ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2f577e55-d80e-5e93-aeba-f8bbfff45e93', '6a153e25-c76a-52ac-8403-bfee61662c58', 'بأيّ جهاز تُسجَّل الموجات الزلزالية؟', '[{"id":"a","text":"المرصاد الزلزالي (le sismographe)"},{"id":"b","text":"الميزان الحراري"},{"id":"c","text":"البوصلة"},{"id":"d","text":"المجهر"}]'::jsonb, 'a', 'المرصاد الزلزالي جهاز يكشف الموجات الزلزالية ويسجّلها في مخطّط زلزالي. الميزان الحراري يقيس درجة الحرارة، والبوصلة تحدّد الاتّجاهات، والمجهر يكبّر الأجسام الصغيرة، فلا علاقة لها بتسجيل الزلازل.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
