  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fcadd697-8bdd-5a97-beb4-7a553538f9bf', '6a153e25-c76a-52ac-8403-bfee61662c58', 'ما الفرق بين شدّة الزلزال ومقداره (سلّم ريشتر)؟', '[{"id":"a","text":"المقدار يعبّر عن الطاقة المحرَّرة عند البؤرة، والشدّة تعبّر عن آثار الزلزال على المكان"},{"id":"b","text":"هما الشيء نفسه بأسماء مختلفة"},{"id":"c","text":"الشدّة تقاس بسلّم ريشتر دائمًا"},{"id":"d","text":"المقدار يصف الأضرار على المباني فقط"}]'::jsonb, 'a', 'المقدار (سلّم ريشتر) يقيس الطاقة التي يحرّرها الزلزال عند البؤرة وهو قيمة واحدة للزلزال، أمّا الشدّة فتصف آثاره ودرجة الأضرار التي تختلف من مكان لآخر. فهما ليسا الشيء نفسه، والشدّة لا تقاس بريشتر، والمقدار لا يقتصر على وصف الأضرار.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0e3660a8-ac34-53ae-aa60-54f36ea39b16', '6a153e25-c76a-52ac-8403-bfee61662c58', 'ما السبب الرئيسي للزلازل التكتونية؟', '[{"id":"a","text":"تحرّك الصفائح التكتونية وتراكم الإجهادات في الصخور ثمّ تكسّرها فجأةً"},{"id":"b","text":"هطول الأمطار الغزيرة"},{"id":"c","text":"دوران الأرض حول الشمس"},{"id":"d","text":"تغيّر درجة حرارة الهواء"}]'::jsonb, 'a', 'تنشأ الزلازل التكتونية من حركة الصفائح التي تراكم إجهادات في الصخور حتّى تتجاوز مقاومتها فتنكسر فجأةً (على مستوى الفوالق) مُحرِّرةً طاقةً على شكل موجات. الأمطار ودوران الأرض حول الشمس وحرارة الهواء عوامل مناخية أو فلكية لا تسبّب الزلازل التكتونية.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9b9356cd-32de-5de1-87d9-8e6b4079c178', '6a153e25-c76a-52ac-8403-bfee61662c58', 'أيّ سلوك يُعدّ من إجراءات الوقاية الصحيحة أثناء وقوع زلزال داخل قاعة الدرس؟', '[{"id":"a","text":"الاحتماء تحت طاولة متينة بعيدًا عن النوافذ والابتعاد عن الأشياء التي قد تسقط"},{"id":"b","text":"الركض بسرعة عبر الدَّرَج والتدافع نحو المخرج"},{"id":"c","text":"الوقوف قرب النوافذ الزجاجية لمراقبة ما يحدث"},{"id":"d","text":"استعمال المصعد للنزول بسرعة"}]'::jsonb, 'a', 'أثناء الزلزال يُنصح بالاحتماء تحت طاولة متينة بعيدًا عن النوافذ والأشياء التي قد تسقط حتّى تهدأ الهزّة. الركض والتدافع يسبّبان الإصابات، والوقوف قرب الزجاج خطر لتكسّره، واستعمال المصعد ممنوع لاحتمال انقطاع الكهرباء واحتجاز الأشخاص فيه.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a8bc2920-578f-5b48-a48c-03d18585a81e', '6a153e25-c76a-52ac-8403-bfee61662c58', 'زلزالان لهما المقدار نفسه على سلّم ريشتر، لكنّ أحدهما خلّف أضرارًا أكبر بكثير. ما التفسير الأرجح؟', '[{"id":"a","text":"أنّ المقدار خاطئ بالضرورة في أحدهما"},{"id":"b","text":"اختلاف عمق البؤرة وقرب المركز السطحي من العمران ونوع المباني والتربة"},{"id":"c","text":"أنّ الأرض تدور بسرعة مختلفة في الموقعين"},{"id":"d","text":"أنّ الزلزال الأقوى لا يصدر موجات زلزالية"}]'::jsonb, 'b', 'بنفس المقدار قد تختلف الأضرار (الشدّة) باختلاف عمق البؤرة وقرب المركز السطحي من المناطق المأهولة ونوع التربة وجودة البناء. فاختلاف الأضرار طبيعي ولا يدلّ على خطأ في المقدار، ولا علاقة له بسرعة دوران الأرض، وكلّ زلزال يصدر موجات زلزالية.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

