  ('dfa7af95-6394-5853-a691-737d901d1505', 'ca61212e-8e45-50b3-82cb-ec086f3a39dd', 'sciences-vie-terre', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الزلازل — أمواج ومقدار وتحديد المركز', 4, 300, 60, 'challenge', 'admin', 6)
