INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c175f781-8bbb-56b4-8b6e-9767694f653a', 'dfa7af95-6394-5853-a691-737d901d1505', 'ما الفرق بين بؤرة الزلزال (المركز العميق) والمركز السطحيّ للزلزال؟', '[{"id":"a","text":"البؤرة نقطة انطلاق الزلزال في العمق ; المركز السطحيّ إسقاطها عموديًّا على سطح الأرض"},{"id":"b","text":"البؤرة على السطح ; المركز السطحيّ في العمق"},{"id":"c","text":"هما نقطة واحدة بتسميتَين"},{"id":"d","text":"البؤرة في البحر والمركز السطحيّ في اليابسة دائمًا"}]'::jsonb, 'a', 'البؤرة (المركز الجوفيّ) هي نقطة انطلاق الكسر داخل الأرض حيث تتحرّر الطاقة، والمركز السطحيّ هو النقطة على سطح الأرض عموديًّا فوق البؤرة (حيث تكون الأضرار أشدّ غالبًا). ✓ الخطأ الشائع: الخلط بين البؤرة العميقة والمركز السطحيّ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f688b0da-a3c0-5114-91a0-fa16c65516b1', 'dfa7af95-6394-5853-a691-737d901d1505', 'قال تلميذ: «كلّما زاد مقدار الزلزال على سلّم ريشتر ازداد عدد الضحايا حتمًا». ما الخطأ؟', '[{"id":"a","text":"عدد الضحايا يتعلّق بالشدّة المحلّية وكثافة السكّان ومتانة البناء وساعة الوقوع، لا بالمقدار وحده"},{"id":"b","text":"لا خطأ، المقدار وحده يحدّد عدد الضحايا"},{"id":"c","text":"المقدار لا علاقة له بقوّة الزلزال إطلاقًا"},{"id":"d","text":"الزلازل الكبيرة لا تسبّب ضحايا أبدًا"}]'::jsonb, 'a', 'المقدار يقيس الطاقة المتحرّرة عند المصدر، لكنّ حجم الكارثة يتوقّف على الشدّة في الموقع (تتناقص بالبُعد ونوع التربة)، وكثافة العمران، ومتانة المباني، ووقت الحدوث. فقد يقلّ ضحايا زلزال قويّ في منطقة مُحكمة البناء قليلة السكّان. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين المقدار (عند المصدر) والشدّة/الأثر (في الموقع).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bba99cbb-84ba-52bd-8573-7945b0b3b754', 'dfa7af95-6394-5853-a691-737d901d1505', 'تنتشر الأمواج الأوّلية P أسرع من الأمواج الثانوية S. في محطّة رصد سُجّلت P أوّلًا ثمّ S بعد فارق زمنيّ. علامَ يدلّ كِبَر هذا الفارق الزمنيّ بين وصول الموجتين؟', '[{"id":"a","text":"أنّ المحطّة أبعد عن مركز الزلزال"},{"id":"b","text":"أنّ المحطّة أقرب إلى مركز الزلزال"},{"id":"c","text":"أنّ الزلزال أقوى مقدارًا"},{"id":"d","text":"أنّ الزلزال أضعف مقدارًا"}]'::jsonb, 'a', 'بما أنّ P أسرع من S، فكلّما بَعُدت المحطّة عن المركز اتّسع الفارق الزمنيّ بين وصولهما (تتراكم فوارق السرعة على مسافة أطول). فالفارق الكبير يدلّ على بُعد المحطّة عن المركز. ✓ الخطأ الشائع: ربط الفارق الزمنيّ بمقدار الزلزال بدل ربطه بالمسافة إلى المركز.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('68ddd8ed-948f-5f0c-8463-a15d36d687f6', 'dfa7af95-6394-5853-a691-737d901d1505', 'لتحديد الموقع الدقيق لمركز زلزال انطلاقًا من فوارق وصول الأمواج، ما أقلّ عدد من محطّات الرصد اللازمة؟', '[{"id":"a","text":"3 محطّات"},{"id":"b","text":"محطّة واحدة"},{"id":"c","text":"محطّتان"},{"id":"d","text":"5 محطّات"}]'::jsonb, 'a', 'كلّ محطّة تُعطي مسافتها إلى المركز (من فارق زمن P وS)، أي دائرة من المواقع الممكنة. محطّتان تعطيان تقاطعَين محتملَين، ويلزم تقاطع ثلاث دوائر (3 محطّات) لتعيين نقطة المركز بلا لبس. ✓ الخطأ الشائع: الاكتفاء بمحطّة أو محطّتين، فيبقى الموقع غير محدَّد بدقّة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('087d9799-1cf6-55f5-8e54-2bde0853f11e', 'dfa7af95-6394-5853-a691-737d901d1505', 'سلّم ريشتر لتقدير مقدار الزلزال سلّمٌ لوغاريتميّ: كلّ زيادة بوحدة واحدة في المقدار تقابل ازديادًا في سعة الاهتزاز المسجَّلة بمقدار كم مرّة؟', '[{"id":"a","text":"10 مرّات"},{"id":"b","text":"مرّة واحدة (زيادة قدرها 1 فقط)"},{"id":"c","text":"مرّتان"},{"id":"d","text":"100 مرّة لكلّ وحدة"}]'::jsonb, 'a', 'سلّم ريشتر لوغاريتميّ بأساس 10: زيادة المقدار بوحدة واحدة تعني أنّ سعة الاهتزاز المسجَّلة تصير 10 أضعاف (فزلزال مقداره 7 سعته 10 أضعاف زلزال مقداره 6). ✓ الخطأ الشائع: التعامل مع السلّم على أنّه خطّيّ (زيادة 1 = ضعف بسيط) بدل كونه لوغاريتميًّا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('257c6cd6-671e-5c37-b127-95431c77152f', 'dfa7af95-6394-5853-a691-737d901d1505', 'منطقتان: (أ) قرب حدود صفيحتَين تكتونيتَين نشطتَين، و(ب) في وسط صفيحة بعيدًا عن الحدود. أيّهما أكثر عرضةً للزلازل، ولماذا؟', '[{"id":"a","text":"(أ)، لأنّ الزلازل تتركّز أساسًا عند حدود الصفائح حيث تحتكّ وتتحرّك"},{"id":"b","text":"(ب)، لأنّ وسط الصفيحة أضعف"},{"id":"c","text":"متساويتان، الزلازل موزّعة عشوائيًّا"},{"id":"d","text":"(ب)، لبُعدها عن البحر"}]'::jsonb, 'a', 'معظم الزلازل تنشأ عند حدود الصفائح (تباعد، تقارب، انزلاق) حيث تتراكم الإجهادات وتتحرّر فجأةً؛ فالمنطقة (أ) القريبة من الحدود أكثر عرضةً بكثير. (تمرين تحليل وضعية.) ✓ الخطأ الشائع: افتراض توزيع عشوائيّ للزلازل بدل ربطها بحدود الصفائح.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

