INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3f8f6110-6f58-54b0-9ecb-932213bf4320', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'ما هو البركان؟', '[{"id":"a","text":"اهتزاز مفاجئ لسطح الأرض ناتج عن تحرّر طاقة في باطنها"},{"id":"b","text":"فُتحة في القشرة الأرضية تخرج منها موادّ منصهرة وغازات وموادّ صلبة من باطن الأرض"},{"id":"c","text":"صخر منصهر يبقى دائمًا حبيس باطن الأرض"},{"id":"d","text":"تجويف على سطح الأرض تجمّع فيه ماء المطر"}]'::jsonb, 'b', 'البركان فُتحة (أو شقّ) في القشرة الأرضية تخرج منها موادّ منصهرة وغازات وموادّ صلبة آتية من العمق. أمّا الاهتزاز المفاجئ للأرض فهو الزلزال لا البركان، والصهارة الحبيسة دائمًا في الباطن ليست بركانًا لأنّ البركان يتطلّب خروج الموادّ إلى السطح.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
