  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('799a06e3-775f-5fd8-af12-64f0252d41df', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أين تتجمّع الصهارة قبل صعودها نحو سطح الأرض؟', '[{"id":"a","text":"في الفوّهة"},{"id":"b","text":"في المخروط البركاني"},{"id":"c","text":"في الخزّان الصهاري (الغرفة الصهارية)"},{"id":"d","text":"في الرماد البركاني"}]'::jsonb, 'c', 'تتجمّع الصهارة في الخزّان الصهاري الموجود في العمق، ثمّ تصعد عبر المدخنة إلى الفوّهة فالسطح. الفوّهة هي الفتحة العلوية، والمخروط هو الجبل المتراكم خارجًا، فلا يصحّ أيّ منهما مكانًا لتجمّع الصهارة قبل الصعود.', 2, 'mcq', NULL, NULL)
