INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('73b75412-8e4a-59d0-9a2c-e2712b129445', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'ما الذي يميّز الثوران البركاني الانسيابي (الهادئ)؟', '[{"id":"a","text":"انفجار عنيف يقذف سحبًا حارقة من الرماد والكُتل"},{"id":"b","text":"خروج اللابة السائلة بهدوء وسيلانها على شكل أنهار من الحِمم"},{"id":"c","text":"عدم خروج أيّ مادّة من الفوّهة"},{"id":"d","text":"خروج الماء فقط دون لابة"}]'::jsonb, 'b', 'في الثوران الانسيابي تكون الصهارة سائلة قليلة اللزوجة، فتخرج اللابة بهدوء وتسيل بعيدًا مكوّنةً أنهارًا من الحِمم ومخروطًا منبسطًا. أمّا الانفجار العنيف وقذف السُحب الحارقة فهو سمة الثوران الانفجاري لا الانسيابي.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('201daf6e-3c9f-5acd-a33c-ed2fb316b2b2', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أيّ ممّا يلي يُعدّ فائدة من فوائد البراكين للإنسان؟', '[{"id":"a","text":"خصوبة التربة البركانية والطاقة الحرارية الأرضية (الجيوحرارية)"},{"id":"b","text":"تدمير المنشآت بالحِمم"},{"id":"c","text":"خنق الكائنات الحيّة بالرماد"},{"id":"d","text":"تلوّث الهواء بالغازات"}]'::jsonb, 'a', 'من فوائد البراكين خصوبة تربتها وتوفير الطاقة الجيوحرارية والثروات المعدنية وينابيع المياه الساخنة. أمّا تدمير المنشآت وخنق الكائنات بالرماد وتلوّث الهواء فهي من مخاطر البراكين لا فوائدها.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('85dff667-cdd6-5b2a-8a36-8e98376e11d7', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'ما الفرق الأساسي بين الصهارة (Magma) واللابة (Lave)؟', '[{"id":"a","text":"الصهارة في باطن الأرض ومحمّلة بالغازات، واللابة هي الصهارة نفسها بعد خروجها إلى السطح وفقدها معظم غازاتها"},{"id":"b","text":"اللابة في باطن الأرض، والصهارة على سطحها"},{"id":"c","text":"الصهارة صلبة دائمًا، واللابة غاز"},{"id":"d","text":"هما مادّتان مختلفتان تمامًا لا علاقة بينهما"}]'::jsonb, 'a', 'الصهارة صخر منصهر محمّل بالغازات يوجد في باطن الأرض، واللابة هي الصهارة ذاتها بعد خروجها إلى السطح وقد فقدت معظم غازاتها. فالعلاقة بينهما واحدة: نفس المادّة قبل الخروج (صهارة) وبعده (لابة)، لذا فالقول إنّهما مختلفتان تمامًا أو إنّ اللابة في الباطن خطأ شائع.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3359ec63-90e2-5cf0-a769-94dd37b4dfab', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أيّ نوع من الصهارة يميّز الثوران البركاني الانفجاري (المتفجّر)؟', '[{"id":"a","text":"صهارة سائلة قليلة اللزوجة وفقيرة بالغازات"},{"id":"b","text":"صهارة لزجة (كثيفة) غنيّة بالغازات"},{"id":"c","text":"صهارة باردة صلبة"},{"id":"d","text":"ماء ساخن مشبّع بالأملاح"}]'::jsonb, 'b', 'الثوران الانفجاري ينتج عن صهارة لزجة غنيّة بالغازات: تَسُدّ اللزوجة المدخنة فيتراكم ضغط الغازات حتى ينفجر البركان. أمّا الصهارة السائلة القليلة اللزوجة فتعطي ثورانًا انسيابيًّا هادئًا، وهذا هو الخلط الشائع بين النوعين.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2f0aef35-b057-5f8b-b7ef-6420a0ef20c8', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'أيّ المجموعات التالية تمثّل المقذوفات البركانية الثلاثة؟', '[{"id":"a","text":"موادّ سائلة (لابة) + موادّ غازية + موادّ صلبة (رماد وكُتل)"},{"id":"b","text":"ماء + هواء + تراب فقط"},{"id":"c","text":"غازات فقط لا غير"},{"id":"d","text":"صخور صلبة باردة فقط"}]'::jsonb, 'a', 'يقذف البركان ثلاثة أصناف: موادّ سائلة (اللابة)، وموادّ غازية (بخار الماء وثاني أكسيد الكربون وغيرها)، وموادّ صلبة (الرماد والحصى والقنابل البركانية). فحصْرها في الغازات وحدها أو الصخور الباردة وحدها غير صحيح.', 7, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1deecf3f-237a-5fb9-91b7-3d550ac1456b', '9b5651b1-1a26-5a20-baa1-d7a19a32cd94', 'كيف تتوزّع البراكين على سطح الأرض؟', '[{"id":"a","text":"توزّعًا عشوائيًّا متساويًا في كلّ مكان"},{"id":"b","text":"في المناطق القطبية الباردة فقط"},{"id":"c","text":"تتركّز على طول حدود الصفائح التكتونية (مثل حزام النار حول المحيط الهادئ)"},{"id":"d","text":"في وسط القارّات بعيدًا عن أيّ حدود"}]'::jsonb, 'c', 'لا تتوزّع البراكين عشوائيًّا، بل تتركّز أساسًا على حدود الصفائح التكتونية، وأشهرها حزام النار المحيط بالمحيط الهادئ. هذا التركّز يدلّ على ارتباط النشاط البركاني بحركة الصفائح، فلا يصحّ القول إنّه عشوائي أو محصور في القطبين.', 8, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

