INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2e1eb424-4dcd-5f84-a9db-0cf9938f6633', '2eed667c-8445-52e3-93cd-5803e6592d72', 'القناة الشاقولية التي تصعد عبرها الموادّ من الخزّان الصهاري نحو السطح تُسمّى:', '[{"id":"a","text":"الفوّهة"},{"id":"b","text":"المدخنة (المجرى)"},{"id":"c","text":"المخروط البركاني"},{"id":"d","text":"الخزّان الصهاري"}]'::jsonb, 'b', 'المدخنة هي القناة التي تصعد فيها الموادّ من الخزّان الصهاري إلى الفوّهة. الفوّهة هي الفتحة العلوية التي تخرج منها المقذوفات، والخزّان مكان تجمّع الصهارة في العمق، والمخروط هو الجبل المتراكم خارجًا؛ فلا ينطبق أيّ منها على قناة الصعود.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('91872dd1-5150-522b-929d-f457bc287302', '2eed667c-8445-52e3-93cd-5803e6592d72', 'الفتحة العلوية للبركان التي تخرج منها المقذوفات تُسمّى:', '[{"id":"a","text":"الخزّان الصهاري"},{"id":"b","text":"المدخنة"},{"id":"c","text":"الفوّهة"},{"id":"d","text":"اللابة"}]'::jsonb, 'c', 'الفوّهة هي الفتحة العلوية للبركان التي تخرج منها اللابة والغازات والموادّ الصلبة. الخزّان والمدخنة يقعان تحت الفوّهة، واللابة مادّة لا جزء من بنية البركان.', 2, 'mcq', NULL, NULL)
