  ('058d7fe8-2ddc-5ef2-9f17-cf1840b56532', '2eed667c-8445-52e3-93cd-5803e6592d72', 'الجبل المخروطي الذي يتكوّن من تراكم المقذوفات حول الفوّهة يُسمّى:', '[{"id":"a","text":"الخزّان الصهاري"},{"id":"b","text":"المخروط البركاني"},{"id":"c","text":"المدخنة"},{"id":"d","text":"الصهارة"}]'::jsonb, 'b', 'تراكم المقذوفات (لابة ورماد وكُتل) حول الفوّهة عبر الزمن يبني المخروط البركاني ذا الشكل الجبلي. الخزّان والمدخنة في العمق، والصهارة مادّة وليست بنية.', 5, 'mcq', NULL, NULL)
