  ('87d0c151-b937-5a15-aa00-ff95b7c8c531', '2eed667c-8445-52e3-93cd-5803e6592d72', 'أيّ ترتيب يصف صعود الموادّ في البركان من العمق إلى السطح صعودًا صحيحًا؟', '[{"id":"a","text":"الفوّهة ← المدخنة ← الخزّان الصهاري"},{"id":"b","text":"المدخنة ← الفوّهة ← الخزّان الصهاري"},{"id":"c","text":"الخزّان الصهاري ← المدخنة ← الفوّهة"},{"id":"d","text":"الخزّان الصهاري ← الفوّهة ← المدخنة"}]'::jsonb, 'c', 'تبدأ الموادّ من الخزّان الصهاري في العمق، ثمّ تصعد عبر المدخنة، فتخرج أخيرًا من الفوّهة إلى السطح. أيّ ترتيب يضع الفوّهة قبل المدخنة أو الخزّان في الأعلى يعكس مسار الصعود الحقيقي.', 6, 'mcq', NULL, NULL)
