INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('90d644e7-11db-5627-9a31-b5a8d55b3ac0', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'أيّ ممّا يلي من المقذوفات الصلبة للبركان؟', '[{"id":"a","text":"اللابة السائلة"},{"id":"b","text":"بخار الماء"},{"id":"c","text":"الرماد البركاني والقنابل البركانية"},{"id":"d","text":"ثاني أكسيد الكربون"}]'::jsonb, 'c', 'الرماد البركاني والكُتل الصخرية (القنابل البركانية) هي موادّ صلبة مقذوفة. اللابة مادّة سائلة، وبخار الماء وثاني أكسيد الكربون موادّ غازية، فهي لا تُعدّ مقذوفات صلبة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a2962615-64e1-5d14-b588-f291251efb4d', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'العامل الأساسي الذي يحدّد ما إذا كان الثوران هادئًا أم انفجاريًّا هو:', '[{"id":"a","text":"لون المخروط البركاني"},{"id":"b","text":"ارتفاع الجبل البركاني فقط"},{"id":"c","text":"لزوجة الصهارة وكمّية الغازات فيها"},{"id":"d","text":"الوقت من السنة"}]'::jsonb, 'c', 'طبيعة الثوران تتوقّف على لزوجة الصهارة وكمّية الغازات: الصهارة السائلة القليلة الغازات تعطي ثورانًا هادئًا، واللزجة الغنيّة بالغازات تعطي ثورانًا انفجاريًّا. أمّا لون المخروط أو ارتفاعه أو الفصل فلا علاقة لها بنوع الثوران.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4215d9f8-e89a-5df6-b234-824021e596fe', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'تتركّز معظم براكين العالم النشطة على طول:', '[{"id":"a","text":"خطّ الاستواء فقط"},{"id":"b","text":"حدود الصفائح التكتونية (مثل حزام النار حول المحيط الهادئ)"},{"id":"c","text":"وسط الصحاري الكبرى"},{"id":"d","text":"القطبين الشمالي والجنوبي"}]'::jsonb, 'b', 'ترتبط البراكين بحركة الصفائح، لذلك تتركّز على حدودها، وأشهر تجمّع هو حزام النار حول المحيط الهادئ. لا علاقة لتوزّعها بخطّ الاستواء أو الصحاري أو القطبين.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4f0bc02e-9def-5196-ab64-16519288cc10', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'أيّ زوج يربط نوع الصهارة بنوع الثوران ربطًا صحيحًا؟', '[{"id":"a","text":"صهارة سائلة قليلة الغازات ← ثوران انفجاري"},{"id":"b","text":"صهارة لزجة غنيّة بالغازات ← ثوران هادئ"},{"id":"c","text":"صهارة لزجة غنيّة بالغازات ← ثوران انفجاري"},{"id":"d","text":"صهارة باردة صلبة ← ثوران هادئ"}]'::jsonb, 'c', 'الصهارة اللزجة الغنيّة بالغازات تسدّ المدخنة ويتراكم الضغط فيحدث ثوران انفجاري، بينما الصهارة السائلة القليلة الغازات تعطي ثورانًا هادئًا. لذلك ربط السائلة بالانفجار أو اللزجة بالهدوء خلط شائع بين النوعين، والصهارة الباردة الصلبة لا تثور أصلًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9035b2de-9933-55e8-a9ea-1f34c6a24c87', '6c750cda-b071-5a1b-aaa4-20510a92cdee', 'أيّ مقذوف بركاني يُعدّ خطرًا كبيرًا على حركة الطيران ويمتدّ أثره إلى مسافات بعيدة؟', '[{"id":"a","text":"اللابة السائلة"},{"id":"b","text":"الرماد البركاني المتطاير في الجوّ"},{"id":"c","text":"المخروط البركاني"},{"id":"d","text":"الخزّان الصهاري"}]'::jsonb, 'b', 'الرماد البركاني الدقيق يتطاير ويرتفع في الجوّ وينتشر لمسافات بعيدة، فيُعطّل حركة الطيران ويخنق الكائنات ويلوّث الهواء. اللابة خطرها محلّي حول البركان، والمخروط والخزّان عنصران من بنية البركان لا مقذوفات متطايرة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2d7eca62-3226-5a2d-8889-aabec2c0455f', '43b4902b-3f94-5a0b-98f9-019bf0a28685', 'sciences-vie-terre', '⚔️ زعيم الفصل: البراكين', 3, 120, 30, 'boss', 'admin', 3)
