INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f3ccda48-8108-560a-ac1e-a9c88ec15449', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'تلميذ قال: «اللابة هي الصخر المنصهر داخل الخزّان الصهاري، والصهارة هي ما يخرج إلى السطح». ما الصواب؟', '[{"id":"a","text":"كلامه صحيح تمامًا"},{"id":"b","text":"العكس هو الصحيح: الصهارة في الباطن، واللابة ما يخرج إلى السطح"},{"id":"c","text":"الاسمان مترادفان ولا فرق بينهما"},{"id":"d","text":"كلاهما يوجد في الجوّ فقط"}]'::jsonb, 'b', 'التلميذ عكس المفهومين: الصهارة (Magma) هي الصخر المنصهر المحمّل بالغازات في باطن الأرض، واللابة (Lave) هي الصهارة نفسها بعد خروجها إلى السطح وفقدها معظم غازاتها. وهما ليسا مترادفين تمامًا لأنّ الموقع وكمّية الغازات تختلف، ولا يوجدان في الجوّ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('58e6ae8a-7817-57f7-b9b6-0848595b0089', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'بركان صهارته لزجة جدًّا وغنيّة بالغازات. ما السلوك المتوقّع لثورانه ولماذا؟', '[{"id":"a","text":"ثوران هادئ لأنّ اللابة ستسيل بسهولة"},{"id":"b","text":"ثوران انفجاري لأنّ اللزوجة تَسُدّ المدخنة فيتراكم ضغط الغازات حتى ينفجر"},{"id":"c","text":"لن يثور أبدًا لأنّ الصهارة لزجة"},{"id":"d","text":"سيُخرج ماءً عذبًا فقط"}]'::jsonb, 'b', 'اللزوجة العالية تعيق صعود الصهارة فتَسُدّ المدخنة، ومع غناها بالغازات يتراكم الضغط حتى ينفجر البركان قاذفًا رمادًا وكُتلًا وسُحبًا حارقة. فالصهارة اللزجة الغنيّة بالغازات لا تعطي ثورانًا هادئًا، وهي تثور بعنف لا أنّها لا تثور.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a93265fd-b2b3-5a76-9491-ba4afd59a9d8', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'لماذا تتراصف البراكين والزلازل غالبًا في الأحزمة نفسها على الكرة الأرضية؟', '[{"id":"a","text":"لأنّها ظواهر عشوائية بحتة"},{"id":"b","text":"لأنّ كليهما مرتبط بحركة الصفائح التكتونية على حدودها"},{"id":"c","text":"لأنّها تحدث فقط في المناطق الباردة"},{"id":"d","text":"لأنّ سبب البراكين هو المطر الغزير"}]'::jsonb, 'b', 'تتركّز البراكين والزلازل على حدود الصفائح لأنّ كليهما من مظاهر النشاط الباطني المرتبط بحركة هذه الصفائح وتفاعلها (تقارب وتباعد). فالأمر ليس عشوائيًّا ولا مرتبطًا بالبرودة أو المطر.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a331edff-ffe9-58f7-869f-9561a036e357', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'أيّ مقارنة بين الثوران الانسيابي والانفجاري صحيحة؟', '[{"id":"a","text":"الانسيابي مخروطه منبسط وحممه سائلة، والانفجاري أعنف ويقذف رمادًا وكُتلًا"},{"id":"b","text":"الانسيابي هو الأخطر دائمًا، والانفجاري لا يقذف شيئًا"},{"id":"c","text":"كلاهما يقذف لابة سائلة فقط دون غازات"},{"id":"d","text":"الانفجاري حممه سائلة تسيل بهدوء بعيدًا"}]'::jsonb, 'a', 'الثوران الانسيابي ناتج عن صهارة سائلة تعطي مخروطًا منبسطًا وحممًا تسيل بهدوء، أمّا الانفجاري فأعنف ويقذف رمادًا وكُتلًا وسُحبًا حارقة وهو الأخطر. فلا يصحّ نسبة الخطورة الأكبر للانسيابي ولا نسبة السيلان الهادئ للانفجاري.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('737a946e-6748-551e-8d47-63dfb113feb4', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'تجمّعت سحابة من الرماد البركاني الدقيق وانتشرت لمئات الكيلومترات بعد ثوران. أيّ المخاطر التالية الأكثر ارتباطًا بهذه السحابة؟', '[{"id":"a","text":"خصوبة فورية للتربة دون أيّ ضرر"},{"id":"b","text":"تعطيل حركة الطيران واختناق الكائنات وتلوّث الهواء"},{"id":"c","text":"تبريد سطح الأرض إلى درجة التجمّد فورًا"},{"id":"d","text":"توليد الكهرباء مباشرةً للمنازل"}]'::jsonb, 'b', 'الرماد المتطاير الدقيق يعطّل محرّكات الطائرات ويعيق الرؤية ويخنق الكائنات الحيّة ويلوّث الهواء عبر مسافات بعيدة، وهذه من أخطر آثار البراكين الانفجارية. أمّا خصوبة التربة فأثر لاحق طويل الأمد لا يلغي الخطر، والرماد لا يجمّد الأرض فورًا ولا يولّد كهرباء مباشرة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c21355cf-f901-5dc2-8890-42c54d1f1da7', '2d7eca62-3226-5a2d-8889-aabec2c0455f', 'وُجد في إقليم تربة بركانية خصبة وينابيع مياه ساخنة ومحطّة طاقة جيوحرارية. ما العلاقة الصحيحة بهذه المعطيات؟', '[{"id":"a","text":"هي كلّها من فوائد النشاط البركاني للإنسان"},{"id":"b","text":"هي كلّها أضرار يجب التخلّص منها"},{"id":"c","text":"لا علاقة لها بالبراكين إطلاقًا"},{"id":"d","text":"هي دليل على غياب أيّ نشاط باطني"}]'::jsonb, 'a', 'التربة البركانية الخصبة والمياه الساخنة والطاقة الجيوحرارية كلّها من فوائد النشاط البركاني التي يستثمرها الإنسان. فهي ليست أضرارًا، ووجودها مرتبط مباشرةً بالنشاط الباطني البركاني لا دليلًا على غيابه.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

