INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6f6bb2dd-68da-59a1-b432-76024b357baa', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'بركانان: الأوّل مخروطه شديد الانحدار وثوراناته تقذف رمادًا وكُتلًا بعنف، والثاني مخروطه منبسط واسع وحممه تسيل بهدوء لمسافات بعيدة. ما الاستنتاج الأصحّ حول صهارة كلّ منهما؟', '[{"id":"a","text":"صهارة الأوّل لزجة غنيّة بالغازات، وصهارة الثاني سائلة قليلة الغازات"},{"id":"b","text":"صهارة الأوّل سائلة قليلة الغازات، وصهارة الثاني لزجة غنيّة بالغازات"},{"id":"c","text":"صهارتهما متطابقتان والفرق صدفة فقط"},{"id":"d","text":"لا علاقة بين شكل المخروط ونوع الصهارة"}]'::jsonb, 'a', 'المخروط الشديد الانحدار مع القذف العنيف يدلّ على صهارة لزجة غنيّة بالغازات (ثوران انفجاري)، بينما المخروط المنبسط مع سيلان الحِمم بهدوء يدلّ على صهارة سائلة قليلة الغازات (ثوران انسيابي). فشكل المخروط وسلوك الثوران مرتبطان مباشرةً بطبيعة الصهارة لا بالصدفة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e127f7d2-ed74-5711-aab1-ef76138e83dc', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'خريطة عالمية تُظهر تطابقًا كبيرًا بين مواقع البراكين النشطة ومواقع الزلازل القوية على شكل أحزمة. ما التفسير العلمي لهذا التطابق؟', '[{"id":"a","text":"الزلازل هي التي تنتج البراكين بشكل مباشر"},{"id":"b","text":"كلتا الظاهرتين من مظاهر النشاط الباطني المرتبط بحركة الصفائح على حدودها"},{"id":"c","text":"التطابق محض مصادفة لا معنى لها"},{"id":"d","text":"البراكين تتبع توزّع المدن الكبرى"}]'::jsonb, 'b', 'تطابق أحزمة البراكين والزلازل يُفسَّر بأنّ كليهما من مظاهر النشاط الباطني عند حدود الصفائح التكتونية حيث تتفاعل الصفائح (تقاربًا وتباعدًا). فليست الزلازل سببًا مباشرًا في توليد البراكين، والتطابق ليس مصادفة ولا علاقة له بتوزّع المدن.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('aa94d3c6-f437-5122-95f0-91b8ae58ae4e', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'لاحظ سكّان أنّ غازات البركان وبخار الماء تتصاعد بهدوء من الفوّهة لأسابيع دون قذف رماد أو كُتل، وأنّ سطح الحمم في الفوّهة سائل ومتوهّج. ما النوع الأرجح لهذا البركان؟', '[{"id":"a","text":"بركان انفجاري شديد الخطورة على وشك الانفجار حتمًا"},{"id":"b","text":"بركان انسيابي هادئ صهارته سائلة تسمح بتحرّر الغازات تدريجيًّا"},{"id":"c","text":"بركان خامد لا نشاط فيه إطلاقًا"},{"id":"d","text":"ليس بركانًا بل مجرّد ينبوع ماء ساخن"}]'::jsonb, 'b', 'تحرّر الغازات تدريجيًّا بهدوء ووجود حمم سائلة متوهّجة دون قذف عنيف مؤشّرات على ثوران انسيابي هادئ، لأنّ الصهارة السائلة تسمح للغازات بالإفلات دون تراكم ضغط انفجاري. فلا يدلّ ذلك على انفجار حتمي، ووجود نشاط ظاهر ينفي كونه خامدًا أو مجرّد ينبوع.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('819005be-7c71-5cfd-9b1e-4959abc4c98d', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'بعد سنوات من ثوران انفجاري، أصبحت أراضي المنطقة من أخصب الأراضي الزراعية رغم الدمار الذي خلّفه الثوران. ما التفسير العلمي الذي يجمع بين الضرر والفائدة؟', '[{"id":"a","text":"البراكين مفيدة فقط ولا ضرر لها على الإطلاق"},{"id":"b","text":"البراكين ضارّة فقط، والخصوبة لا علاقة لها بها"},{"id":"c","text":"للبركان مخاطر آنية (دمار ورماد) وفوائد لاحقة كإغناء التربة بالمعادن من موادّه"},{"id":"d","text":"الخصوبة سببها توقّف المطر بعد الثوران"}]'::jsonb, 'c', 'للبراكين وجهان: مخاطر آنية (دمار وحرائق ورماد) وفوائد لاحقة، إذ تغني موادّ البركان (الرماد واللابة المتحلّلة) التربة بالمعادن فتجعلها خصبة مع الزمن. فلا يصحّ حصْره في الفائدة وحدها أو الضرر وحده، والخصوبة سببها معادن البركان لا توقّف المطر.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5717bc09-d510-5b10-8363-d57b551b158c', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'لماذا تكون اللابة الخارجة من البركان أفقر بالغازات من الصهارة التي كانت في الخزّان الصهاري؟', '[{"id":"a","text":"لأنّ الغازات تتحرّر وتنطلق إلى الجوّ أثناء صعود الصهارة وخروجها إلى السطح"},{"id":"b","text":"لأنّ الصهارة تكتسب غازات إضافية عند الخروج"},{"id":"c","text":"لأنّ اللابة لا تحتوي غازات أصلًا في أيّ مرحلة"},{"id":"d","text":"لأنّ الخزّان الصهاري لا يحتوي أيّ غازات"}]'::jsonb, 'a', 'مع انخفاض الضغط أثناء صعود الصهارة نحو السطح تتحرّر الغازات الذائبة وتنطلق إلى الجوّ، فتخرج اللابة وقد فقدت معظم غازاتها. فالصهارة لا تكتسب غازات عند الخروج، والخزّان غنيّ بالغازات أصلًا، وهي السبب في ذلك الفرق.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('40ec4025-fa54-56d3-b309-a256d5da58ff', 'ed7f3893-2d09-5646-9952-83b2d24d51a0', 'مدينتان قرب بركان واحد: الأولى في وادٍ منخفض على مسار سيلان الحمم، والثانية على مرتفع بعيد لكنّها في اتّجاه الرياح السائدة. أيّ خطر أبرز يهدّد كلّ مدينة؟', '[{"id":"a","text":"الأولى تهدّدها الحمم السائلة، والثانية يهدّدها الرماد المتطاير الذي تحمله الرياح"},{"id":"b","text":"الأولى يهدّدها الرماد فقط، والثانية الحمم فقط"},{"id":"c","text":"لا خطر على أيّ منهما ما دامتا قرب البركان"},{"id":"d","text":"كلتاهما مهدّدة فقط بالزلازل لا بالبركان"}]'::jsonb, 'a', 'الحمم السائلة تنحدر مع الجاذبية نحو المناطق المنخفضة فتهدّد المدينة في الوادي، بينما الرماد المتطاير الدقيق تحمله الرياح إلى المناطق الواقعة في اتّجاهها ولو كانت بعيدة ومرتفعة، فيهدّد المدينة الثانية. فلا يصحّ عكس الخطرين ولا نفيهما، والخطر هنا بركاني لا زلزالي.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

