INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('19de6d1c-e98c-5f0d-a4aa-3cab98f0e1f2', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'ما الفرق الصحيح بين الصهارة (le magma) واللابة (la lave)؟', '[{"id":"a","text":"الصهارة صخر منصهر داخل الأرض، واللابة هي الصهارة بعد خروجها إلى السطح"},{"id":"b","text":"اللابة داخل الخزّان والصهارة على السطح"},{"id":"c","text":"هما اسمان لغازات بركانية"},{"id":"d","text":"الصهارة صلبة دائمًا واللابة سائلة دائمًا داخل الأرض"}]'::jsonb, 'a', 'الصهارة صخر منصهر يوجد في باطن الأرض (في الخزّان الصهاري)، وعندما تخرج إلى السطح عبر الفوّهة تُسمّى لابة. فالعبارة (ب) معكوسة، وهما ليستا غازات، والصهارة ليست صلبة بل منصهرة في الباطن.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6d8dd85a-44f3-5d4f-a156-e2b44dba1e89', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'أيّ هذه المكوّنات يمثّل جزءًا من بنية البركان؟', '[{"id":"a","text":"الخزّان الصهاري والمدخنة والفوّهة"},{"id":"b","text":"البؤرة والمركز السطحي"},{"id":"c","text":"الليثوسفير والأسثينوسفير فقط"},{"id":"d","text":"النواة والوشاح فقط"}]'::jsonb, 'a', 'يتكوّن البركان من خزّان صهاري في العمق تصعد منه الصهارة عبر مدخنة لتخرج من فوّهة في القمّة. البؤرة والمركز السطحي مصطلحان خاصّان بالزلازل، والليثوسفير والوشاح والنواة طبقات الأرض لا أجزاء بنية البركان نفسه.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b40d85ce-4f72-5e76-ad6a-66a431625b5c', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'بركان صهارته لزجة جدًّا وغنيّة بالغازات. ما نوع ثورانه المتوقّع؟', '[{"id":"a","text":"ثوران انفجاري عنيف لأنّ الغازات تُحتجَز في صهارة لزجة ثمّ تنطلق فجأةً"},{"id":"b","text":"ثوران انسيابي هادئ تسيل فيه اللابة ببطء"},{"id":"c","text":"لا يثور أبدًا"},{"id":"d","text":"يخرج ماءً فقط دون لابة"}]'::jsonb, 'a', 'اللزوجة العالية تحبس الغازات داخل الصهارة فيرتفع الضغط حتّى تنفجر فجأةً (ثوران انفجاري) مع قذف رماد ومواد صلبة. أمّا الثوران الانسيابي الهادئ فيخصّ الصهارة السيّالة قليلة الغازات، والقول إنّه لا يثور أو يخرج ماءً فقط غير صحيح.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fd260756-dd88-59d3-b13e-8124a4a396df', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'ما المقذوفات التي يطرحها البركان أثناء الثوران؟', '[{"id":"a","text":"لابة وغازات ومواد صلبة (رماد وقذائف صخرية)"},{"id":"b","text":"ماء عذب فقط"},{"id":"c","text":"هواء بارد فقط"},{"id":"d","text":"صخور رسوبية مترسّبة من البحر"}]'::jsonb, 'a', 'تشمل المقذوفات البركانية اللابة السائلة والغازات والمواد الصلبة من رماد وقذائف صخرية. البركان لا يطرح ماءً عذبًا أو هواءً باردًا، والصخور الرسوبية تتكوّن بالترسّب لا بالثوران البركاني.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('87a5769e-52d0-5d9f-8c58-7dc27461d63b', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'لماذا تتراصف معظم البراكين والزلازل في الأحزمة نفسها على الكرة الأرضية؟', '[{"id":"a","text":"لأنّها ترتبط معًا بحدود الصفائح التكتونية حيث يكثر النشاط الباطني"},{"id":"b","text":"بمحض الصدفة دون سبب"},{"id":"c","text":"لأنّ الأمطار تتركّز في تلك المناطق"},{"id":"d","text":"لأنّها تتبع خطوط الطول والعرض"}]'::jsonb, 'a', 'تتركّز البراكين والزلازل عند حدود الصفائح التكتونية لأنّ حركة الصفائح هناك تتيح صعود الصهارة وتراكم الإجهادات، فيتراصفان في الأحزمة نفسها (مثل حزام النار). فليس الأمر صدفةً ولا مرتبطًا بالأمطار أو بخطوط الطول والعرض.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
