  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('19c75169-488f-5a87-baef-d5527ce47843', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'وُجد في إقليم تربة بركانية خصبة وينابيع ماء ساخنة ومحطّة طاقة جيوحرارية. ما العلاقة الصحيحة؟', '[{"id":"a","text":"أنّها فوائد مرتبطة بالنشاط البركاني والحرارة الباطنية"},{"id":"b","text":"أنّها أدلّة على غياب أيّ نشاط بركاني"},{"id":"c","text":"أنّها مجرّد صدف لا علاقة بينها"},{"id":"d","text":"أنّها مخاطر فقط دون أيّ فائدة"}]'::jsonb, 'a', 'للنشاط البركاني فوائد: التربة البركانية خصبة للزراعة، والحرارة الباطنية تسخّن المياه فتنشأ ينابيع ساخنة وتُستغلّ في الطاقة الجيوحرارية. فهذه المعطيات مترابطة بالنشاط البركاني لا دليل غيابه ولا صدفة، وللبراكين فوائد إلى جانب مخاطرها.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
