INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('117d410e-235f-5db7-8cf0-f9fde24aec14', '390b5908-2cee-5675-9e9a-cfe82c272674', 'بركان لابته سائلة قليلة اللزوجة تسيل بسهولة على المنحدرات. ما نوع ثورانه غالبًا؟', '[{"id":"a","text":"انسيابيّ (هادئ) ذو سيَلانات حممية"},{"id":"b","text":"انفجاريّ عنيف يقذف الكتل والرماد"},{"id":"c","text":"لا يثور إطلاقًا"},{"id":"d","text":"يعتمد على حالة الطقس"}]'::jsonb, 'a', 'اللابة السائلة قليلة اللزوجة تسمح للغازات بالإفلات بسهولة، فيكون الثوران انسيابيًّا هادئًا تسيل فيه الحمم (كبراكين هاواي). ✓ الخطأ الشائع: ربط اللابة السائلة بالثوران الانفجاريّ — العكس هو الصحيح، فالانفجار مرتبط باللابة اللزجة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cad51dac-5c25-566d-9efa-1a45b0544291', '390b5908-2cee-5675-9e9a-cfe82c272674', 'قال تلميذ: «البراكين ذات اللابة السائلة جدًّا هي الأكثر انفجارًا وخطرًا على المناطق القريبة». ما الخطأ؟', '[{"id":"a","text":"اللابة السائلة تُنتج ثورانًا انسيابيًّا هادئًا؛ الانفجار العنيف مرتبط باللابة اللزجة الحابسة للغاز"},{"id":"b","text":"لا خطأ، اللابة السائلة هي الأكثر انفجارًا"},{"id":"c","text":"كلّ اللابات متساوية في العنف"},{"id":"d","text":"اللابة السائلة لا تخرج من البركان أصلًا"}]'::jsonb, 'a', 'درجة الانفجار تحدّدها اللزوجة ومحتوى الغاز: اللابة السائلة تُفلت غازاتها فتسيل بهدوء (انسيابيّ)، بينما اللزجة تحبس الغاز فتنفجر بعنف. فالخطر الانفجاريّ مرتبط باللزوجة لا بالسيولة. (تمرين «صيد الخطأ».) الخطأ الشائع: عكس العلاقة بين لزوجة اللابة ونوع الثوران.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('294dd26e-db15-526d-8d8f-b3ba4dd1d9e7', '390b5908-2cee-5675-9e9a-cfe82c272674', 'لماذا تكون ثورانات البراكين ذات اللابة اللزجة انفجاريةً عنيفةً عادةً؟', '[{"id":"a","text":"لأنّ اللزوجة تحبس الغازات فيرتفع الضغط حتى ينفجر فجأةً"},{"id":"b","text":"لأنّ اللابة اللزجة أبرد من أن تسيل فتتجمّد بهدوء"},{"id":"c","text":"لأنّ اللابة اللزجة خالية تمامًا من الغازات"},{"id":"d","text":"لأنّ اللزوجة تجعل اللابة تسيل أسرع"}]'::jsonb, 'a', 'اللابة اللزجة تعيق إفلات الغازات المذابة، فتتراكم وتزداد الضغط داخل المدخنة حتى يتحرّر فجأةً في ثوران انفجاريّ يقذف الرماد والكتل. ✓ الخطأ الشائع: ظنّ اللابة اللزجة خاليةً من الغاز؛ الغاز موجود لكنّه محبوس، وهو سبب العنف.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('791d3ff9-7802-5aea-9fd2-361f136a47ff', '390b5908-2cee-5675-9e9a-cfe82c272674', 'براكين الظهرات المحيطية (حدود متباعدة) لابتها بازلتية سائلة، وبراكين مناطق الطمر (حدود متقاربة) لابتها لزجة غنيّة بالغازات. أيّ نوعٍ من الحدود يُنتج غالبًا الثورانات الانفجارية الخطيرة؟', '[{"id":"a","text":"الحدود المتقاربة (مناطق الطمر)"},{"id":"b","text":"الحدود المتباعدة (الظهرات المحيطية)"},{"id":"c","text":"لا فرق بين نوعَي الحدود"},{"id":"d","text":"وسط الصفائح بعيدًا عن الحدود"}]'::jsonb, 'a', 'عند الحدود المتقاربة (الطمر) تنشأ صهارة لزجة غنيّة بالغازات، فثوراناتها انفجارية عنيفة. أمّا الظهرات المتباعدة فلابتها بازلتية سائلة وثوراناتها انسيابية هادئة. ✓ الخطأ الشائع: نسب الثوران الانفجاريّ إلى نوع الحدّ الخطأ (الظهرات بدل الطمر).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('14de9d9e-6d36-51b3-b5c7-8888bcfd126d', '390b5908-2cee-5675-9e9a-cfe82c272674', 'قبل ثورانٍ بركانيّ، رصدت المراصد المؤشّرات التالية مجتمعةً: تزايد الزلازل الصغيرة، وانتفاخ (تشوّه) سطح البركان، وارتفاع انبعاث الغازات. علامَ تدلّ هذه المؤشّرات معًا؟', '[{"id":"a","text":"صعود الصهارة نحو السطح واحتمال ثوران وشيك"},{"id":"b","text":"خمود البركان خمودًا نهائيًّا"},{"id":"c","text":"زلزال تكتونيّ لا علاقة له بالبركان"},{"id":"d","text":"لا دلالة لهذه المؤشّرات على النشاط البركانيّ"}]'::jsonb, 'a', 'صعود الصهارة يُحدث كسورًا صغيرة (زلازل دقيقة)، ويدفع سطح البركان فينتفخ، ويُطلق غازات متزايدة؛ فاجتماع هذه المؤشّرات ينذر بثوران وشيك، وعليه يقوم الرصد البركانيّ في الوقاية. (تمرين تحليل مؤشّرات.) ✓ الخطأ الشائع: تفسير كلّ مؤشّر منفصلًا وإهمال دلالتها المجتمعة على صعود الصهارة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('66cd4ee7-e070-5001-9339-958bd93cdcb2', '390b5908-2cee-5675-9e9a-cfe82c272674', 'رغم أنّ سيَلان الحمم بطيء نسبيًّا يمكن تفاديه أحيانًا، لماذا تُعدّ الرماد والغازات البركانية خطرًا واسع النطاق؟', '[{"id":"a","text":"لأنّها تنتشر بعيدًا وبسرعة في الهواء فتهدّد التنفّس والطيران والمناطق البعيدة"},{"id":"b","text":"لأنّها أثقل من الحمم فتبقى في الفوّهة"},{"id":"c","text":"لأنّها لا تنتقل إلا مع سيَلان الحمم"},{"id":"d","text":"لأنّها غير سامّة وغير مؤثّرة أصلًا"}]'::jsonb, 'a', 'بخلاف الحمم البطيئة المحصورة في مسارها، ينتقل الرماد والغازات عبر الغلاف الجوّيّ لمسافات بعيدة وبسرعة، فيسبّب اختناقًا وتلوّثًا ويشلّ الملاحة الجوّية حتى بعيدًا عن البركان. ✓ الخطأ الشائع: حصر الخطر البركانيّ في الحمم فقط وإهمال انتشار الرماد والغاز.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

