INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a8ba0dd0-a06a-509c-a588-0e0d5cfee8a2', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ما ترتيب طبقات الكرة الأرضية من السطح نحو المركز؟', '[{"id":"a","text":"النواة ثمّ الوشاح ثمّ القشرة"},{"id":"b","text":"القشرة ثمّ الوشاح ثمّ النواة"},{"id":"c","text":"الوشاح ثمّ القشرة ثمّ النواة"},{"id":"d","text":"القشرة ثمّ النواة ثمّ الوشاح"}]'::jsonb, 'b', 'من السطح نحو العمق نجد: القشرة الأرضية (طبقة خارجية رقيقة صلبة)، ثمّ الوشاح (طبقة سميكة جدًّا)، ثمّ النواة في المركز. القشرة هي الأقرب إلينا والنواة هي الأعمق.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
