  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b5593f4a-b80d-5f5c-a5f9-8e3d3c487c73', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ما اسم القارّة العملاقة الواحدة التي افترض فاجنر أنّ القارّات انفصلت عنها؟', '[{"id":"a","text":"الأسثينوسفير"},{"id":"b","text":"الظهرة"},{"id":"c","text":"بانجيا (Pangée)"},{"id":"d","text":"الليثوسفير"}]'::jsonb, 'c', 'اقترح ألفريد فاجنر أنّ القارّات كانت ملتصقة في قارّة عملاقة واحدة سمّاها «بانجيا»، ثمّ تباعدت تدريجيًّا (نظرية انجراف القارّات).', 2, 'mcq', NULL, NULL)
