  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d41b4048-cd3f-5fb2-897c-d9de3e51430e', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'أين تتركّز معظم الزلازل والبراكين على سطح الأرض؟', '[{"id":"a","text":"في وسط الصفائح بعيدًا عن حدودها"},{"id":"b","text":"على حدود الصفائح التكتونية"},{"id":"c","text":"في النواة الداخلية فقط"},{"id":"d","text":"بشكل متساوٍ في كلّ مكان من الأرض"}]'::jsonb, 'b', 'تتركّز معظم الزلازل والبراكين على حدود الصفائح (الظهرات ومناطق الطمر) حيث تحتكّ الصفائح وتتحرّك، لا في وسطها. ومن أمثلة ذلك حزام النار المحيط بالمحيط الهادئ.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
