  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d917dacf-423c-52dc-ac0a-743e9cddf713', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ما الفرق بين القشرة القارّية والقشرة المحيطية؟', '[{"id":"a","text":"القشرة القارّية أرقّ وأكثر كثافة من المحيطية"},{"id":"b","text":"القشرة المحيطية أسمك وأقلّ كثافة من القارّية"},{"id":"c","text":"القشرة القارّية أسمك وأقلّ كثافة، والمحيطية أرقّ وأكثر كثافة"},{"id":"d","text":"لا فرق بينهما؛ هما طبقة واحدة"}]'::jsonb, 'c', 'القشرة القارّية سميكة (نحو 30–70 كم) وأقلّ كثافة (غرانيتية)، أمّا القشرة المحيطية فرقيقة (نحو 5–10 كم) وأكثر كثافة (بازلتية). هذا الفرق في الكثافة هو الذي يجعل القشرة المحيطية تغوص تحت القارّية عند الطمر.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('219e410f-acb9-568f-a714-090de5f57ba4', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ممّ يتكوّن الليثوسفير (الغلاف الصخري)؟', '[{"id":"a","text":"من القشرة وحدها"},{"id":"b","text":"من القشرة + الجزء العلوي الصلب من الوشاح"},{"id":"c","text":"من الوشاح والنواة معًا"},{"id":"d","text":"من الأسثينوسفير اللزج فقط"}]'::jsonb, 'b', 'الليثوسفير صلب ويشمل القشرة والجزء العلوي الصلب من الوشاح معًا، وهو المجزّأ إلى صفائح تكتونية. لذلك الصفيحة ليست القشرة وحدها.', 5, 'mcq', NULL, NULL)
