INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c5468bcb-f60a-5c91-9afc-5db6bdeb4a49', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'أيّ ممّا يلي يُعدّ دليلًا استند إليه فاجنر على انجراف القارّات؟', '[{"id":"a","text":"وجود المتحجّرات نفسها على قارّات تفصلها محيطات اليوم"},{"id":"b","text":"تساوي عدد سكّان القارّات"},{"id":"c","text":"تشابه ألوان مياه المحيطات"},{"id":"d","text":"تساوي درجات الحرارة في كلّ القارّات"}]'::jsonb, 'a', 'من أدلّة فاجنر وجود متحجّرات لكائنات نفسها على قارّات متباعدة اليوم، إضافة إلى تطابق السواحل وتواصل الصخور والجبال. وهذا يدلّ على أنّ القارّات كانت ملتصقة سابقًا.', 6, 'mcq', NULL, NULL)
