INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cef65281-4f05-569e-b5e1-364a8ec75178', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'ماذا يحدث عند الظهرة المحيطية؟', '[{"id":"a","text":"تغوص صفيحة تحت أخرى وتختفي القشرة"},{"id":"b","text":"تتباعد صفيحتان ويصعد الصهير فيكوّن قشرة محيطية جديدة"},{"id":"c","text":"تتوقّف الصفائح عن الحركة نهائيًّا"},{"id":"d","text":"تلتصق القارّات ببعضها من جديد"}]'::jsonb, 'b', 'الظهرة المحيطية حدود متباعدة: تتباعد عندها صفيحتان فيصعد الصهير من الوشاح ويبرد مكوّنًا قشرة محيطية جديدة. هذه ظاهرة التوسّع المحيطي، وبها تكون القشرة أحدث عند الظهرة وأقدم كلّما ابتعدنا.', 7, 'mcq', NULL, NULL)
