INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9111412d-4b81-5ff8-9d9b-a2d421ad9169', '42259663-22a3-56ae-b44a-a0d2fe940ce8', 'في منطقة الطمر (الاندساس)، أيّ صفيحة تغوص تحت الأخرى؟', '[{"id":"a","text":"الصفيحة القارّية لأنّها أكثر كثافة"},{"id":"b","text":"الصفيحة المحيطية لأنّها أكثر كثافة"},{"id":"c","text":"الصفيحتان تصعدان معًا"},{"id":"d","text":"لا تغوص أيّ صفيحة"}]'::jsonb, 'b', 'عند تقارب صفيحتين تغوص الصفيحة المحيطية لأنّها أكثر كثافة من القارّية، فتندسّ داخل الوشاح. يصاحب ذلك خنادق محيطية وبراكين وزلازل قويّة عميقة.', 8, 'mcq', NULL, NULL)
