  ('c27846a2-6c7d-5135-8955-a22bc72311bf', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'بِمَ نسمّي الألواح الكبرى التي يتجزّأ إليها الليثوسفير؟', '[{"id":"a","text":"الصفائح التكتونية"},{"id":"b","text":"الظهرات المحيطية"},{"id":"c","text":"الخنادق"},{"id":"d","text":"المتحجّرات"}]'::jsonb, 'a', 'يتجزّأ الليثوسفير (الغلاف الصخري الصلب) إلى ألواح كبرى تُسمّى الصفائح التكتونية، وهي التي تتحرّك فوق الأسثينوسفير اللزج.', 3, 'mcq', NULL, NULL)
