  ('272fd3b3-f59c-52c1-977f-30885bde42e2', '5a756090-ebb6-5f89-a935-eb7f3b0462eb', 'من العالم الذي اقترح نظرية انجراف القارّات؟', '[{"id":"a","text":"نيوتن"},{"id":"b","text":"ألفريد فاجنر"},{"id":"c","text":"أينشتاين"},{"id":"d","text":"ريشتر"}]'::jsonb, 'b', 'اقترح العالم الألماني ألفريد فاجنر سنة 1912 نظرية انجراف القارّات. أمّا ريشتر فاسمه مرتبط بسلّم قياس مقدار الزلازل، وهو موضوع مختلف.', 4, 'mcq', NULL, NULL)
