INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7ed463fd-8a58-5a34-8195-976595ab172f', '9c3a8491-d576-5ff9-a1ca-630a74da760d', 'الظهرة المحيطية هي:', '[{"id":"a","text":"خندق عميق تختفي عنده القشرة المحيطية"},{"id":"b","text":"سلسلة جبلية بركانية في وسط المحيط تتباعد عندها الصفائح"},{"id":"c","text":"سهل منبسط في قاع المحيط لا تحدث عنده أيّ ظاهرة"},{"id":"d","text":"منطقة تلتصق فيها القارّات"}]'::jsonb, 'b', 'الظهرة المحيطية سلسلة جبلية بركانية ضخمة وسط المحيط، تتباعد عندها صفيحتان وتتكوّن قشرة محيطية جديدة. الخيار (أ) يصف منطقة الطمر، والخلط بين الظهرة (تباعد) والطمر (تقارب) خطأ شائع.', 1, 'mcq', NULL, NULL)
