INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('58ff1f8a-787e-504e-81d3-09e279f4891e', '18baf7c2-8131-5080-bd1d-7995d53194db', 'وُجدت متحجّرات لنبات بَرّي واحد على سواحل إفريقيا وأمريكا الجنوبية معًا. ما أفضل تفسير لذلك؟', '[{"id":"a","text":"النبات عبر المحيط سباحةً"},{"id":"b","text":"القارّتان كانتا ملتصقتين ثمّ تباعدتا بانجراف القارّات"},{"id":"c","text":"صدفة لا معنى لها"},{"id":"d","text":"البذور حملتها الرياح عبر المحيط الأطلسي"}]'::jsonb, 'b', 'وجود المتحجّرات نفسها على قارّتين يفصلهما محيط اليوم دليل على أنّهما كانتا ملتصقتين (بانجيا) ثمّ تباعدتا، وهو جوهر استدلال فاجنر. النبات البرّي لا يعبر محيطًا سباحةً.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('266130a5-b359-5c2a-b3df-8aa6cf93fab9', '18baf7c2-8131-5080-bd1d-7995d53194db', 'لماذا تتركّز البراكين والزلازل العنيفة حول المحيط الهادئ («حزام النار»)؟', '[{"id":"a","text":"لأنّ مياهه أكثر سخونة"},{"id":"b","text":"لأنّه محاط بحدود صفائح ومناطق طمر نشطة"},{"id":"c","text":"لأنّه أبعد المحيطات عن الشمس"},{"id":"d","text":"لأنّ قاعه يخلو من الصفائح"}]'::jsonb, 'b', 'حزام النار يحيط بالمحيط الهادئ حيث تتعدّد حدود الصفائح ومناطق الطمر النشطة، فتتركّز عندها البراكين والزلازل العنيفة. سبب التركّز هو حركة الصفائح عند حدودها لا حرارة الماء.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ac6eed8d-e95d-5ce2-b65c-aa980c76d370', '18baf7c2-8131-5080-bd1d-7995d53194db', 'لماذا توصف القشرة المحيطية بأنّها «تتجدّد» باستمرار رغم قِدم الأرض؟', '[{"id":"a","text":"لأنّها تُنتَج عند الظهرات وتُستهلَك عند مناطق الطمر"},{"id":"b","text":"لأنّها لا تتحرّك إطلاقًا"},{"id":"c","text":"لأنّ الزلازل تكوّنها من جديد"},{"id":"d","text":"لأنّ القارّات تتحوّل إلى قشرة محيطية"}]'::jsonb, 'a', 'تُنتَج القشرة المحيطية عند الظهرات (توسّع محيطي) وتختفي داخل الوشاح عند مناطق الطمر، فتبقى أحدث بكثير من القشرة القارّية. هذا التوازن بين الإنتاج والاستهلاك يفسّر تجدّدها.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d6e89736-fa69-59bc-a679-16a09dfedc24', '18baf7c2-8131-5080-bd1d-7995d53194db', 'إذا اقتربت صفيحتان قارّيتان (كلاهما قشرة قارّية أخفّ)، فالنتيجة الأرجح:', '[{"id":"a","text":"غوص إحداهما بسهولة في الوشاح"},{"id":"b","text":"تصادم يرفع سلاسل جبلية ضخمة"},{"id":"c","text":"تكوّن ظهرة محيطية بينهما"},{"id":"d","text":"اختفاء القارّتين كليًّا"}]'::jsonb, 'b', 'لأنّ القشرة القارّية خفيفة لا تغوص بسهولة، يؤدّي تصادم صفيحتين قارّيتين إلى رفع وتجعّد القشرة وتكوّن سلاسل جبلية ضخمة (مثل جبال الهملايا). الطمر السهل يحدث للقشرة المحيطية الأكثر كثافة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('46270910-933b-5fee-be14-d078c48d0500', '18baf7c2-8131-5080-bd1d-7995d53194db', 'ما العنصر الذي عجز فاجنر عن تفسيره، وفسّرته لاحقًا نظرية تكتونية الصفائح؟', '[{"id":"a","text":"شكل القارّات"},{"id":"b","text":"وجود المتحجّرات"},{"id":"c","text":"القوّة المحرّكة التي تجعل القارّات تنجرف"},{"id":"d","text":"وجود المحيطات"}]'::jsonb, 'c', 'قدّم فاجنر أدلّة قويّة على الانجراف لكنّه لم يستطع تفسير محرّكه، فرُفضت نظريته في البداية. لاحقًا فسّرت تكتونية الصفائح المحرّك بتيّارات الحمل الحراري في الوشاح.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

