INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('35b85bd7-db2d-52e0-97c9-bb92e19322c2', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'قال تلميذ: «الصفيحة التكتونية هي القشرة الأرضية وحدها». ما تصحيح هذه العبارة؟', '[{"id":"a","text":"العبارة صحيحة تمامًا"},{"id":"b","text":"الصفيحة هي الوشاح كلّه"},{"id":"c","text":"الصفيحة جزء من الليثوسفير: القشرة + أعلى الوشاح الصلب"},{"id":"d","text":"الصفيحة هي الأسثينوسفير اللزج"}]'::jsonb, 'c', 'الصفيحة قطعة من الليثوسفير، أي القشرة مضافًا إليها الجزء العلوي الصلب من الوشاح، وليست القشرة وحدها. الخلط بين «الصفيحة» و«القشرة» خطأ شائع جدًّا، كما أنّ الأسثينوسفير لزج وليس جزءًا من الصفيحة الصلبة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8d88457b-ad82-5e6d-b3e5-e7489d611bfb', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'قاس باحث عمر القشرة المحيطية على جانبَي ظهرة فوجده يزداد بانتظام نحو الخارج على الجانبين. ما الاستنتاج الأدقّ؟', '[{"id":"a","text":"القشرة تتكوّن عند الظهرة وتنفصل عنها على الجانبين (توسّع محيطي متماثل)"},{"id":"b","text":"القشرة تغوص عند الظهرة"},{"id":"c","text":"الظهرة تستهلك القشرة القديمة"},{"id":"d","text":"عمر القشرة لا علاقة له بالظهرة"}]'::jsonb, 'a', 'ازدياد العمر بانتظام وبتماثل على الجانبين دليل على أنّ القشرة الجديدة تتكوّن عند محور الظهرة وتُدفع نحو الجانبين، أي توسّع محيطي متماثل. الظهرة تُنتج القشرة ولا تستهلكها (الاستهلاك يحدث عند الطمر).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d20538bc-6d99-5c48-a2f0-a7e4e2a91c64', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'تتقارب صفيحتان محيطيتان متساويتا الكثافة تقريبًا. أيّ نتيجة أكثر اتّساقًا مع آليّة الطمر؟', '[{"id":"a","text":"لا يحدث أيّ طمر إطلاقًا لأنّ الكثافتين متساويتان"},{"id":"b","text":"تغوص الصفيحة الأقدم (الأبرد والأكثر كثافة) تحت الأحدث"},{"id":"c","text":"تصعد الصفيحتان معًا وتكوّنان قارّة"},{"id":"d","text":"تتحوّل القشرة المحيطية إلى قارّية فورًا"}]'::jsonb, 'b', 'تزداد كثافة القشرة المحيطية مع تقادمها وبرودتها، فتغوص الصفيحة الأقدم (الأكثر كثافة) تحت الأحدث. فالطمر لا يتطلّب وجود قشرة قارّية، بل فرقًا في الكثافة قد ينشأ من فرق العمر/الحرارة.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6c1168cc-06f8-5fff-9a7d-fdb3b0fb65cc', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'في خريطة لتوزيع الزلازل، ظهرت بؤرها سطحيةً عند ظهرة محيطية، وعميقةً متدرّجةً مائلةً تحت قارّة مجاورة. كيف نفسّر ذلك؟', '[{"id":"a","text":"البؤر السطحية مرتبطة بالتباعد عند الظهرة، والعميقة المائلة برحلة الصفيحة الغائصة في الطمر"},{"id":"b","text":"كلّ الزلازل سطحية دائمًا"},{"id":"c","text":"البؤر العميقة سببها رياح سطحية"},{"id":"d","text":"لا علاقة بين عمق البؤر وحدود الصفائح"}]'::jsonb, 'a', 'عند الظهرة (تباعد) تكون البؤر سطحيةً، أمّا عند الطمر فتترتّب البؤر على مستوٍ مائل يزداد عمقًا مع غوص الصفيحة داخل الوشاح. هذا التوزيع المائل للبؤر العميقة من أقوى الأدلّة على الطمر.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('594633b4-9cdd-5d32-a408-1f3e35569cc3', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'لماذا لا يكفي تطابق سواحل القارّات وحده لإثبات الانجراف، فاحتاج فاجنر إلى أدلّة أخرى؟', '[{"id":"a","text":"لأنّ التطابق الشكلي قد يكون صدفة، فعزّزه بالمتحجّرات وتواصل الصخور والجبال"},{"id":"b","text":"لأنّ السواحل لا تتطابق أصلًا"},{"id":"c","text":"لأنّ التطابق الشكلي وحده يكفي تمامًا"},{"id":"d","text":"لأنّ المتحجّرات تنفي الانجراف"}]'::jsonb, 'a', 'التطابق الشكلي مؤشّر لكنّه قد يُفسَّر بالصدفة، لذلك دعّمه فاجنر بأدلّة مستقلّة: متحجّرات مشتركة وتواصل صخور وسلاسل جبلية بين القارّات. تضافر أدلّة من مصادر مختلفة يقوّي الاستنتاج العلمي.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('318810fa-5b8a-5549-b3f1-a7578f3d322e', '6788dd68-b99f-5ceb-b9c9-5dd67e628f6d', 'وضعية تركيبية: محيط تتوسّع ظهرته باستمرار بينما إحدى حوافّه منطقة طمر نشطة. ماذا يحدث لمساحة هذا المحيط على المدى الطويل إذا كان معدّل الطمر أكبر من معدّل التوسّع؟', '[{"id":"a","text":"تتقلّص مساحة المحيط لأنّ ما يُستهلَك عند الطمر أكبر ممّا يُنتَج عند الظهرة"},{"id":"b","text":"تتّسع مساحة المحيط حتمًا"},{"id":"c","text":"تبقى المساحة ثابتة دائمًا مهما كانت المعدّلات"},{"id":"d","text":"يختفي المحيط فورًا في لحظة واحدة"}]'::jsonb, 'a', 'مساحة المحيط محصّلة بين الإنتاج عند الظهرة والاستهلاك عند الطمر. إذا فاق معدّل الطمر معدّل التوسّع، تغلب خسارة القشرة على إنتاجها فتتقلّص مساحة المحيط تدريجيًّا (لا فورًا). هذا يفسّر انغلاق محيطات قديمة عبر العصور الجيولوجية.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

