INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('295cbe5d-8677-5de4-b81a-0047e0f7b765', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ما الترتيب الصحيح لطبقات الكرة الأرضية من السطح إلى المركز؟', '[{"id":"a","text":"القشرة ثمّ الوشاح ثمّ النواة"},{"id":"b","text":"النواة ثمّ القشرة ثمّ الوشاح"},{"id":"c","text":"الوشاح ثمّ النواة ثمّ القشرة"},{"id":"d","text":"القشرة ثمّ النواة ثمّ الوشاح"}]'::jsonb, 'a', 'تتكوّن الأرض من السطح إلى المركز من القشرة (الطبقة الخارجية الرقيقة) ثمّ الوشاح (الأسمك) ثمّ النواة في المركز. باقي الترتيبات تخلط بين مواقع الطبقات؛ فالنواة في المركز لا في الأعلى، والوشاح بين القشرة والنواة.', 1, 'mcq', NULL, NULL)
