  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4216a8ee-e2c9-5bb9-854e-d4560c74f331', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ما الليثوسفير (la lithosphère)؟', '[{"id":"a","text":"الطبقة الصلبة الخارجية المجزّأة إلى صفائح تكتونية"},{"id":"b","text":"نواة الأرض السائلة"},{"id":"c","text":"طبقة الغازات المحيطة بالأرض"},{"id":"d","text":"المحيطات وحدها"}]'::jsonb, 'a', 'الليثوسفير هو الغلاف الصلب الخارجي للأرض (القشرة وأعلى الوشاح) المجزّأ إلى صفائح تكتونية تطفو فوق الأسثينوسفير اللدن. وهو ليس النواة السائلة، ولا الغلاف الجوّي الغازي، ولا المحيطات وحدها.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('87cd9971-1945-5aca-9bc6-1bb6319f6c92', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ماذا يحدث عند الظهرات المحيطية (les dorsales)؟', '[{"id":"a","text":"تصعد الصهارة وتتكوّن قشرة محيطية جديدة فيتوسّع المحيط"},{"id":"b","text":"تُدمَّر القشرة المحيطية وتغوص في الوشاح"},{"id":"c","text":"تتوقّف الصفائح عن الحركة تمامًا"},{"id":"d","text":"تتكوّن الجبال القارّية فقط"}]'::jsonb, 'a', 'عند الظهرات المحيطية تصعد الصهارة وتبرد فتتكوّن قشرة محيطية جديدة تدفع الصفائح جانبًا فيتوسّع قعر المحيط. أمّا تدمير القشرة وغوصها فيحدث في مناطق الطمر (الاندساس) لا عند الظهرات، والصفائح هناك تتباعد لا تتوقّف.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('437ac1a1-b49e-5e32-bf73-75081e9bb4b5', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'صفيحة تحمل قشرة محيطية اقتربت من صفيحة تحمل قشرة قارّية. ماذا يحدث عند الحدّ بينهما؟', '[{"id":"a","text":"تغوص القشرة المحيطية الأثقل تحت القارّية في منطقة طمر (اندساس)"},{"id":"b","text":"تغوص القشرة القارّية الأخفّ تحت المحيطية"},{"id":"c","text":"تتباعدان وتتكوّن ظهرة جديدة"},{"id":"d","text":"لا يحدث أيّ تفاعل بينهما"}]'::jsonb, 'a', 'القشرة المحيطية أكثف وأثقل من القارّية، فعند تقاربهما تغوص المحيطية تحت القارّية في منطقة طمر (اندساس) مصحوبة بزلازل وبراكين. فلا تغوص القارّية الأخفّ، وهذا حدّ متقارب لا متباعد، والتفاعل واضح لا منعدم.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c6005ff6-2e9b-57a8-b869-4ee7ec9899fb', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'وُجدت متحجّرات لكائن واحد على سواحل إفريقيا وأمريكا الجنوبية معًا. ما أفضل تفسير لذلك؟', '[{"id":"a","text":"أنّ القارّتين كانتا متّصلتين سابقًا ثمّ تباعدتا بانجراف القارّات"},{"id":"b","text":"أنّ الكائن كان يطير ويعبر المحيط الأطلسي"},{"id":"c","text":"أنّها صدفة لا دلالة لها"},{"id":"d","text":"أنّ القارّتين ثابتتان تمامًا منذ نشأة الأرض"}]'::jsonb, 'a', 'وجود متحجّرات الكائن نفسه على ضفّتي المحيط دليل قدّمه فاجنر على أنّ القارّتين كانتا متّصلتين ثمّ تباعدتا بانجراف القارّات (حركة الصفائح). تفسير الطيران أو الصدفة لا يصمد، والقارّات ليست ثابتة بل تتحرّك مع صفائحها.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b0398a51-656f-5a9a-963b-f07a8c0c947d', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ما العلاقة بين حركة الصفائح والزلازل والبراكين؟', '[{"id":"a","text":"تتركّز الزلازل والبراكين غالبًا عند حدود الصفائح حيث يكثر النشاط الباطني"},{"id":"b","text":"لا علاقة بين حركة الصفائح والزلازل والبراكين"},{"id":"c","text":"تتركّز الزلازل والبراكين في مراكز الصفائح بعيدًا عن حدودها"},{"id":"d","text":"تحدث الزلازل فقط حيث لا توجد براكين أبدًا"}]'::jsonb, 'a', 'تتركّز الزلازل والبراكين عند حدود الصفائح (تباعد أو تقارب أو انزلاق) لأنّ حركتها هناك تحرّر طاقةً وتتيح صعود الصهارة، ولذلك يتراصفان في الأحزمة نفسها مثل حزام النار. فالعلاقة وثيقة، والنشاط يكثر عند الحدود لا في مراكز الصفائح، والزلازل والبراكين كثيرًا ما يجتمعان في المنطقة نفسها.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

