  ('c6607336-8d4d-57d2-8d92-761f3e3d1476', '19515433-2bba-541b-9762-67c03842195a', 'sciences-vie-terre', '👑 تحدّي المناظرة ⭐⭐⭐⭐: تكتونية الصفائح — حدود وسرعات وأدلّة', 4, 300, 60, 'challenge', 'admin', 6)
