INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('73660d84-547a-5438-81c6-b6c1b277da01', 'c6607336-8d4d-57d2-8d92-761f3e3d1476', 'عند الظهرة المحيطية تتباعد صفيحتان وتتكوّن قشرة محيطية جديدة من الصهارة الصاعدة. ما نوع هذه الحدود؟', '[{"id":"a","text":"حدود متباعدة (بنّاءة)"},{"id":"b","text":"حدود متقاربة (طمر)"},{"id":"c","text":"حدود محوّلة (انزلاقية)"},{"id":"d","text":"حدود ثابتة لا حركة فيها"}]'::jsonb, 'a', 'تباعد الصفيحتين وتكوّن قشرة جديدة عند الظهرة يُعرّف الحدود المتباعدة (البنّاءة)، حيث تُضاف مادّة جديدة إلى القشرة المحيطية. ✓ الخطأ الشائع: الخلط بين الحدود المتباعدة (تكوين قشرة) والمتقاربة (استهلاك قشرة بالطمر).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('98ea26a4-29d4-5043-a6c8-259be37e833b', 'c6607336-8d4d-57d2-8d92-761f3e3d1476', 'قال تلميذ: «انجراف القارّات وتكتونية الصفائح شيءٌ واحد اكتشفه فاجنر (Wegener) كاملًا». ما التصحيح؟', '[{"id":"a","text":"فاجنر اقترح انجراف القارّات دون تفسير آليّته؛ وتكتونية الصفائح (لاحقًا) قدّمت الآلية (تيّارات الحمل واتّساع القاع)"},{"id":"b","text":"لا خطأ، فاجنر وضع النظرية كاملةً بآليّتها"},{"id":"c","text":"تكتونية الصفائح سبقت فاجنر زمنيًّا"},{"id":"d","text":"الانجراف والتكتونية لا علاقة بينهما إطلاقًا"}]'::jsonb, 'a', 'اقترح فاجنر انجراف القارّات بناءً على أدلّة (تطابق السواحل، الأحافير، الطبقات) لكنّه لم يفسّر آليّة الحركة، فرُفضت نظريته حينها. وجاءت تكتونية الصفائح لاحقًا فقدّمت الآلية (تيّارات الحمل في الرداء واتّساع قاع المحيطات). (تمرين «صيد الخطأ».) الخطأ الشائع: اعتبار النظريتَين شيئًا واحدًا مكتملًا عند فاجنر.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bd1f22bf-f714-5858-bcfc-911262fee6bb', 'c6607336-8d4d-57d2-8d92-761f3e3d1476', 'قِيس عمر القشرة المحيطية على بُعد 100 km من محور الظهرة فوُجد 5 ملايين سنة. ما سرعة اتّساع القاع (التوسّع) على هذا الجانب تقريبًا؟', '[{"id":"a","text":"2 cm في السنة"},{"id":"b","text":"20 cm في السنة"},{"id":"c","text":"0,5 cm في السنة"},{"id":"d","text":"5 cm في السنة"}]'::jsonb, 'a', 'السرعة = المسافة / الزمن. 100 km تكوّنت في 5 ملايين سنة، أي 100/5 = 20 km لكلّ مليون سنة. والتحويل: 20 km لكلّ مليون سنة يعادل 2 cm في السنة الواحدة (يقابل كلّ مليون سنة زحفًا قدره 20 km). ✓ الخطأ الشائع: التوقّف عند 20 km لكلّ مليون سنة دون التحويل إلى cm في السنة؛ أو قلب القسمة.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('57427238-430f-531e-9a8a-cc34cfc2f0f1', 'c6607336-8d4d-57d2-8d92-761f3e3d1476', 'منطقة تتميّز بالمؤشّرات التالية معًا: خندق محيطيّ عميق، وزلازل تزداد عمقًا نحو القارّة، وسلسلة براكين انفجارية على الحافّة القارّية. ما نوع الحدود؟', '[{"id":"a","text":"حدود متقاربة (منطقة طمر)"},{"id":"b","text":"حدود متباعدة (ظهرة محيطية)"},{"id":"c","text":"حدود محوّلة (انزلاقية)"},{"id":"d","text":"منطقة خاملة وسط صفيحة"}]'::jsonb, 'a', 'الخندق العميق + الزلازل المتدرّجة في العمق (تتبع الصفيحة الغائصة) + البراكين الانفجارية على الحافّة القارّية كلّها بصمات منطقة الطمر عند حدود متقاربة. (تمرين تحليل مؤشّرات.) ✓ الخطأ الشائع: نسب الزلازل العميقة والبراكين الانفجارية إلى ظهرة متباعدة بدل منطقة طمر.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b5ed99ba-e46c-5b78-a85e-d1ef9f3fb80a', 'c6607336-8d4d-57d2-8d92-761f3e3d1476', 'تتقارب صفيحة محيطية (كثيفة) مع صفيحة قارّية (أقلّ كثافة). أيّهما تنغرز (تغوص) تحت الأخرى، ولماذا؟', '[{"id":"a","text":"الصفيحة المحيطية، لأنّها أكثف فتغوص تحت القارّية"},{"id":"b","text":"الصفيحة القارّية، لأنّها أكثف"},{"id":"c","text":"لا انغراز، ترتدّان معًا للخلف"},{"id":"d","text":"الأخفّ دائمًا هي التي تغوص"}]'::jsonb, 'a', 'الصفيحة المحيطية أكثف من القارّية، فعند التقاربهما تغوص المحيطية تحت القارّية مكوّنةً منطقة طمر (خندق + براكين على القارّة). ✓ الخطأ الشائع: ظنّ أنّ الأخفّ يغوص؛ الأكثف (المحيطية) هي التي تنغرز.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2d9f6ef7-7aa6-51fa-8288-6a97d8169698', 'c6607336-8d4d-57d2-8d92-761f3e3d1476', 'تُظهر القشرة المحيطية على جانبَي الظهرة تناظرًا في أعمار الصخور وفي تسجيلها المغناطيسيّ (تناوب متماثل على الجانبَين). علامَ يدلّ هذا التناظر؟', '[{"id":"a","text":"على توسّع القاع المحيطيّ بالتساوي على جانبَي الظهرة (دليل على اتّساع القاع)"},{"id":"b","text":"على أنّ القشرة ثابتة لا تتحرّك"},{"id":"c","text":"على أنّ الظهرة تستهلك القشرة بالطمر"},{"id":"d","text":"على أنّ القارّات لا تتحرّك مطلقًا"}]'::jsonb, 'a', 'التماثل في الأعمار والتسجيل المغناطيسيّ على جانبَي الظهرة يعني أنّ قشرةً جديدة تتكوّن عند المحور وتنزاح إلى الجانبَين بالتساوي، وهو دليلٌ مباشر على اتّساع قاع المحيط. ✓ الخطأ الشائع: تفسير التناظر بثبات القشرة بدل توسّعها المتناظر.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

