  ('108a767e-ef6d-5ed7-ab54-f21275007d6b', 'e544d74c-e24f-5d7d-83af-3c29e0d74bc1', 'sciences-vie-terre', 'مراجعة شاملة: أحياء وجيولوجيا', 1, 20, 5, 'quiz', 'admin', 0)
