INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b17fa6aa-1461-5c2b-8a15-a5c8c98685f9', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'عند تحليل أيّ وثيقة في السبر، ما الخطوة الصحيحة قبل صياغة الاستنتاج؟', '[{"id":"a","text":"قراءة معطيات الوثيقة وملاحظتها بدقّة"},{"id":"b","text":"كتابة رأي شخصي دون النظر إلى الوثيقة"},{"id":"c","text":"حفظ الجواب النموذجي من درس آخر"},{"id":"d","text":"تجاهل المحاور والأرقام والاكتفاء بالعنوان"}]'::jsonb, 'a', 'الاستنتاج العلمي يُبنى على **قراءة معطيات الوثيقة** أوّلًا (المحاور، الأرقام، المقارنات). الرأي الشخصي أو الجواب المحفوظ من درس آخر لا يصلح، وتجاهل المحاور والأرقام يُفقد التحليل أساسه.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
