INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('835e6294-5255-5418-a045-122a6e29cc12', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'في وثيقة تجربة، يوجد دائمًا «شاهد» (témoin). ما فائدته؟', '[{"id":"a","text":"زيادة عدد الحيوانات في التجربة فقط"},{"id":"b","text":"المقارنة معه لكشف دور العامل المدروس"},{"id":"c","text":"تعويض الحالة المختبَرة إذا فشلت"},{"id":"d","text":"لا فائدة منه علميًّا"}]'::jsonb, 'b', 'الشاهد لم يخضع للعامل المدروس، فبـ **مقارنته بالحالة المختبَرة** نكشف أثر هذا العامل. لو غاب الشاهد لما أمكن نسبة النتيجة إلى العامل، فهو ركن أساسي في كلّ تجربة لا حشو.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a7cca3a3-2469-5852-939d-d3c4ead4274c', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'نمط نووي لخليّة جسمية يُظهر 46 صبغيًّا منها زوج جنسي XX. ماذا نستنتج؟', '[{"id":"a","text":"ذكر سليم"},{"id":"b","text":"أنثى سليمة عدد صبغيّاتها طبيعي"},{"id":"c","text":"مصاب بالتثلّث الصبغي 21"},{"id":"d","text":"مشيج (خليّة تناسلية)"}]'::jsonb, 'b', 'العدد 46 صبغيًّا هو العدد **الطبيعي** لخلايا الجسم، والزوج **XX** يدلّ على **أنثى**. الذكر يكون XY، والتثلّث 21 يُظهر 47 صبغيًّا، والمشيج يحمل 23 صبغيًّا فقط لا 46.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('82d684ab-4f7e-5520-b7a0-07f77e425c40', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'بعد دخول جرثومة، يرتفع في الدم عدد جزيئات نوعية تلتصق بالجرثومة وتعدِمها. ما هذه الجزيئات؟', '[{"id":"a","text":"الأجسام المضادّة"},{"id":"b","text":"الكريّات الحمراء"},{"id":"c","text":"الصفيحات الدموية"},{"id":"d","text":"الهرمونات الجنسية"}]'::jsonb, 'a', 'الجزيئات النوعية التي تلتصق بالمستضدّ (الجرثومة) وتُبطل مفعوله هي **الأجسام المضادّة** التي تنتجها اللمفاويات. الكريّات الحمراء تنقل الأكسجين، والصفيحات تتدخّل في تخثّر الدم، والهرمونات الجنسية تنظّم التكاثر لا الدفاع.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('164792c0-f812-51c6-9e58-e21fc6524be9', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'تُظهر خريطة عالمية أنّ معظم البراكين والزلازل تتركّز في أشرطة ضيّقة لا عشوائيًّا. ماذا نستنتج؟', '[{"id":"a","text":"أنّها تقع صدفةً دون سبب"},{"id":"b","text":"أنّها تتمركز على حدود الصفائح التكتونية"},{"id":"c","text":"أنّها مرتبطة بكثافة السكّان"},{"id":"d","text":"أنّها مرتبطة بدرجة حرارة الجوّ"}]'::jsonb, 'b', 'تمركز البراكين والزلازل في أشرطة ضيّقة يطابق **حدود الصفائح التكتونية**، حيث تتحرّك الصفائح وتتفاعل. فهي ليست صدفة، ولا علاقة لها بعدد السكّان ولا بحرارة الجوّ بل بحركة الصفائح في باطن الأرض.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ef8522fd-435d-56ab-b4dc-ede68b2083bc', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'أبوان سليمان ظاهريًّا أنجبا طفلًا مصابًا بمرض وراثي متنحٍّ. ما الاستنتاج الصحيح؟', '[{"id":"a","text":"أحد الأبوين فقط يحمل الحليل المعطوب"},{"id":"b","text":"كلا الأبوين مهجّن حامل للحليل المتنحّي دون أن يمرض"},{"id":"c","text":"المرض اكتُسب من المحيط"},{"id":"d","text":"كلا الأبوين مصاب بالمرض"}]'::jsonb, 'b', 'لظهور مرض **متنحٍّ** عند الطفل لا بدّ أن يرث الحليل المعطوب من **كلا الأبوين**. ولأنّهما سليمان ظاهريًّا فكلّ منهما **مهجّن حامل** (a//a لم يجتمع عندهما). لو حمله أحدهما فقط لما اجتمع الحليلان عند الطفل، والمرض وراثي لا مكتسب.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f7c8264a-7ae5-51bd-bddb-800033867d8b', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'سُجّل زلزال مقداره 5.5 على سلّم ريشتر، لكنّ شدّته اختلفت بين مدينتين. ما التفسير الصحيح؟', '[{"id":"a","text":"خطأ في القياس لأنّ القيم يجب أن تتطابق"},{"id":"b","text":"المقدار قيمة واحدة (طاقة البؤرة)، والشدّة تختلف حسب الآثار على السطح"},{"id":"c","text":"المقدار أيضًا يختلف من مدينة لأخرى"},{"id":"d","text":"الشدّة والمقدار يقيسان الشيء نفسه"}]'::jsonb, 'b', '**المقدار** يقيس الطاقة المحرَّرة عند البؤرة وله **قيمة واحدة** لكلّ الزلزال، أمّا **الشدّة** فتقيس آثاره على السطح فتختلف من مدينة لأخرى حسب القرب من المركز ونوع التربة وجودة البناء. فلا خطأ ولا تطابق مطلوب، وهما مقياسان مختلفان.', 7, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0c998b5b-0732-52b2-b5b8-50464d718eb2', '108a767e-ef6d-5ed7-ab54-f21275007d6b', 'بركان يقذف صهارة لزجة جدًّا فتنفجر بعنف؛ وآخر تنساب حممه بسهولة في شكل أنهار. ما الفرق الأساسي؟', '[{"id":"a","text":"لزوجة الصهارة: لزجة تعطي انفجاريًّا، وسائلة تعطي انسيابيًّا"},{"id":"b","text":"لون الصخور حول البركان فقط"},{"id":"c","text":"ارتفاع البركان فوق سطح البحر فقط"},{"id":"d","text":"عمر البركان بالسنوات"}]'::jsonb, 'a', 'تحدّد **لزوجة الصهارة** نوع البركان: الصهارة **اللزجة** تحبس الغازات فتنفجر (بركان انفجاري)، والصهارة **السائلة** تطلق غازاتها بسهولة فتنساب الحمم (بركان انسيابي). أمّا اللون والارتفاع والعمر فليست هي السبب في نمط الثوران.', 8, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d0a4b9c1-9dc9-5933-90b6-0440e41cf134', 'e544d74c-e24f-5d7d-83af-3c29e0d74bc1', 'sciences-vie-terre', '📝 سبر تطبيقي: تحليل وثائق (أحياء وجيولوجيا)', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
