INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b026f476-b7d0-53d6-a42c-d33dc9346f14', 'd0a4b9c1-9dc9-5933-90b6-0440e41cf134', 'وثيقة 1 (منحنى موصوف): في الدورة الجنسية عند المرأة، يُظهر منحنى تركيز الأستروجين في الدم ارتفاعًا تدريجيًّا في النصف الأوّل من الدورة. ماذا يحدث في بطانة الرحم خلال هذه المرحلة بحسب هذا المعطى؟', '[{"id":"a","text":"تتثخّن بطانة الرحم استعدادًا لاستقبال بيضة مخصّبة"},{"id":"b","text":"تتمزّق بطانة الرحم وينزل الطمث"},{"id":"c","text":"تختفي المبايض نهائيًّا"},{"id":"d","text":"يتوقّف نموّ بطانة الرحم تمامًا"}]'::jsonb, 'a', 'ارتفاع الأستروجين في النصف الأوّل من الدورة يرافقه **تثخّن بطانة الرحم** تهيّؤًا لاستقبال بيضة مخصّبة. أمّا تمزّق البطانة ونزول الطمث فيحدث حين **ينخفض** الهرمون في نهاية الدورة، والمبايض لا تختفي بل تفرز الهرمون، والبطانة تنمو لا تتوقّف.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e5a5c9eb-a834-5d75-bcad-77381e272fbe', 'd0a4b9c1-9dc9-5933-90b6-0440e41cf134', 'وثيقة 2 (نمط نووي): صورة نمط نووي لخليّة جسمية تُظهر 44 صبغيًّا جسميًّا + زوجًا جنسيًّا XY. ما الاستنتاج؟', '[{"id":"a","text":"أنثى عدد صبغيّاتها 46"},{"id":"b","text":"ذكر عدد صبغيّاته 46"},{"id":"c","text":"خليّة مشيج عدد صبغيّاتها 23"},{"id":"d","text":"مصاب بالتثلّث الصبغي 21"}]'::jsonb, 'b', '44 صبغيًّا جسميًّا (22 زوجًا) + الزوج الجنسي = **46 صبغيًّا**، والزوج **XY** يدلّ على **ذكر**. الأنثى تكون XX، والمشيج يحمل 23 صبغيًّا فقط، والتثلّث 21 يُظهر 47 صبغيًّا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('119384f8-775b-5877-bb51-d79a249c6092', 'd0a4b9c1-9dc9-5933-90b6-0440e41cf134', 'وثيقة 3 (تجربة): حُقن فأر سليم بمصل يحتوي أجسامًا مضادّة ضدّ جرثومة معيّنة، ثمّ عُرّض للجرثومة فلم يمرض، بينما مرض الفأر الشاهد الذي لم يُحقَن. ماذا نستنتج عن دور الأجسام المضادّة؟', '[{"id":"a","text":"لا دور للأجسام المضادّة في الحماية"},{"id":"b","text":"الأجسام المضادّة الجاهزة وفّرت حماية فورية ضدّ الجرثومة"},{"id":"c","text":"الفأر الشاهد هو الذي تلقّى الحماية"},{"id":"d","text":"الجرثومة فقدت خطورتها تلقائيًّا"}]'::jsonb, 'b', 'الفأر الذي تلقّى **الأجسام المضادّة الجاهزة** نجا، بينما مرض الشاهد غير المحقون؛ فالمقارنة تكشف أنّ الأجسام المضادّة وفّرت **حماية فورية**. الشاهد هو الذي لم يُحقَن فمرض، والجرثومة لم تتغيّر، فالفرق سببه الأجسام المضادّة وحدها.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('caa4f222-487d-582c-8d2b-a38340ad43e7', 'd0a4b9c1-9dc9-5933-90b6-0440e41cf134', 'وثيقة 4 (سجلّ زلزالي): على مخطّط مرصاد زلزالي، تُسجَّل أوّلًا موجات سريعة ثمّ موجات أبطأ بعدها بثوانٍ. ما الموجات التي تصل أوّلًا؟', '[{"id":"a","text":"الموجات الأوّلية (P) لأنّها الأسرع"},{"id":"b","text":"الموجات الثانوية (S) لأنّها الأسرع"},{"id":"c","text":"الموجات السطحية لأنّها الأسرع"},{"id":"d","text":"كلّ الموجات تصل في اللحظة نفسها"}]'::jsonb, 'a', 'الموجات **الأوّلية P** هي الأسرع فتصل أوّلًا إلى المرصاد، ثمّ تتبعها الموجات **S** الأبطأ. الموجات السطحية تصل لاحقًا، والموجات لا تصل دفعة واحدة بل تتدرّج حسب سرعتها، وهذا الفارق يُستعمل لتحديد بُعد المركز.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('414e0c31-aab0-5146-bb58-141c67ae8324', 'd0a4b9c1-9dc9-5933-90b6-0440e41cf134', 'وثيقة 5 (خريطة): تُظهر خريطة أنّ بركانًا انفجاريًّا يقع قرب منطقة تتقارب فيها صفيحتان وتغوص إحداهما تحت الأخرى. ما العلاقة المستنتَجة؟', '[{"id":"a","text":"البركان مرتبط بتقارب الصفائح وغوص إحداها"},{"id":"b","text":"البركان يقع صدفةً دون علاقة بالصفائح"},{"id":"c","text":"البراكين توجد فقط بعيدًا عن حدود الصفائح"},{"id":"d","text":"تقارب الصفائح يمنع تكوّن البراكين"}]'::jsonb, 'a', 'عند **تقارب** صفيحتين وغوص إحداهما تنصهر الصخور في العمق فتتكوّن صهارة تغذّي البراكين الانفجارية؛ فالبركان **مرتبط بحدود الصفائح** لا صدفة. والبراكين تتمركز عند الحدود لا بعيدًا عنها، والتقارب يولّد البراكين لا يمنعها.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e9eab2b3-9b80-5c2e-b4f5-e00a2f95827c', 'd0a4b9c1-9dc9-5933-90b6-0440e41cf134', 'وثيقة 6 (استرجاع وربط): مرحلتا الإلقاح وتعشيش البيضة المخصّبة. ما الترتيب الصحيح للأحداث بعد التقاء المشيجين؟', '[{"id":"a","text":"تعشيش في الرحم ← ثمّ إلقاح في المبيض"},{"id":"b","text":"إلقاح (اتّحاد المشيجين) ← تكوّن بيضة مخصّبة ← تعشيش في بطانة الرحم"},{"id":"c","text":"نزول الطمث ← ثمّ إلقاح ← ثمّ تعشيش"},{"id":"d","text":"تعشيش ثمّ تكوّن المشيجين بعده"}]'::jsonb, 'b', 'الترتيب الصحيح: **إلقاح** (اتّحاد النطفة بالبويضة) في البوق ← تكوّن **بيضة مخصّبة** ← انتقالها و**تعشيشها** في بطانة الرحم المتثخّنة. الإلقاح يسبق التعشيش لا العكس، ونزول الطمث يحدث عند غياب الحمل، والمشيجان يتكوّنان قبل الإلقاح لا بعد التعشيش.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f75aa5c8-b6f1-5b2a-a974-53c289576c9e', 'e544d74c-e24f-5d7d-83af-3c29e0d74bc1', 'sciences-vie-terre', '👹 سبر زعيم: تحليل معمّق واستنتاج', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
