INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('046c93e4-77f9-5230-b29d-ddfe9ce03aca', 'f75aa5c8-b6f1-5b2a-a974-53c289576c9e', 'وثيقة 1 (تجربة تلقيح): لُقّح فأر بجرثومة مُضعَفة فلم يمرض، ثمّ بعد أسابيع عُرّض للجرثومة نفسها قويّة فبقي سليمًا، بينما مرض الشاهد غير الملقَّح. ما المفهوم الذي تثبته هذه التجربة؟', '[{"id":"a","text":"أنّ التلقيح يمنح ذاكرة مناعية تحمي عند اللقاء اللاحق"},{"id":"b","text":"أنّ التلقيح يجعل الفأر مصدرًا لعدوى الآخرين"},{"id":"c","text":"أنّ الجرثومة المُضعَفة أخطر من القويّة"},{"id":"d","text":"أنّ المناعة صفة مكتسبة من المحيط دون تلقيح"}]'::jsonb, 'a', 'التلقيح بجرثومة مُضعَفة يحرّض الجسم على إنتاج خلايا **ذاكرة مناعية**، فعند اللقاء اللاحق بالجرثومة القويّة يستجيب بسرعة ويحمي الفرد؛ وهذا ما يفسّر نجاة الملقَّح ومرض الشاهد. التلقيح لا ينشر العدوى، والجرثومة المُضعَفة أقلّ خطرًا، والمناعة هنا نتجت عن التلقيح لا تلقائيًّا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ee636527-0f79-597b-a7bb-54627ae2c68c', 'f75aa5c8-b6f1-5b2a-a974-53c289576c9e', 'وثيقة 5 (مقارنة براكين): بركان (1) يقذف رمادًا وقنابل بانفجارات عنيفة، وبركان (2) تنساب منه حمم سائلة هادئة. ما الذي يفسّر هذا الاختلاف؟', '[{"id":"a","text":"لزوجة الصهارة وكمّية الغازات المحبوسة فيها"},{"id":"b","text":"لون الجبل المحيط بالبركان"},{"id":"c","text":"وقت الثوران من النهار"},{"id":"d","text":"ارتفاع البركان فقط دون أيّ عامل آخر"}]'::jsonb, 'a', 'الصهارة **اللزجة** تحبس الغازات فتتراكم حتّى تنفجر بعنف (بركان انفجاري كالبركان 1)، بينما الصهارة **السائلة** تطلق غازاتها بسهولة فتنساب حممها هادئة (بركان انسيابي كالبركان 2). أمّا اللون ووقت النهار والارتفاع وحده فلا تحدّد نمط الثوران.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('054b72f1-0cf5-5208-9abc-db23b8a7f5c6', 'f75aa5c8-b6f1-5b2a-a974-53c289576c9e', 'وثيقة 2 (منحنى مناعي): بعد أوّل تماس بمستضدّ يرتفع إنتاج الأجسام المضادّة ببطء وبكمّية قليلة؛ وبعد تماس ثانٍ بالمستضدّ نفسه يرتفع الإنتاج بسرعة وبكمّية أكبر بكثير. ما تفسير الفرق بين الاستجابتين؟', '[{"id":"a","text":"خطأ في القياس لأنّ الاستجابتين يجب أن تتطابقا"},{"id":"b","text":"وجود ذاكرة مناعية جعلت الاستجابة الثانية أسرع وأقوى"},{"id":"c","text":"أنّ المستضدّ صار غير ضارّ في المرّة الثانية"},{"id":"d","text":"أنّ الجسم نسي المستضدّ تمامًا"}]'::jsonb, 'b', 'الاستجابة الثانية أسرع وأقوى بسبب **خلايا الذاكرة** المتكوّنة بعد التماس الأوّل، وهذا أساس فعالية التلقيح. التطابق غير مطلوب، والمستضدّ لم يتغيّر، ولو نسيه الجسم لكانت الاستجابة الثانية مثل الأولى أو أضعف لا أقوى.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9960b7cb-67d9-5091-804c-264916e830e4', 'f75aa5c8-b6f1-5b2a-a974-53c289576c9e', 'وثيقة 3 (شجرة نسب): مرض وراثي متنحٍّ؛ أبوان سليمان أنجبا بنتًا مصابة. ما تركيب الأبوين الوراثي؟ (A سليم سائد، a معطوب متنحٍّ)', '[{"id":"a","text":"كلاهما A//A نقيّ سليم"},{"id":"b","text":"كلاهما A//a مهجّن حامل"},{"id":"c","text":"كلاهما a//a مصاب"},{"id":"d","text":"أحدهما A//A والآخر a//a"}]'::jsonb, 'b', 'البنت المصابة تركيبها **a//a**، فأخذت a من كلّ والد. وبما أنّ الأبوين سليمان ظاهريًّا فكلّ منهما **A//a مهجّن حامل**. لو كانا A//A لما وجد a يُورَّث، ولو كانا a//a لكانا مصابين، ولو كان أحدهما a//a لظهر عليه المرض.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c9130b00-19a9-5291-af93-4ac21f95250d', 'f75aa5c8-b6f1-5b2a-a974-53c289576c9e', 'وثيقة 4 (سجلّ زلزالي وحساب): سُجّل أنّ فرق وصول الموجات P و S في مرصاد A أكبر منه في مرصاد B. أيّ المرصدين أقرب إلى المركز السطحي؟', '[{"id":"a","text":"المرصد A لأنّ فرق الوصول أكبر"},{"id":"b","text":"المرصد B لأنّ فرق الوصول أصغر"},{"id":"c","text":"كلاهما على المسافة نفسها"},{"id":"d","text":"لا علاقة بين فرق الوصول والمسافة"}]'::jsonb, 'b', 'كلّما **قرب** المرصد من المركز السطحي **قلّ** فرق الوصول بين P و S، لأنّ الموجتين لم يتباعدا كثيرًا بعد. ففرق B الأصغر يدلّ على أنّه **الأقرب**، وفرق A الأكبر يدلّ على بُعده. فالعلاقة موجودة وليست منعدمة، والمسافتان مختلفتان.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4cdbe792-5aa5-5b1e-8917-4e38aafe8a9d', 'f75aa5c8-b6f1-5b2a-a974-53c289576c9e', 'وثيقة 6 (تركيب جيولوجي): عند حدود متباعدة في وسط المحيط، تبتعد صفيحتان فتصعد صهارة وتتكوّن قشرة جديدة. ماذا يؤكّد هذا عن الصفائح؟', '[{"id":"a","text":"أنّ الصفائح ثابتة لا تتحرّك"},{"id":"b","text":"أنّ الصفائح متحرّكة وأنّ قشرة محيطية جديدة تتكوّن عند الحدود المتباعدة"},{"id":"c","text":"أنّ القشرة المحيطية لا تتجدّد أبدًا"},{"id":"d","text":"أنّ الصهارة تأتي من خارج الأرض"}]'::jsonb, 'b', 'تباعد الصفيحتين وصعود الصهارة لتكوين قشرة جديدة يؤكّدان أنّ **الصفائح متحرّكة** وأنّ القشرة المحيطية **تتجدّد** عند الحدود المتباعدة (ظهرات وسط المحيط). فالصفائح ليست ثابتة، والقشرة تتجدّد، والصهارة تأتي من **باطن الأرض** لا من خارجها.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

