  ('0487af90-2509-5724-a5e0-eb0262698181', 'e544d74c-e24f-5d7d-83af-3c29e0d74bc1', 'sciences-vie-terre', '🏆 تحدّي النخبة: سبر شامل وتركيب المفاهيم', 4, 300, 60, 'challenge', 'admin', 3)
