INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9f525f37-233a-5f0d-ac8a-101e8c60695a', '0487af90-2509-5724-a5e0-eb0262698181', 'وثيقة 2 (تجربة بلعمة): وُضعت كريّات بيضاء (بالعات) مع جراثيم تحت المجهر؛ لوحظ أنّها تحيط بالجرثومة ثمّ تُدخلها وتهضمها. ما الخطّ الدفاعي الذي تمثّله هذه الظاهرة؟', '[{"id":"a","text":"البلعمة، استجابة مناعية غير نوعية تبتلع الأجسام الغريبة"},{"id":"b","text":"إنتاج أجسام مضادّة نوعية فقط"},{"id":"c","text":"تخثّر الدم بالصفيحات"},{"id":"d","text":"نقل الأكسجين بالكريّات الحمراء"}]'::jsonb, 'a', 'إحاطة الخليّة بالجرثومة وابتلاعها وهضمها هي **البلعمة**، وهي استجابة مناعية **غير نوعية** تتصدّى لمختلف الأجسام الغريبة. إنتاج الأجسام المضادّة استجابة **نوعية** مختلفة، والتخثّر دور الصفيحات، ونقل الأكسجين دور الكريّات الحمراء لا البالعات.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3980c44c-fcb3-56fb-ac2f-cc680e3bc354', '0487af90-2509-5724-a5e0-eb0262698181', 'وثيقة 1 (منحنيان هرمونيّان): في الدورة الجنسية، يبلغ منحنى هرمون LH قمّة حادّة في منتصف الدورة تقريبًا. أيّ حدث تكاثري يرتبط مباشرةً بهذه القمّة؟', '[{"id":"a","text":"الإباضة (انطلاق البويضة من المبيض)"},{"id":"b","text":"نزول الطمث"},{"id":"c","text":"تعشيش البيضة في الرحم"},{"id":"d","text":"تكوّن النطف عند الذكر"}]'::jsonb, 'a', 'القمّة الحادّة لهرمون **LH** في منتصف الدورة تحرّض **الإباضة** أي انطلاق البويضة من المبيض. نزول الطمث يحدث في نهاية الدورة عند انخفاض الهرمونات، والتعشيش يأتي لاحقًا بعد الإلقاح، وتكوّن النطف ظاهرة عند الذكر لا علاقة لها بدورة المرأة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f8892c5e-1330-504f-a41a-bb675f5c1df4', '0487af90-2509-5724-a5e0-eb0262698181', 'وثيقة 3 (تحديد الجنس واحتمال): زوجان لهما ثلاث بنات ويرغبان في معرفة احتمال أن يكون مولودهما القادم ذكرًا. ما الجواب الصحيح علميًّا؟', '[{"id":"a","text":"الاحتمال أعلى لأنّهم أنجبوا بنات سابقًا"},{"id":"b","text":"الاحتمال 50 ٪ لأنّ النطفة تحمل X أو Y مناصفةً في كلّ حمل"},{"id":"c","text":"الاحتمال 0 ٪ لأنّ الأمّ تحمل XX"},{"id":"d","text":"الأمّ هي من تحدّد الجنس فالاحتمال يعتمد عليها"}]'::jsonb, 'b', 'البويضة تحمل **X دائمًا**، والنطفة تحمل **X أو Y مناصفةً**، فاحتمال الذكر **50 ٪** في **كلّ** حمل بصرف النظر عن المواليد السابقين (لا ذاكرة للأحداث المستقلّة). الأب هو من يحدّد الجنس لا الأمّ، والاحتمال ليس صفرًا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('54f8ca79-ef53-5d24-886e-63fe510c18ce', '0487af90-2509-5724-a5e0-eb0262698181', 'وثيقة 4 (ربط جيولوجي شامل): سجّلت منطقة زلازل متكرّرة وبراكين نشطة معًا، وهي تقع على حدّ بين صفيحتين متقاربتين. ما التفسير الموحِّد لاجتماع الظاهرتين؟', '[{"id":"a","text":"صدفة جغرافية لا تفسير لها"},{"id":"b","text":"حركة الصفائح عند الحدّ المتقارب تولّد الزلازل وتُنتج صهارة تغذّي البراكين"},{"id":"c","text":"الزلازل تمنع البراكين فلا يجتمعان عادةً"},{"id":"d","text":"مناخ المنطقة هو سبب الظاهرتين"}]'::jsonb, 'b', 'عند الحدّ **المتقارب** تحتكّ الصفيحتان وتغوص إحداهما؛ فالاحتكاك والتكسّر يولّدان **الزلازل**، والانصهار في العمق يُنتج **صهارة** تغذّي **البراكين**. فالظاهرتان نتاج العامل نفسه (حركة الصفائح) لا صدفة ولا مناخ، وهما تجتمعان عند هذه الحدود لا تتنافيان.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('206bcfff-bd62-505d-8053-b84a7be77070', '0487af90-2509-5724-a5e0-eb0262698181', 'وثيقة 5 (شدّة ومقدار وخريطة): زلزال واحد مقداره 7؛ سُجّلت أعلى شدّة قرب المركز السطحي وأقلّ شدّة في مدينة بعيدة ذات تربة صخرية صلبة. ما الاستنتاج المركّب الصحيح؟', '[{"id":"a","text":"المقدار يتغيّر بين المدينتين تبعًا للشدّة"},{"id":"b","text":"المقدار واحد للزلزال، والشدّة تقلّ بالابتعاد وتتأثّر بنوع التربة"},{"id":"c","text":"الشدّة ثابتة في كلّ مكان والمقدار هو المتغيّر"},{"id":"d","text":"التربة الصلبة ترفع الشدّة دائمًا"}]'::jsonb, 'b', '**المقدار** قيمة واحدة للزلزال (7) تقيس طاقة البؤرة، بينما **الشدّة** تقيس الآثار فتقلّ بالابتعاد عن المركز وتتأثّر بنوع التربة؛ والتربة الصخرية الصلبة تقلّل الاهتزاز فتخفّض الشدّة. فالمقدار لا يتغيّر، والشدّة هي المتغيّرة، والتربة الصلبة تخفّض الشدّة لا ترفعها.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8acacd40-bb84-5042-9994-b598af9f5a55', '0487af90-2509-5724-a5e0-eb0262698181', 'وثيقة 6 (تركيب الوراثة والصبغيّات): نمط نووي يُظهر 47 صبغيًّا، مع ثلاث نسخ من الصبغيّ رقم 21 وزوج جنسي XX. ما التشخيص والاستنتاج عن أصل الخلل؟', '[{"id":"a","text":"ذكر مصاب بمرض متنحٍّ في حليل واحد"},{"id":"b","text":"أنثى مصابة بمتلازمة داون بسبب خلل في عدد الصبغيّات (تثلّث 21)"},{"id":"c","text":"أنثى سليمة عدد صبغيّاتها طبيعي"},{"id":"d","text":"مشيج به طفرة في حليل"}]'::jsonb, 'b', 'العدد **47** مع **ثلاث نسخ من الصبغيّ 21** = **متلازمة داون (التثلّث 21)**، والزوج **XX** يدلّ على **أنثى**؛ والخلل في **عدد الصبغيّات** لا في حليل مفرد. فالزوج XX لا يدلّ على ذكر، والعدد 47 ليس طبيعيًّا، والمشيج يحمل 23 لا 47، والسبب اختلال عددي لا طفرة حليل.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

-- Converge question → competency mappings for this subject (étude 07 D-2).
DO $$
BEGIN
  IF to_regclass('public.question_competencies') IS NOT NULL THEN
    DELETE FROM public.question_competencies qc
    USING public.questions q, public.exercises e
    WHERE qc.question_id = q.id
      AND q.exercise_id = e.id
      AND e.subject_id = 'sciences-vie-terre'
      AND e.source = 'admin';
  END IF;
END $$;

